def _get_preschool_vocab_data():
    """Okul öncesi 10 ünite kelime verisi — curriculum + günlük plan birleştirmesi."""
    import json, os

    _unit_map = {1: (1, 4), 2: (5, 8), 3: (9, 12), 4: (13, 16), 5: (17, 20),
                 6: (21, 24), 7: (25, 27), 8: (28, 30), 9: (31, 33), 10: (34, 36)}
    _unit_names = {
        1: ("Greetings", "Selamlasma"),
        2: ("Colours", "Renkler"),
        3: ("Numbers", "Sayilar"),
        4: ("Weather", "Hava Durumu"),
        5: ("Toys & Party", "Oyuncaklar ve Parti"),
        6: ("Farm Animals", "Ciftlik Hayvanlari"),
        7: ("Seasons", "Mevsimler"),
        8: ("Beach & Nature", "Sahil ve Doga"),
        9: ("Community Helpers", "Yardimcilar"),
        10: ("Goodbye & Review", "Hosca Kal ve Tekrar"),
    }

    # Curriculum verisinden kelimeler
    _curriculum = _CURRICULUM.get("preschool", [])

    # Günlük plan verisinden ek kelimeler
    _wp_vocab = {}
    _wp_path = os.path.join("data", "english", "weekly_plans.json")
    if os.path.exists(_wp_path):
        try:
            with open(_wp_path, "r", encoding="utf-8") as f:
                _wp = json.load(f)
            _pk_plans = _wp.get("preschool", [])
            for pw in _pk_plans:
                wn = pw.get("week", 0)
                oc = pw.get("outcomes", {})
                vlist = oc.get("vocabulary", [])
                if vlist:
                    _wp_vocab[wn] = vlist
        except Exception:
            pass

    units = []
    for u in range(1, 11):
        ws, we = _unit_map[u]
        en_name, tr_name = _unit_names[u]

        # Curriculum kelimeler
        all_words = []
        week_details = []
        for wk in _curriculum:
            wn = wk.get("week", 0)
            if ws <= wn <= we:
                theme = wk.get("theme", "")
                theme_tr = wk.get("theme_tr", "")
                cur_vocab = wk.get("vocab", [])
                wp_vocab = _wp_vocab.get(wn, [])
                # Birleştir, tekrarları kaldır
                merged = list(dict.fromkeys(cur_vocab + wp_vocab))
                all_words.extend(merged)
                week_details.append({
                    "week": wn,
                    "theme": theme,
                    "theme_tr": theme_tr,
                    "words": merged,
                })

        # Tüm ünite kelimelerini deduplicate
        all_words = list(dict.fromkeys(all_words))

        units.append({
            "unit": u,
            "name_en": en_name,
            "name_tr": tr_name,
            "weeks": week_details,
            "all_words": all_words,
            "word_count": len(all_words),
        })

    return units


def _get_grade_vocab_data(grade: int):
    """Belirli sınıf için kümülatif kelime verisi döndürür.

    grade=0 → preschool (mevcut fonksiyon)
    grade=1 → preschool kelimeleri + grade1 yeni kelimeleri
    grade=N → grade(N-1) kelimeleri + gradeN yeni kelimeleri
    """
    import json, os

    if grade == 0:
        return _get_preschool_vocab_data()

    _unit_map_standard = {1:(1,4),2:(5,8),3:(9,12),4:(13,16),5:(17,20),
                          6:(21,24),7:(25,27),8:(28,30),9:(31,33),10:(34,36)}
    _unit_map_46 = {u: ((u-1)*4+1, u*4) for u in range(1, 10)}  # 1-9: 4 hafta
    _unit_map_46[10] = (37, 40)  # fallback

    # Önceki sınıfın TÜM kelimelerini topla (kümülatif)
    _prev_words = set()
    for g in range(0, grade):
        _key = "preschool" if g == 0 else f"grade{g}"
        _cur = _CURRICULUM.get(_key, [])
        for w in _cur:
            for v in w.get("vocab", []):
                if v and v not in ("all previous words", "all words",
                                   "term1","term2","term3","term4","term5",
                                   "term6","term7","term8","term9","term10"):
                    _prev_words.add(v.lower())

    # Bu sınıfın kelimelerini topla (ünite bazlı)
    _level_key = f"grade{grade}"
    _curriculum = _CURRICULUM.get(_level_key, [])

    # Günlük plan verisinden ek kelimeler
    _wp_vocab = {}
    _wp_path = os.path.join("data", "english", "weekly_plans.json")
    if os.path.exists(_wp_path):
        try:
            with open(_wp_path, "r", encoding="utf-8") as f:
                _wp = json.load(f)
            _grade_plans = _wp.get(str(grade), [])
            for pw in _grade_plans:
                wn = pw.get("week", 0)
                oc = pw.get("outcomes", {})
                vlist = oc.get("vocabulary", [])
                if vlist:
                    _wp_vocab[wn] = vlist
        except Exception:
            pass

    # Ünite mapping
    if grade >= 9:
        _umap = _unit_map_standard
    else:
        _umap = {u: ((u-1)*4+1, u*4) for u in range(1, 10)}
        _umap[10] = (37, 40)
        # Düzelt: standart 36 hafta mapping
        _umap = _unit_map_standard

    _cefr_map = {0:"Pre-A1",1:"A1",2:"A1",3:"A1",4:"A1",5:"A2",6:"A2",7:"A2",8:"A2",
                 9:"B1",10:"B1+",11:"B2",12:"B2+"}

    units = []
    for u in range(1, 11):
        ws, we = _umap.get(u, (1, 4))
        # Bu üniteye ait haftalar
        _unit_weeks = [wk for wk in _curriculum if ws <= wk.get("week", 0) <= we]
        if not _unit_weeks:
            start = (u - 1) * 4
            _unit_weeks = _curriculum[start:start + 4] if start < len(_curriculum) else []

        theme = _unit_weeks[0].get("theme", f"Unit {u}") if _unit_weeks else f"Unit {u}"
        theme_tr = _unit_weeks[0].get("theme_tr", "") if _unit_weeks else ""

        # Curriculum + daily plan kelimeler
        new_words = []
        week_details = []
        for wk in _unit_weeks:
            wn = wk.get("week", 0)
            cur_vocab = [v for v in wk.get("vocab", [])
                        if v and v not in ("all previous words", "all words",
                                           "term1","term2","term3","term4","term5",
                                           "term6","term7","term8","term9","term10")]
            wp_v = _wp_vocab.get(wn, [])
            merged = list(dict.fromkeys(cur_vocab + wp_v))
            new_words.extend(merged)
            week_details.append({
                "week": wn,
                "theme": wk.get("theme", ""),
                "theme_tr": wk.get("theme_tr", ""),
                "words": merged,
            })

        new_words = list(dict.fromkeys(new_words))

        # Önceki sınıf kelimeleri (sadece bu ünite için değil, genel)
        # Burada "yeni kelimeler" = bu sınıfta eklenen
        # "önceki kelimeler" = alt sınıflardan taşınan
        _truly_new = [w for w in new_words if w.lower() not in _prev_words]
        _from_prev = [w for w in new_words if w.lower() in _prev_words]

        units.append({
            "unit": u,
            "name_en": theme,
            "name_tr": theme_tr,
            "weeks": week_details,
            "all_words": new_words,
            "new_words": _truly_new,
            "prev_words": _from_prev,
            "word_count": len(new_words),
        })

    # Önceki sınıf toplam kelime listesi (tablo referansı için)
    _prev_words_list = sorted(_prev_words)

    return {
        "grade": grade,
        "cefr": _cefr_map.get(grade, "A1"),
        "kademe": "Ilkokul" if grade <= 4 else "Ortaokul" if grade <= 8 else "Lise",
        "units": units,
        "prev_grade_words": _prev_words_list,
        "prev_word_count": len(_prev_words_list),
        "total_new_words": sum(len(u["new_words"]) for u in units),
        "total_all_words": sum(u["word_count"] for u in units),
    }


def _generate_vocab_pdf(units_data, selected_units=None, grade=0, grade_data=None) -> bytes:
    """Vocabulary PDF — grade 0-4: emojili kartlar, grade 5-12: premium tablo."""
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.units import cm
    from reportlab.lib.colors import HexColor, white, black, Color
    from reportlab.pdfgen import canvas
    import io

    buf = io.BytesIO()
    w, h = A4
    c = canvas.Canvas(buf, pagesize=A4)

    # Renkler
    _unit_colors = [
        (HexColor("#dc2626"), HexColor("#fee2e2")),   # red
        (HexColor("#ea580c"), HexColor("#ffedd5")),   # orange
        (HexColor("#ca8a04"), HexColor("#fef9c3")),   # yellow
        (HexColor("#16a34a"), HexColor("#dcfce7")),   # green
        (HexColor("#0891b2"), HexColor("#cffafe")),   # teal
        (HexColor("#2563eb"), HexColor("#dbeafe")),   # blue
        (HexColor("#7c3aed"), HexColor("#ede9fe")),   # purple
        (HexColor("#be185d"), HexColor("#fce7f3")),   # pink
        (HexColor("#0369a1"), HexColor("#e0f2fe")),   # sky
        (HexColor("#b45309"), HexColor("#fef3c7")),   # amber
    ]
    _DARK = HexColor("#94A3B8")
    _GRAY = HexColor("#64748b")
    _GOLD = HexColor("#f59e0b")

    _emoji_map = {**_GRADE14_WORD_EMOJI, **_PRESCHOOL_WORD_EMOJI}

    def _get_emoji(word):
        return _emoji_map.get(word, _emoji_map.get(word.lower(), "\U0001F539"))

    # ── Emoji → PNG renderer (Pillow + Segoe UI Emoji) ──
    from PIL import Image as _PILImage, ImageDraw as _PILDraw, ImageFont as _PILFont
    from reportlab.lib.utils import ImageReader
    import os as _os

    _emoji_font_path = _os.path.join(_os.environ.get("WINDIR", "C:/Windows"), "Fonts", "seguiemj.ttf")
    _emoji_font_cache = {}
    _emoji_img_cache = {}

    def _get_emoji_font(size):
        if size not in _emoji_font_cache:
            try:
                _emoji_font_cache[size] = _PILFont.truetype(_emoji_font_path, size)
            except Exception:
                _emoji_font_cache[size] = _PILFont.load_default()
        return _emoji_font_cache[size]

    def _emoji_to_reader(emoji_char, px_size=64):
        """Emoji karakterini ImageReader olarak döndürür (cache'li)."""
        _key = (emoji_char, px_size)
        if _key not in _emoji_img_cache:
            font = _get_emoji_font(px_size)
            _pad = 4
            img = _PILImage.new("RGBA", (px_size + _pad * 2, px_size + _pad * 2), (255, 255, 255, 0))
            draw = _PILDraw.Draw(img)
            try:
                draw.text((_pad, _pad), emoji_char, font=font, embedded_color=True)
            except TypeError:
                draw.text((_pad, _pad), emoji_char, font=font)
            _buf = io.BytesIO()
            img.save(_buf, format="PNG")
            _buf.seek(0)
            _emoji_img_cache[_key] = ImageReader(_buf)
        return _emoji_img_cache[_key]

    def _draw_emoji(x, y, emoji_char, size_pt=28):
        """PDF canvas üzerine emoji çizer (PNG olarak)."""
        try:
            reader = _emoji_to_reader(emoji_char, px_size=int(size_pt * 2.5))
            c.drawImage(reader, x, y, width=size_pt, height=size_pt, mask="auto")
        except Exception:
            # Fallback: renkli daire + soru işareti
            c.saveState()
            c.setFillColor(HexColor("#f59e0b"))
            c.circle(x + size_pt / 2, y + size_pt / 2, size_pt / 2.5, fill=1, stroke=0)
            c.setFont("Helvetica-Bold", int(size_pt * 0.4))
            c.setFillColor(white)
            c.drawCentredString(x + size_pt / 2, y + size_pt * 0.3, "?")
            c.restoreState()

    def _new_page():
        c.showPage()

    def _draw_rounded_rect(x, y, rw, rh, r, fill=None, stroke=None, sw=1):
        c.saveState()
        if fill:
            c.setFillColor(fill)
        if stroke:
            c.setStrokeColor(stroke)
            c.setLineWidth(sw)
        p = c.beginPath()
        p.roundRect(x, y, rw, rh, r)
        if fill and stroke:
            c.drawPath(p, fill=1, stroke=1)
        elif fill:
            c.drawPath(p, fill=1, stroke=0)
        else:
            c.drawPath(p, fill=0, stroke=1)
        c.restoreState()

    def _draw_star(x, y, size, color):
        import math
        c.saveState()
        c.setFillColor(color)
        p = c.beginPath()
        for i in range(5):
            angle = math.radians(-90 + i * 72)
            px = x + size * math.cos(angle)
            py = y + size * math.sin(angle)
            if i == 0:
                p.moveTo(px, py)
            else:
                p.lineTo(px, py)
            inner_angle = math.radians(-90 + i * 72 + 36)
            ix = x + size * 0.4 * math.cos(inner_angle)
            iy = y + size * 0.4 * math.sin(inner_angle)
            p.lineTo(ix, iy)
        p.close()
        c.drawPath(p, fill=1, stroke=0)
        c.restoreState()

    # Grade bilgisi
    _g = grade
    _is_emoji_mode = _g <= 4  # 0-4: emoji kartlar, 5-12: premium tablo
    _cefr_map = {0:"Pre-A1",1:"A1",2:"A1",3:"A1",4:"A1",5:"A2",6:"A2",7:"A2",8:"A2",
                 9:"B1",10:"B1+",11:"B2",12:"B2+"}
    _cefr = _cefr_map.get(_g, "A1")
    _kademe = "Okul Oncesi" if _g == 0 else "Ilkokul" if _g <= 4 else "Ortaokul" if _g <= 8 else "Lise"
    _grade_label = "Okul Oncesi" if _g == 0 else f"{_g}. Sinif"

    if isinstance(units_data, dict) and "units" in units_data:
        # grade_data format
        _all_units = units_data["units"]
        _prev_count = units_data.get("prev_word_count", 0)
    else:
        _all_units = units_data
        _prev_count = 0

    _selected = selected_units or [u["unit"] for u in _all_units]
    _units = [u for u in _all_units if u["unit"] in _selected]

    # ═══════════════════════════════════════════════════════════════
    # KAPAK SAYFASI
    # ═══════════════════════════════════════════════════════════════
    if _is_emoji_mode:
        # Yeşil gradient (ilkokul)
        for i in range(30):
            frac = i / 30
            r = 0.08 + frac * 0.2
            g = 0.44 + frac * 0.2
            b = 0.18 + frac * 0.3
            c.setFillColor(Color(min(r, 1), min(g, 1), min(b, 1)))
            c.rect(0, h - (i + 1) * (h / 30), w, h / 30 + 1, fill=1, stroke=0)
    else:
        # Koyu mavi gradient (ortaokul/lise)
        for i in range(30):
            frac = i / 30
            r = 0.05 + frac * 0.1
            g = 0.1 + frac * 0.15
            b = 0.35 + frac * 0.25
            c.setFillColor(Color(min(r, 1), min(g, 1), min(b, 1)))
            c.rect(0, h - (i + 1) * (h / 30), w, h / 30 + 1, fill=1, stroke=0)

    c.setStrokeColor(_GOLD)
    c.setLineWidth(3)
    c.roundRect(1.2 * cm, 1.2 * cm, w - 2.4 * cm, h - 2.4 * cm, 15, fill=0, stroke=1)

    import random as _rnd
    _rnd.seed(42 + _g)
    for _ in range(15):
        _draw_star(_rnd.uniform(2 * cm, w - 2 * cm),
                   _rnd.uniform(h - 6 * cm, h - 1.5 * cm),
                   _rnd.uniform(5, 10), _GOLD)

    _draw_rounded_rect(2 * cm, h - 14 * cm, w - 4 * cm, 10 * cm, 15,
                       fill=Color(1, 1, 1, 0.95), stroke=_GOLD, sw=3)

    c.setFont("Helvetica-Bold", 34)
    c.setFillColor(HexColor("#16a34a") if _is_emoji_mode else HexColor("#1e40af"))
    c.drawCentredString(w / 2, h - 5.5 * cm, "MY VOCABULARY")
    c.setFont("Helvetica-Bold", 22)
    c.setFillColor(_GOLD)
    c.drawCentredString(w / 2, h - 7 * cm, "BOOK")

    c.setFont("Helvetica-Bold", 16)
    c.setFillColor(HexColor("#7c3aed"))
    c.drawCentredString(w / 2, h - 8.5 * cm,
                       f"{_grade_label} — {_kademe}")
    c.setFont("Helvetica-Bold", 13)
    c.setFillColor(HexColor("#ea580c"))
    c.drawCentredString(w / 2, h - 9.5 * cm, f"CEFR {_cefr}")

    c.setFont("Helvetica", 11)
    c.setFillColor(_GRAY)
    _total_words = sum(u["word_count"] for u in _units)
    _desc = "Emojili Kelime Kartlari" if _is_emoji_mode else "Premium Kelime Tablolari + Turkce Karsiliklari"
    c.drawCentredString(w / 2, h - 11 * cm,
                       f"{len(_units)} Unite  |  {_total_words} Yeni Kelime  |  {_desc}")
    if _prev_count > 0 and _g > 0:
        c.setFont("Helvetica", 10)
        c.drawCentredString(w / 2, h - 11.8 * cm,
                           f"+ {_prev_count} kelime onceki siniflardan (kumulatif)")

    if _is_emoji_mode:
        _sample_emojis = ["\U0001F34E", "\U0001F431", "\u26BD", "\U0001F308", "\U0001F382", "\U0001F436", "\u2708\uFE0F", "\U0001F338", "\U0001F60A", "\U0001F534"]
        _ex = 2.5 * cm
        for ei, em in enumerate(_sample_emojis):
            _draw_emoji(_ex + ei * 1.6 * cm, h - 13.5 * cm, em, size_pt=30)

    # QR kod alanı (sesli dinleme)
    _draw_rounded_rect(2.5 * cm, 3 * cm, w - 5 * cm, 2.5 * cm, 8,
                       fill=Color(1, 1, 1, 0.8), stroke=_GOLD, sw=1)
    c.setFont("Helvetica-Bold", 9)
    c.setFillColor(HexColor("#16a34a"))
    c.drawCentredString(w / 2, 4.8 * cm, "Sesli Dinleme: Her unite sayfasindaki QR kodu telefonla tarat!")
    c.setFont("Helvetica", 8)
    c.setFillColor(_GRAY)
    c.drawCentredString(w / 2, 4.1 * cm,
                       "QR kod > SmartCampus AI > Yabanci Dil > Listening sekmesi > Unite secimi")
    c.drawCentredString(w / 2, 3.5 * cm,
                       "Kelimelerin telaffuzunu dinle, tekrarla ve pratik yap!")

    c.setFont("Helvetica", 9)
    c.setFillColor(_GOLD)
    c.drawCentredString(w / 2, 2 * cm, f"SmartCampus AI — {_grade_label} English Vocabulary")

    # ═══════════════════════════════════════════════════════════════
    # İÇİNDEKİLER
    # ═══════════════════════════════════════════════════════════════
    _new_page()
    c.setFillColor(HexColor("#f0fdf4"))
    c.rect(0, 0, w, h, fill=1, stroke=0)

    # Başlık
    c.setFillColor(HexColor("#16a34a"))
    c.rect(0, h - 2.5 * cm, w, 2.5 * cm, fill=1, stroke=0)
    c.setFont("Helvetica-Bold", 18)
    c.setFillColor(white)
    c.drawCentredString(w / 2, h - 1.7 * cm, "ICERIKLER — TABLE OF CONTENTS")

    y = h - 4 * cm
    for ui in _units:
        _uc, _ubg = _unit_colors[(ui["unit"] - 1) % len(_unit_colors)]
        _draw_rounded_rect(2 * cm, y - 1.8 * cm, w - 4 * cm, 2 * cm, 8,
                          fill=_ubg, stroke=_uc, sw=1.5)
        c.setFont("Helvetica-Bold", 13)
        c.setFillColor(_uc)
        c.drawString(2.8 * cm, y - 0.5 * cm,
                    f"Unite {ui['unit']}: {ui['name_en']}")
        c.setFont("Helvetica", 10)
        c.setFillColor(_DARK)
        c.drawString(2.8 * cm, y - 1.2 * cm,
                    f"{ui['name_tr']} — {ui['word_count']} kelime")
        c.setFont("Helvetica-Bold", 11)
        c.setFillColor(_GRAY)
        c.drawRightString(w - 2.5 * cm, y - 0.8 * cm,
                         f"{ui['word_count']} words")
        y -= 2.5 * cm
        if y < 3 * cm:
            _new_page()
            c.setFillColor(HexColor("#f0fdf4"))
            c.rect(0, 0, w, h, fill=1, stroke=0)
            y = h - 3 * cm

    # ═══════════════════════════════════════════════════════════════
    # ÜNİTE SAYFALARI
    # ═══════════════════════════════════════════════════════════════
    for ui in _units:
        _uc, _ubg = _unit_colors[(ui["unit"] - 1) % len(_unit_colors)]

        # ── Ünite kapak sayfası ──
        _new_page()
        c.setFillColor(_ubg)
        c.rect(0, 0, w, h, fill=1, stroke=0)

        c.setFillColor(_uc)
        c.rect(0, h - 4 * cm, w, 4 * cm, fill=1, stroke=0)
        c.setFont("Helvetica-Bold", 26)
        c.setFillColor(white)
        c.drawCentredString(w / 2, h - 2.2 * cm, f"UNIT {ui['unit']}")
        c.setFont("Helvetica-Bold", 18)
        c.drawCentredString(w / 2, h - 3.2 * cm, ui["name_en"])

        c.setFont("Helvetica-Bold", 14)
        c.setFillColor(_uc)
        c.drawCentredString(w / 2, h - 5.5 * cm, ui["name_tr"])

        c.setFont("Helvetica", 12)
        c.setFillColor(_DARK)
        _new_cnt = len(ui.get("new_words", ui["all_words"]))
        _prev_cnt = len(ui.get("prev_words", []))
        _wk_cnt = len(ui["weeks"])
        _info_line = f"{ui['word_count']} kelime — {_wk_cnt} hafta"
        if _prev_cnt > 0:
            _info_line += f" ({_new_cnt} yeni + {_prev_cnt} onceki)"
        c.drawCentredString(w / 2, h - 7 * cm, _info_line)

        # Emoji önizleme (sadece 0-4)
        if _is_emoji_mode:
            _preview_words = ui["all_words"][:12]
            _px = 2 * cm
            _py = h - 9.5 * cm
            for pi, pw in enumerate(_preview_words):
                em = _get_emoji(pw)
                _draw_emoji(_px, _py, em, size_pt=32)
                _px += 1.5 * cm
                if _px > w - 2 * cm:
                    _px = 2 * cm
                    _py -= 2 * cm

        # QR kod alanı
        _draw_rounded_rect(w / 2 - 3 * cm, 3 * cm, 6 * cm, 2 * cm, 6,
                          fill=Color(1, 1, 1, 0.9), stroke=_uc, sw=1)
        c.setFont("Helvetica-Bold", 8)
        c.setFillColor(_uc)
        c.drawCentredString(w / 2, 4.3 * cm, "Sesli Dinleme icin QR Kodu Tarat")
        # QR placeholder (kare çerçeve)
        c.setStrokeColor(_uc)
        c.setLineWidth(1.5)
        c.rect(w / 2 - 0.6 * cm, 3.2 * cm, 1.2 * cm, 1.2 * cm, fill=0, stroke=1)
        c.setFont("Helvetica", 6)
        c.setFillColor(_GRAY)
        c.drawCentredString(w / 2, 3.5 * cm, "QR")

        # Hafta listesi
        y = h - (14 * cm if _is_emoji_mode else 8.5 * cm)
        if y > 6 * cm:
            c.setFont("Helvetica-Bold", 11)
            c.setFillColor(_uc)
            c.drawString(2 * cm, y, "Haftalik Dagitim:")
            c.setFont("Helvetica", 10)
            c.setFillColor(_DARK)
            for wi, wd in enumerate(ui["weeks"]):
                y -= 0.6 * cm
                if y < 6 * cm:
                    break
                c.drawString(2.5 * cm, y,
                            f"Hafta {wd['week']}: {wd['theme']} ({wd['theme_tr']}) — {len(wd['words'])} kelime")

        # ══════════════════════════════════════════════════════
        if _is_emoji_mode:
            # ── EMOJİ KART MODU (Grade 0-4) ──
            _cards_per_page = 12
            _words = ui["all_words"]

            for page_start in range(0, len(_words), _cards_per_page):
                _new_page()
                c.setFillColor(_ubg)
                c.rect(0, 0, w, h, fill=1, stroke=0)

                c.setFillColor(_uc)
                c.rect(0, h - 2 * cm, w, 2 * cm, fill=1, stroke=0)
                c.setFont("Helvetica-Bold", 12)
                c.setFillColor(white)
                c.drawString(1.5 * cm, h - 1.4 * cm,
                            f"Unit {ui['unit']}: {ui['name_en']} — Kelime Kartlari")
                _pg_num = page_start // _cards_per_page + 1
                _pg_total = (len(_words) + _cards_per_page - 1) // _cards_per_page
                c.setFont("Helvetica", 9)
                c.drawRightString(w - 1.5 * cm, h - 1.4 * cm,
                                 f"Sayfa {_pg_num}/{_pg_total}")

                _page_words = _words[page_start:page_start + _cards_per_page]
                _cols = 3
                _rows = 4
                _card_w = (w - 3.5 * cm) / _cols
                _card_h = (h - 5 * cm) / _rows
                _margin_x = 1.5 * cm
                _top_y = h - 3 * cm

                for ci, word in enumerate(_page_words):
                    col = ci % _cols
                    row = ci // _cols
                    cx = _margin_x + col * (_card_w + 0.25 * cm)
                    cy = _top_y - row * (_card_h + 0.25 * cm) - _card_h

                    _draw_rounded_rect(cx, cy, _card_w, _card_h, 10,
                                      fill=Color(1, 1, 1, 0.95), stroke=_uc, sw=1.5)
                    emoji = _get_emoji(word)
                    _em_size = 36
                    _draw_emoji(cx + _card_w / 2 - _em_size / 2,
                               cy + _card_h * 0.5, emoji, size_pt=_em_size)

                    c.setFont("Helvetica-Bold", 13)
                    c.setFillColor(_uc)
                    _fw = len(word)
                    if _fw > 12:
                        c.setFont("Helvetica-Bold", 10)
                    elif _fw > 8:
                        c.setFont("Helvetica-Bold", 11)
                    c.drawCentredString(cx + _card_w / 2, cy + _card_h * 0.22, word)

                    c.setStrokeColor(HexColor("#d1d5db"))
                    c.setLineWidth(0.5)
                    c.setDash(2, 2)
                    c.line(cx + 0.4 * cm, cy + 0.3 * cm,
                           cx + _card_w - 0.4 * cm, cy + 0.3 * cm)
                    c.setDash()

                c.setFont("Helvetica", 7)
                c.setFillColor(_GRAY)
                c.drawCentredString(w / 2, 1 * cm,
                                   f"Vocabulary Book — {_grade_label} — Unit {ui['unit']}")

        else:
            # ── PREMİUM TABLO MODU (Grade 5-12) ──
            _words = ui["all_words"]
            _rows_per_page = 22
            _tr_dict = _WORD_TR

            for page_start in range(0, len(_words), _rows_per_page):
                _new_page()
                # Arka plan
                c.setFillColor(HexColor("#111827"))
                c.rect(0, 0, w, h, fill=1, stroke=0)

                # Üst banner
                c.setFillColor(_uc)
                c.rect(0, h - 2 * cm, w, 2 * cm, fill=1, stroke=0)
                c.setFont("Helvetica-Bold", 11)
                c.setFillColor(white)
                c.drawString(1.5 * cm, h - 1.4 * cm,
                            f"Unit {ui['unit']}: {ui['name_en']} — {_grade_label} ({_kademe})")
                _pg_num = page_start // _rows_per_page + 1
                _pg_total = (len(_words) + _rows_per_page - 1) // _rows_per_page
                c.setFont("Helvetica", 9)
                c.drawRightString(w - 1.5 * cm, h - 1.4 * cm,
                                 f"Sayfa {_pg_num}/{_pg_total}")

                # Tablo başlığı
                _th_y = h - 3 * cm
                _col_x = [1.5 * cm, 2.5 * cm, 8 * cm, 13.5 * cm]
                _col_labels = ["#", "English", "Turkce", "Notes"]

                # Başlık satırı
                _draw_rounded_rect(1.3 * cm, _th_y - 0.1 * cm, w - 2.6 * cm, 0.7 * cm, 4,
                                  fill=_uc, stroke=None)
                c.setFont("Helvetica-Bold", 9)
                c.setFillColor(white)
                for ci, cx in enumerate(_col_x):
                    c.drawString(cx, _th_y + 0.1 * cm, _col_labels[ci] if ci < len(_col_labels) else "")

                # Veri satırları
                _page_words = _words[page_start:page_start + _rows_per_page]
                _ry = _th_y - 0.7 * cm

                for ri, word in enumerate(_page_words):
                    _row_idx = page_start + ri + 1
                    _is_new = word in ui.get("new_words", _words)
                    # Zebra renk
                    _row_bg = Color(1, 1, 1, 1) if ri % 2 == 0 else HexColor("#1A2035")
                    c.setFillColor(_row_bg)
                    c.rect(1.3 * cm, _ry - 0.15 * cm, w - 2.6 * cm, 0.6 * cm, fill=1, stroke=0)

                    # Satır çizgisi
                    c.setStrokeColor(HexColor("#e2e8f0"))
                    c.setLineWidth(0.3)
                    c.line(1.3 * cm, _ry - 0.15 * cm, w - 1.3 * cm, _ry - 0.15 * cm)

                    # # sütunu
                    c.setFont("Helvetica", 8)
                    c.setFillColor(_GRAY)
                    c.drawString(_col_x[0], _ry + 0.05 * cm, str(_row_idx))

                    # English sütunu
                    c.setFont("Helvetica-Bold", 10)
                    c.setFillColor(_uc if _is_new else _DARK)
                    c.drawString(_col_x[1], _ry + 0.05 * cm, word[:25])
                    if _is_new:
                        # Yeni kelime işareti
                        c.setFont("Helvetica-Bold", 7)
                        c.setFillColor(HexColor("#16a34a"))
                        c.drawString(_col_x[1] + len(word[:25]) * 5.5 + 5, _ry + 0.1 * cm, "NEW")

                    # Türkçe sütunu
                    _tr = _tr_dict.get(word, _tr_dict.get(word.lower(), ""))
                    c.setFont("Helvetica", 10)
                    c.setFillColor(_DARK)
                    c.drawString(_col_x[2], _ry + 0.05 * cm, _tr[:25])

                    # Notes sütunu (boş — yazma alanı)
                    c.setStrokeColor(HexColor("#cbd5e1"))
                    c.setDash(2, 2)
                    c.line(_col_x[3], _ry, w - 1.5 * cm, _ry)
                    c.setDash()

                    _ry -= 0.6 * cm

                # Alt bilgi
                c.setFont("Helvetica", 7)
                c.setFillColor(_GRAY)
                c.drawCentredString(w / 2, 1 * cm,
                                   f"Vocabulary Book — {_grade_label} — Unit {ui['unit']} — CEFR {_cefr}")

        # ── Haftalık kelime listesi sayfası (özet) ──
        _new_page()
        c.setFillColor(_ubg)
        c.rect(0, 0, w, h, fill=1, stroke=0)

        c.setFillColor(_uc)
        c.rect(0, h - 2 * cm, w, 2 * cm, fill=1, stroke=0)
        c.setFont("Helvetica-Bold", 12)
        c.setFillColor(white)
        c.drawString(1.5 * cm, h - 1.4 * cm,
                    f"Unit {ui['unit']}: {ui['name_en']} — Haftalik Kelime Listesi")

        y = h - 3.2 * cm
        for wd in ui["weeks"]:
            _draw_rounded_rect(1.5 * cm, y - 0.7 * cm, w - 3 * cm, 0.9 * cm, 5,
                              fill=_uc, stroke=None)
            c.setFont("Helvetica-Bold", 10)
            c.setFillColor(white)
            c.drawString(2 * cm, y - 0.4 * cm,
                        f"Hafta {wd['week']}: {wd['theme']} ({wd['theme_tr']})")
            y -= 1.2 * cm

            _wlist = wd["words"]
            if _is_emoji_mode:
                _cols = 3
                _col_w = (w - 4 * cm) / _cols
                for wi, wrd in enumerate(_wlist):
                    col = wi % _cols
                    if col == 0 and wi > 0:
                        y -= 0.6 * cm
                    if y < 2.5 * cm:
                        _new_page()
                        c.setFillColor(_ubg)
                        c.rect(0, 0, w, h, fill=1, stroke=0)
                        c.setFillColor(_uc)
                        c.rect(0, h - 2 * cm, w, 2 * cm, fill=1, stroke=0)
                        c.setFont("Helvetica-Bold", 12)
                        c.setFillColor(white)
                        c.drawString(1.5 * cm, h - 1.4 * cm,
                                    f"Unit {ui['unit']} — Kelime Listesi (devam)")
                        y = h - 3.2 * cm
                    _cx = 2 * cm + col * _col_w
                    em = _get_emoji(wrd)
                    _draw_emoji(_cx, y - 0.1 * cm, em, size_pt=14)
                    c.setFont("Helvetica", 10)
                    c.setFillColor(_DARK)
                    c.drawString(_cx + 0.6 * cm, y, wrd)
            else:
                # Tablo modu — kelime + Türkçe
                for wi, wrd in enumerate(_wlist):
                    if y < 2.5 * cm:
                        _new_page()
                        c.setFillColor(_ubg)
                        c.rect(0, 0, w, h, fill=1, stroke=0)
                        c.setFillColor(_uc)
                        c.rect(0, h - 2 * cm, w, 2 * cm, fill=1, stroke=0)
                        c.setFont("Helvetica-Bold", 12)
                        c.setFillColor(white)
                        c.drawString(1.5 * cm, h - 1.4 * cm,
                                    f"Unit {ui['unit']} — Kelime Listesi (devam)")
                        y = h - 3.2 * cm
                    c.setFont("Helvetica-Bold", 10)
                    c.setFillColor(_uc)
                    c.drawString(2 * cm, y, wrd[:25])
                    _tr = _WORD_TR.get(wrd, _WORD_TR.get(wrd.lower(), ""))
                    c.setFont("Helvetica", 10)
                    c.setFillColor(_DARK)
                    c.drawString(8 * cm, y, _tr[:30])
                    y -= 0.5 * cm

            y -= 1 * cm

    c.save()
    return buf.getvalue()


def _render_vocabulary_tab():
    """Vocabulary — Tum siniflar icin Kelime Kitabi PDF (0-12)."""

    _CEFR_MAP = {0: "Pre-A1", 1: "A1", 2: "A1", 3: "A1", 4: "A1",
                 5: "A2", 6: "A2", 7: "A2", 8: "A2",
                 9: "B1", 10: "B1+", 11: "B2", 12: "B2+"}
    _GRADE_LABELS = {0: "Okul Oncesi", 1: "1. Sinif", 2: "2. Sinif", 3: "3. Sinif",
                     4: "4. Sinif", 5: "5. Sinif", 6: "6. Sinif", 7: "7. Sinif",
                     8: "8. Sinif", 9: "9. Sinif", 10: "10. Sinif", 11: "11. Sinif",
                     12: "12. Sinif"}

    st.markdown(
        '<div style="background:linear-gradient(135deg,#16a34a,#4ade80);color:white;'
        'padding:15px 20px;border-radius:12px;margin-bottom:15px;">'
        '<div style="font-size:1.3rem;font-weight:800;">'
        '\U0001F4DD Vocabulary — Kelime Kitabi</div>'
        '<div style="font-size:.85rem;opacity:.9;margin-top:4px;">'
        'Okul oncesinden 12. sinifa kadar kumulatif kelime kitabi PDF olusturur. '
        '1-4. siniflar emojili kartlar, 5-12. siniflar premium tablo (Turkce karsiliklari) '
        'formatinda uretilir. Her sinif onceki siniflarin kelimelerini de icerir.</div></div>',
        unsafe_allow_html=True,
    )

    # ── Sınıf seçimi ──
    _gc1, _gc2 = st.columns([1, 2])
    with _gc1:
        _vb_grade = st.selectbox(
            "Sinif Seviyesi:",
            list(range(0, 13)),
            format_func=lambda g: f"{_GRADE_LABELS[g]} ({_CEFR_MAP[g]})",
            key="vb_grade_select",
        )

    # ── Veri yükle ──
    if _vb_grade == 0:
        _vdata = _get_preschool_vocab_data()
        _grade_data = None
    else:
        _grade_data = _get_grade_vocab_data(_vb_grade)
        _vdata = _grade_data["units"]

    _is_emoji_mode = _vb_grade <= 4

    with _gc2:
        _mode_info = "Emojili Kartlar" if _is_emoji_mode else "Premium Tablo + Turkce"
        st.markdown(
            f'<div style="background:#f0fdf4;border:1px solid #86efac;border-radius:8px;'
            f'padding:10px 14px;margin-top:24px;">'
            f'<b style="color:#166534;">{_GRADE_LABELS[_vb_grade]}</b> | '
            f'CEFR {_CEFR_MAP[_vb_grade]} | {_mode_info}'
            f'{"" if _vb_grade == 0 else f" | Kumulatif: onceki siniflarin kelimeleri dahil"}'
            f'</div>',
            unsafe_allow_html=True,
        )

    # ── Ünite seçimi ──
    c1, c2 = st.columns([1, 1])
    with c1:
        _vb_mode = st.radio(
            "Mod:", ["Tum 10 Unite", "Secili Uniteler"],
            key="vb_mode", horizontal=True,
        )
    with c2:
        if _vb_mode == "Secili Uniteler":
            _vb_units = st.multiselect(
                "Uniteler:", list(range(1, 11)),
                default=list(range(1, 11)),
                format_func=lambda u: f"Unite {u}: {_vdata[u-1]['name_en']}" if u <= len(_vdata) else f"Unite {u}",
                key="vb_units_multi",
            )
        else:
            _vb_units = list(range(1, 11))

    # ── Ünite bilgi kartları ──
    _selected_data = [u for u in _vdata if u["unit"] in _vb_units]
    _total_words = sum(u["word_count"] for u in _selected_data)
    _em_lookup = {**_GRADE14_WORD_EMOJI, **_PRESCHOOL_WORD_EMOJI}
    _uc_hex = ["#dc2626","#ea580c","#ca8a04","#16a34a","#0891b2",
               "#2563eb","#7c3aed","#be185d","#0369a1","#b45309"]
    _ubg_hex = ["#fee2e2","#ffedd5","#fef9c3","#dcfce7","#cffafe",
                "#dbeafe","#ede9fe","#fce7f3","#e0f2fe","#fef3c7"]

    if _selected_data:
        _cards_html = '<div style="display:flex;flex-wrap:wrap;gap:8px;margin:10px 0;">'
        for ui in _selected_data:
            _ci = (ui["unit"] - 1) % 10
            if _is_emoji_mode:
                _emojis = " ".join([_em_lookup.get(w, _em_lookup.get(w.lower(), "\U0001F539"))
                                   for w in ui["all_words"][:6]])
                _preview_line = f'<div style="font-size:1.1rem;margin-top:4px;">{_emojis}</div>'
            else:
                _sample = ", ".join(ui["all_words"][:6])
                _preview_line = f'<div style="font-size:.75rem;color:#6b7280;margin-top:3px;font-style:italic;">{_sample}...</div>'
            _cards_html += (
                f'<div style="background:{_ubg_hex[_ci]};border:2px solid {_uc_hex[_ci]};'
                f'border-radius:10px;padding:10px 14px;flex:1;min-width:220px;">'
                f'<div style="font-weight:700;color:{_uc_hex[_ci]};font-size:.85rem;">'
                f'Unite {ui["unit"]}: {ui["name_en"]}</div>'
                f'<div style="font-size:.75rem;color:#94A3B8;margin-top:2px;">'
                f'{ui["name_tr"]} | {ui["word_count"]} kelime</div>'
                f'{_preview_line}</div>'
            )
        _cards_html += '</div>'
        st.markdown(_cards_html, unsafe_allow_html=True)

    # ── Kümülatif bilgi (grade > 0) ──
    if _grade_data and _vb_grade > 0:
        _prev_count = _grade_data.get("prev_word_count", 0)
        _new_count = _grade_data.get("total_new_words", 0)
        st.markdown(
            f'<div style="background:#eff6ff;border:1px solid #93c5fd;border-radius:8px;'
            f'padding:10px 14px;margin:6px 0;">'
            f'<span style="font-weight:700;color:#1e40af;">Kumulatif Kelime Dagilimi:</span> '
            f'<span style="color:#1d4ed8;">Onceki siniflardan: <b>{_prev_count}</b> kelime | '
            f'Bu sinifin yeni kelimeleri: <b>{_new_count}</b> | '
            f'Toplam: <b>{_prev_count + _new_count}</b></span></div>',
            unsafe_allow_html=True,
        )

    # ── Özet bilgi ──
    st.markdown(
        f'<div style="background:#dcfce7;border:1px solid #86efac;border-radius:8px;'
        f'padding:10px 14px;margin:6px 0;">'
        f'<span style="font-weight:700;color:#166534;">{_GRADE_LABELS[_vb_grade]}</span> | '
        f'<span style="color:#15803d;">{len(_vb_units)} unite | '
        f'<b>{_total_words} kelime</b> | '
        f'{"Emojili kartlar + haftalik listeler" if _is_emoji_mode else "Premium tablo + Turkce karsiliklari + QR Kod"}'
        f'</span></div>',
        unsafe_allow_html=True,
    )

    # ── Kelime önizleme (expander) ──
    with st.expander("Kelime Onizleme (Tum Uniteler)", expanded=False):
        for ui in _selected_data:
            _ci = (ui["unit"] - 1) % 10
            if _is_emoji_mode:
                _em_preview = " ".join([
                    f'{_em_lookup.get(w, _em_lookup.get(w.lower(), "\U0001F539"))} {w}'
                    for w in ui["all_words"][:15]
                ])
            else:
                _em_preview = " | ".join([
                    f'{w} ({_WORD_TR.get(w.lower(), "—")})'
                    for w in ui["all_words"][:15]
                ])
            _more = f' ... +{ui["word_count"] - 15} daha' if ui["word_count"] > 15 else ""
            st.markdown(
                f'<div style="margin:6px 0;padding:8px 12px;background:{_ubg_hex[_ci]};'
                f'border-left:4px solid {_uc_hex[_ci]};border-radius:6px;">'
                f'<b style="color:{_uc_hex[_ci]};">Unite {ui["unit"]}: {ui["name_en"]}</b><br>'
                f'<span style="font-size:.85rem;">{_em_preview}{_more}</span></div>',
                unsafe_allow_html=True,
            )

    # ── PDF üret butonu ──
    _grade_label_short = _GRADE_LABELS[_vb_grade].replace(". ", "").replace(" ", "_").lower()
    _btn_label = f"\U0001F4DD Vocabulary PDF Uret — {_GRADE_LABELS[_vb_grade]} ({len(_vb_units)} unite, {_total_words} kelime)"
    if st.button(_btn_label, key="vb_generate", use_container_width=True, type="primary"):
        if not _vb_units:
            st.warning("En az 1 unite secin.")
        else:
            with st.spinner(f"{_GRADE_LABELS[_vb_grade]} — {len(_vb_units)} unite — {_total_words} kelime hazirlaniyor..."):
                try:
                    pdf_bytes = _generate_vocab_pdf(_vdata, _vb_units, grade=_vb_grade, grade_data=_grade_data)
                    st.session_state["_vb_pdf"] = pdf_bytes
                    st.session_state["_vb_pdf_name"] = f"vocabulary_{_grade_label_short}_{len(_vb_units)}units.pdf"
                    st.success(f"Vocabulary PDF hazir! {_GRADE_LABELS[_vb_grade]} — {_total_words} kelime, {len(_vb_units)} unite.")
                except Exception as e:
                    st.error(f"PDF uretilemedi: {e}")

    # ── İndirme butonu ──
    if st.session_state.get("_vb_pdf"):
        st.download_button(
            label=f"\u2B07\uFE0F {st.session_state.get('_vb_pdf_name', 'vocabulary.pdf')} Indir",
            data=st.session_state["_vb_pdf"],
            file_name=st.session_state.get("_vb_pdf_name", "vocabulary.pdf"),
            mime="application/pdf",
            key="vb_download",
            use_container_width=True,
        )
        st.markdown(
            f'<div style="background:#111827;border:1px solid #e2e8f0;border-radius:8px;'
            f'padding:10px;margin-top:8px;font-size:.82rem;color:#64748b;">'
            f'Dosya boyutu: {len(st.session_state["_vb_pdf"]) / 1024:.0f} KB</div>',
            unsafe_allow_html=True,
        )

    # ── Sayfa içeriği açıklaması ──
    with st.expander("PDF Icerik Yapisi", expanded=False):
        st.markdown(
            '<div style="font-size:.82rem;color:#94A3B8;line-height:1.7;">'
            '<b>Her unite icin:</b><br>'
            '1. <b>Unite Kapak Sayfasi</b> — unite adi, kelime sayisi, emoji onizleme, haftalik dagitim<br>'
            '2. <b>Kelime Kartlari</b> — 3x4 grid, her kartta: buyuk emoji + kelime + yazma alani<br>'
            '3. <b>Haftalik Kelime Listesi</b> — hafta bazli emoji + kelime siralaması<br><br>'
            '<b>Toplam 10 Unite:</b><br>'
            '1. Greetings (Selamlasma) | 2. Colours (Renkler) | 3. Numbers (Sayilar)<br>'
            '4. Weather (Hava Durumu) | 5. Toys & Party | 6. Farm Animals<br>'
            '7. Seasons (Mevsimler) | 8. Beach & Nature | 9. Community Helpers<br>'
            '10. Goodbye & Review</div>',
            unsafe_allow_html=True,
        )


def _render_interactive_book_tab():
    """Interaktif Etkinlik Kitabi — Tam icerikli flipbook + EBA tarzi sayfalar + Practice Book."""
    from views.activity_book_grade2 import (
        build_page_body_speaking,
        build_page_body_pronunciation,
        build_activity_pages,
    )
    from views.textbook_grade5 import build_coursebook_flipbook_html as _build_flipbook

    styled_header("Interaktif Etkinlik Kitabi", "Dijital ders kitabi ve etkinlik sayfalari", icon="\U0001F4D6")

    # Kademe ve sinif secimi
    _ib_c1, _ib_c2, _ib_c3 = st.columns(3)
    with _ib_c1:
        _ib_kademe = st.selectbox("Kademe", ["Okul Oncesi", "Ilkokul (1-4)", "Ortaokul (5-8)", "Lise (9-12)"], key="ib_kademe")
    _grade_map = {
        "Okul Oncesi": [0],
        "Ilkokul (1-4)": [1, 2, 3, 4],
        "Ortaokul (5-8)": [5, 6, 7, 8],
        "Lise (9-12)": [9, 10, 11, 12],
    }
    _grades = _grade_map.get(_ib_kademe, [1, 2, 3, 4])
    _grade_labels = {0: "Okul Oncesi"}
    with _ib_c2:
        _ib_grade = st.selectbox("Sinif", _grades,
                                 format_func=lambda g: _grade_labels.get(g, f"{g}. Sinif"),
                                 key="ib_grade")
    # Practice Book sadece 1-4. siniflar icin
    _mode_options = ["Tam Kitap (Flipbook)", "Haftalik Etkinlik Sayfalari"]
    if _ib_grade in (1, 2, 3, 4):
        _mode_options.append("\U0001F4D8 Practice Book (Al\u0131\u015Ft\u0131rma)")
    with _ib_c3:
        _ib_mode = st.selectbox("Gorunum", _mode_options, key="ib_mode")

    # Curriculum verisi al
    _level_key = "preschool" if _ib_grade == 0 else f"grade{_ib_grade}"
    _curriculum_data = _CURRICULUM.get(_level_key, [])
    _weeks = _curriculum_data if isinstance(_curriculum_data, list) else _curriculum_data.get("weeks", [])

    if not _weeks:
        st.warning(f"Bu sinif icin mufredat verisi bulunamadi.")
        return

    # -------------------------------------------------------
    # MODE 1: Tam Kitap Flipbook (tum uniteler, tum bankalar)
    # -------------------------------------------------------
    if _ib_mode == "Tam Kitap (Flipbook)":
        _grade_label = "Okul Oncesi" if _ib_grade == 0 else f"{_ib_grade}. Sinif"
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#1e40af,#3b82f6);color:white;'
            f'padding:14px 20px;border-radius:12px;margin:10px 0;">'
            f'<div style="font-size:1.1rem;font-weight:800;">{_grade_label} Ingilizce Ders Kitabi</div>'
            f'<div style="font-size:.85rem;opacity:.85;margin-top:2px;">22 icerik bankasi x 10 unite = Tam kapsamli dijital kitap</div>'
            f'<div style="font-size:.8rem;opacity:.7;margin-top:4px;">'
            f'Hikaye, Okuma, Dilbilgisi, Dinleme, Yazma, Sarki, Diyalog, Telaffuz, Kultur Kosesi, '
            f'Turkiye Kosesi, Cizgi Roman, Gorev, Kacis Odasi, Aile Kosesi, SEL, STEAM, Podcast ve daha fazlasi</div></div>',
            unsafe_allow_html=True,
        )

        if st.button("\U0001F4D6 Flipbook Olustur", key="ib_flipbook_gen", type="primary", use_container_width=True):
            with st.spinner("Dijital kitap hazirlaniyor..."):
                _fb_html = _build_flipbook(_ib_grade, _weeks)
            st.components.v1.html(_fb_html, height=750, scrolling=True)
            st.download_button(
                "\U0001F4E5 HTML Olarak Indir",
                data=_fb_html.encode("utf-8"),
                file_name=f"flipbook_grade{_ib_grade}.html",
                mime="text/html",
                key="ib_fb_download",
                use_container_width=True,
            )

    # -------------------------------------------------------
    # MODE 2: Haftalik Etkinlik Sayfalari (EBA tarzi)
    # -------------------------------------------------------
    elif _ib_mode == "Haftalik Etkinlik Sayfalari":
        _ib_week = st.number_input("Hafta", min_value=1, max_value=36, value=1, key="ib_week")

        _sel_week = None
        for _w in _weeks:
            if _w.get("week") == _ib_week:
                _sel_week = _w
                break

        if _sel_week:
            _theme = _sel_week.get("theme", f"Week {_ib_week}")
            _theme_tr = _sel_week.get("theme_tr", "")
            _vocab = _sel_week.get("vocab", [])
            st.markdown(
                f'<div style="background:linear-gradient(135deg,#1e40af,#3b82f6);color:white;'
                f'padding:14px 20px;border-radius:12px;margin:10px 0;">'
                f'<div style="font-size:1.1rem;font-weight:800;">Week {_ib_week}: {_theme}</div>'
                f'<div style="font-size:.85rem;opacity:.85;margin-top:2px;">{_theme_tr}</div>'
                f'<div style="font-size:.8rem;opacity:.7;margin-top:4px;">'
                f'Kelimeler: {", ".join(_vocab[:8])}{"..." if len(_vocab) > 8 else ""}</div></div>',
                unsafe_allow_html=True,
            )
        else:
            st.warning(f"{_ib_grade}. sinif icin hafta {_ib_week} verisi bulunamadi.")
            return

        if st.button("\U0001F4D6 Sayfalari Olustur", key="ib_generate", type="primary", use_container_width=True):
            st.session_state["ib_generated"] = True

        if st.session_state.get("ib_generated"):
            if _ib_grade == 2 and _ib_week == 7:
                _pages = [build_page_body_speaking(), build_page_body_pronunciation()]
            else:
                _pages = build_activity_pages(_ib_grade, _ib_week, _weeks)

            if not _pages:
                st.error("Bu hafta icin sayfa uretilemedi.")
                return

            _page_tabs = st.tabs([f"Sayfa {i+1}" for i in range(len(_pages))])
            for _pi, _ptab in enumerate(_page_tabs):
                with _ptab:
                    st.components.v1.html(_pages[_pi], height=850, scrolling=True)

            _full_html = "\n<hr style='page-break-after:always;'>\n".join(_pages)
            st.download_button(
                "\U0001F4E5 HTML Olarak Indir",
                data=_full_html.encode("utf-8"),
                file_name=f"activity_book_grade{_ib_grade}_week{_ib_week}.html",
                mime="text/html",
                key="ib_download",
                use_container_width=True,
            )

    # -------------------------------------------------------
    # MODE 3: Practice Book (Alistirma / Pekistirme Kitabi)
    # -------------------------------------------------------
    else:
        from views.practice_book_primary import build_practice_pages, build_full_practice_book

        st.markdown(
            '<div style="background:linear-gradient(135deg,#7c3aed,#a855f7);color:white;'
            'padding:14px 20px;border-radius:12px;margin:10px 0;">'
            '<div style="font-size:1.1rem;font-weight:800;">'
            '\U0001F4D8 Practice Book \u2014 Al\u0131\u015Ft\u0131rma / Peki\u015Ftirme Kitab\u0131</div>'
            '<div style="font-size:.85rem;opacity:.85;margin-top:2px;">'
            'Bo\u015Fluk doldurma \u2022 E\u015Fle\u015Ftirme \u2022 Kelime tamamlama \u2022 Do\u011Fru/Yanl\u0131\u015F \u2022 K\u0131sa test</div>'
            '<div style="font-size:.78rem;opacity:.7;margin-top:4px;">'
            'Ana kitaptaki kazan\u0131mlar\u0131 tekrar ettirmek ve bireysel \u00E7al\u0131\u015Fma s\u00FCrecini desteklemek</div>'
            '</div>',
            unsafe_allow_html=True,
        )

        _pb_c1, _pb_c2 = st.columns([1, 1])
        with _pb_c1:
            _pb_scope = st.radio(
                "Kapsam", ["\U0001F4C5 Tek Hafta", "\U0001F4DA T\u00FCm Haftalar"],
                horizontal=True, key="pb_scope",
            )
        with _pb_c2:
            if "\U0001F4C5" in _pb_scope:
                _pb_week = st.number_input("Hafta", min_value=1, max_value=36, value=1, key="pb_week")

        if "\U0001F4C5" in _pb_scope:
            # Tek hafta
            _sel_w = None
            for _w in _weeks:
                if _w.get("week") == _pb_week:
                    _sel_w = _w
                    break
            if _sel_w:
                _th = _sel_w.get("theme", "")
                _th_tr = _sel_w.get("theme_tr", "")
                _vc = _sel_w.get("vocab", [])
                st.markdown(
                    f'<div style="background:#f5f3ff;border:2px solid #c4b5fd;border-radius:10px;'
                    f'padding:10px 16px;margin:8px 0;">'
                    f'<div style="font-weight:700;color:#7c3aed;">Hafta {_pb_week}: {_th}</div>'
                    f'<div style="font-size:.82rem;color:#6b7280;">{_th_tr}</div>'
                    f'<div style="font-size:.75rem;color:#94a3b8;margin-top:3px;">'
                    f'Kelimeler: {", ".join(_vc[:8])}</div></div>',
                    unsafe_allow_html=True,
                )

            if st.button("\U0001F4DD Al\u0131\u015Ft\u0131rmalar\u0131 Olu\u015Ftur", key="pb_gen",
                         type="primary", use_container_width=True):
                st.session_state["pb_generated"] = True

            if st.session_state.get("pb_generated"):
                _pages = build_practice_pages(_ib_grade, _pb_week, _weeks)
                if not _pages:
                    st.error("Bu hafta i\u00E7in al\u0131\u015Ft\u0131rma \u00FCretilemedi.")
                    return
                _pt = st.tabs([f"\U0001F4D6 Sayfa {i+1}" for i in range(len(_pages))])
                for _pi, _ptab in enumerate(_pt):
                    with _ptab:
                        st.components.v1.html(_pages[_pi], height=1100, scrolling=True)
                _full = "\n<hr style='page-break-after:always;'>\n".join(_pages)
                st.download_button(
                    "\U0001F4E5 HTML Olarak \u0130ndir",
                    data=_full.encode("utf-8"),
                    file_name=f"practice_book_grade{_ib_grade}_week{_pb_week}.html",
                    mime="text/html", key="pb_dl", use_container_width=True,
                )
        else:
            # Tum haftalar
            st.info(f"{_ib_grade}. S\u0131n\u0131f \u2014 {len(_weeks)} hafta i\u00E7in Practice Book \u00FCretilecek.")
            if st.button("\U0001F4DA T\u00FCm Kitab\u0131 Olu\u015Ftur", key="pb_gen_all",
                         type="primary", use_container_width=True):
                with st.spinner("T\u00FCm haftalar i\u00E7in al\u0131\u015Ft\u0131rmalar haz\u0131rlan\u0131yor..."):
                    _all_data = build_full_practice_book(_ib_grade, _weeks)
                if not _all_data:
                    st.error("\u00DCretilemedi.")
                    return
                st.success(f"{len(_all_data)} hafta i\u00E7in Practice Book haz\u0131r!")
                for item in _all_data:
                    with st.expander(f"Hafta {item['week']}: {item['theme']}", expanded=False):
                        _sub_tabs = st.tabs([f"Sayfa {j+1}" for j in range(len(item["pages"]))])
                        for _j, _st2 in enumerate(_sub_tabs):
                            with _st2:
                                st.components.v1.html(item["pages"][_j], height=1100, scrolling=True)
                # Full download
                _all_html_parts = []
                for item in _all_data:
                    for pg in item["pages"]:
                        _all_html_parts.append(pg)
                _full_all = "\n<hr style='page-break-after:always;'>\n".join(_all_html_parts)
                st.download_button(
                    f"\U0001F4E5 T\u00FCm Kitab\u0131 \u0130ndir ({len(_all_data)} hafta)",
                    data=_full_all.encode("utf-8"),
                    file_name=f"practice_book_grade{_ib_grade}_full.html",
                    mime="text/html", key="pb_dl_all", use_container_width=True,
                )


def _generate_kazanim_pdf(level_name: str, cefr: str, color: str, weeks: list) -> bytes:
    """Kazanim listesini profesyonel PDF olarak uret."""
    import io
    from reportlab.lib.pagesizes import A4
    from reportlab.lib import colors as rl
    from reportlab.lib.units import cm, mm
    from reportlab.lib.styles import ParagraphStyle
    from reportlab.lib.enums import TA_CENTER, TA_LEFT
    from reportlab.platypus import (SimpleDocTemplate, Paragraph, Spacer,
                                     Table, TableStyle, PageBreak, KeepTogether)
    try:
        from utils.shared_data import ensure_turkish_pdf_fonts
        fn, fb = ensure_turkish_pdf_fonts()
    except Exception:
        fn, fb = "Helvetica", "Helvetica-Bold"

    buf = io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4,
                            topMargin=1.5*cm, bottomMargin=1.5*cm,
                            leftMargin=1.8*cm, rightMargin=1.8*cm)
    story = []

    # --- Styles ---
    s_title = ParagraphStyle("KzTitle", fontName=fb, fontSize=18, alignment=TA_CENTER,
                              spaceAfter=4*mm, textColor=rl.HexColor("#1e1b4b"))
    s_sub = ParagraphStyle("KzSub", fontName=fn, fontSize=11, alignment=TA_CENTER,
                            spaceAfter=8*mm, textColor=rl.HexColor("#6b7280"))
    s_unit = ParagraphStyle("KzUnit", fontName=fb, fontSize=13, spaceAfter=3*mm,
                             spaceBefore=6*mm, textColor=rl.HexColor("#4c1d95"))
    s_skill = ParagraphStyle("KzSkill", fontName=fb, fontSize=10, spaceAfter=2*mm,
                              textColor=rl.HexColor("#94A3B8"))
    s_code = ParagraphStyle("KzCode", fontName=fb, fontSize=8, textColor=rl.HexColor("#ffffff"))
    s_desc = ParagraphStyle("KzDesc", fontName=fn, fontSize=9, leading=13,
                             textColor=rl.HexColor("#1f2937"))
    s_meta = ParagraphStyle("KzMeta", fontName=fn, fontSize=8, textColor=rl.HexColor("#6366f1"))
    s_footer = ParagraphStyle("KzFooter", fontName=fn, fontSize=7, alignment=TA_CENTER,
                               textColor=rl.HexColor("#9ca3af"))

    _skill_colors = {
        "listening": "#7c3aed", "speaking": "#059669",
        "reading": "#2563eb", "writing": "#dc2626",
    }
    _skill_labels = {
        "listening": "Dinleme (Listening)", "speaking": "Konusma (Speaking)",
        "reading": "Okuma (Reading)", "writing": "Yazma (Writing)",
    }
    _skill_icons = {
        "listening": "\U0001F3A7", "speaking": "\U0001F5E3",
        "reading": "\U0001F4D6", "writing": "\u270D",
    }

    # --- Cover / Title ---
    story.append(Spacer(1, 1.5*cm))
    story.append(Paragraph("YABANCI DIL KAZANIMLARI", s_title))
    story.append(Paragraph(f"{level_name} \u2014 CEFR: {cefr}", s_sub))

    _total_oc = sum(len(w.get("outcome_codes", [])) for w in weeks)
    _total_units = len(set(w.get("unit", w.get("week", 0)) for w in weeks))
    _info_text = f"Toplam: {_total_oc} Kazanim | {_total_units} Unite/Hafta | {len(weeks)} Hafta"
    story.append(Paragraph(_info_text, s_sub))
    story.append(Spacer(1, 5*mm))

    # --- Summary table ---
    _sum_data = [["Unite/Hafta", "Tema", "CEFR", "Kazanim"]]
    _seen = set()
    for w in weeks:
        _u = w.get("unit", w.get("week", 0))
        if _u in _seen:
            continue
        _seen.add(_u)
        _theme = w.get("unit_theme", w.get("theme", ""))
        _c = w.get("outcomes", {}).get("cefr", cefr)
        # Count outcomes for this unit
        _cnt = 0
        for ww in weeks:
            if ww.get("unit", ww.get("week", 0)) == _u:
                _cnt += len(ww.get("outcome_codes", []))
        _label = f"Unite {_u}" if w.get("unit") else f"Hafta {_u}"
        _sum_data.append([_label, _theme[:40], _c, str(_cnt)])

    if len(_sum_data) > 1:
        _sum_t = Table(_sum_data, colWidths=[3*cm, 8*cm, 2*cm, 2.5*cm])
        _sum_t.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (-1, 0), rl.HexColor("#4c1d95")),
            ("TEXTCOLOR", (0, 0), (-1, 0), rl.white),
            ("FONTNAME", (0, 0), (-1, 0), fb),
            ("FONTSIZE", (0, 0), (-1, 0), 9),
            ("FONTNAME", (0, 1), (-1, -1), fn),
            ("FONTSIZE", (0, 1), (-1, -1), 8),
            ("ALIGN", (2, 0), (-1, -1), "CENTER"),
            ("ROWBACKGROUNDS", (0, 1), (-1, -1), [rl.HexColor("#f5f3ff"), rl.white]),
            ("GRID", (0, 0), (-1, -1), 0.5, rl.HexColor("#c4b5fd")),
            ("TOPPADDING", (0, 0), (-1, -1), 4),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
            ("LEFTPADDING", (0, 0), (-1, -1), 6),
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ]))
        story.append(_sum_t)
    story.append(PageBreak())

    # --- Detail pages ---
    _seen2 = set()
    for w in weeks:
        _u = w.get("unit", w.get("week", 0))
        if _u in _seen2:
            continue
        _seen2.add(_u)

        _theme = w.get("unit_theme", w.get("theme", ""))
        _oc = w.get("outcomes", {})
        _c = _oc.get("cefr", cefr)
        _label = f"Unite {_u}: {_theme}" if w.get("unit") else f"Hafta {_u}: {_theme}"

        # Merge outcomes from all weeks of same unit
        _merged = {"listening": [], "speaking": [], "reading": [], "writing": []}
        _funcs = []
        _grams = []
        for ww in weeks:
            if ww.get("unit", ww.get("week", 0)) == _u:
                _woc = ww.get("outcomes", {})
                for sk in _merged:
                    _merged[sk].extend(_woc.get(sk, []))
                _funcs.extend(_woc.get("functions", []))
                _gt = _woc.get("grammar_targets", _woc.get("grammar_focus", []))
                if isinstance(_gt, str):
                    _gt = [_gt] if _gt else []
                _grams.extend(_gt)

        _block = []
        _block.append(Paragraph(f"\U0001F3AF {_label} ({_c})", s_unit))

        # Functions & Grammar
        if _funcs:
            _block.append(Paragraph(f"Functions: {', '.join(dict.fromkeys(_funcs))}", s_meta))
        if _grams:
            _block.append(Paragraph(f"Grammar: {', '.join(dict.fromkeys(_grams))}", s_meta))
        _block.append(Spacer(1, 3*mm))

        for sk in ["listening", "speaking", "reading", "writing"]:
            _outs = _merged[sk]
            if not _outs:
                continue
            _sc = _skill_colors[sk]
            _block.append(Paragraph(
                f"{_skill_icons[sk]} {_skill_labels[sk]} ({len(_outs)})", s_skill))

            _rows = [["Kod", "Kazanim Aciklamasi"]]
            for o in _outs:
                _cd = o.get("code", "") if isinstance(o, dict) else ""
                _ds = o.get("desc", "") if isinstance(o, dict) else str(o)
                _rows.append([
                    Paragraph(_cd, ParagraphStyle("c", fontName=fb, fontSize=7.5,
                              textColor=rl.HexColor(_sc))),
                    Paragraph(_ds, s_desc),
                ])
            _t = Table(_rows, colWidths=[2.8*cm, 13*cm])
            _t.setStyle(TableStyle([
                ("BACKGROUND", (0, 0), (-1, 0), rl.HexColor(_sc)),
                ("TEXTCOLOR", (0, 0), (-1, 0), rl.white),
                ("FONTNAME", (0, 0), (-1, 0), fb),
                ("FONTSIZE", (0, 0), (-1, 0), 8),
                ("FONTNAME", (0, 1), (-1, -1), fn),
                ("FONTSIZE", (0, 1), (-1, -1), 8),
                ("ROWBACKGROUNDS", (0, 1), (-1, -1), [rl.white, rl.HexColor("#fafafa")]),
                ("GRID", (0, 0), (-1, -1), 0.4, rl.HexColor("#e5e7eb")),
                ("TOPPADDING", (0, 0), (-1, -1), 3),
                ("BOTTOMPADDING", (0, 0), (-1, -1), 3),
                ("LEFTPADDING", (0, 0), (-1, -1), 5),
                ("VALIGN", (0, 0), (-1, -1), "TOP"),
            ]))
            _block.append(_t)
            _block.append(Spacer(1, 4*mm))

        story.append(KeepTogether(_block) if len(_block) < 15 else _block[0])
        if len(_block) >= 15:
            story.extend(_block[1:])
        story.append(Spacer(1, 6*mm))

    # --- Footer info ---
    story.append(Spacer(1, 8*mm))
    from datetime import datetime as _dt
    story.append(Paragraph(
        f"SmartCampusAI \u2014 Yabanci Dil Kazanim Raporu \u2014 {_dt.now().strftime('%d.%m.%Y')}",
        s_footer))

    doc.build(story)
    return buf.getvalue()


def _render_kazanimlar_tab():
    """Tum kademeler icin kazanim goruntuleme sekmesi."""
    import json as _kz_json

    # ── Header ──
    st.markdown(
        '<div style="background:linear-gradient(135deg,#581c87,#7c3aed);padding:20px 24px;'
        'border-radius:16px;margin-bottom:16px;">'
        '<div style="font-size:1.3rem;font-weight:800;color:#f5f3ff;letter-spacing:.3px;">'
        '\U0001F3AF Kazanim Yonetimi</div>'
        '<div style="font-size:.85rem;color:#c4b5fd;margin-top:4px;">'
        'Tum kademelerin CEFR uyumlu kazanimlari — Dinleme, Konusma, Okuma, Yazma</div></div>',
        unsafe_allow_html=True,
    )

    # ── Load data ──
    _kz_cache = "_yd_kazanimlar_cache_v1"
    if _kz_cache not in st.session_state:
        try:
            _kz_path = _WP_PATH
            with open(_kz_path, "r", encoding="utf-8") as _f:
                st.session_state[_kz_cache] = _kz_json.load(_f)
        except Exception:
            st.session_state[_kz_cache] = {}
    _kz_data = st.session_state[_kz_cache]

    if not _kz_data:
        st.error("weekly_plans.json yuklenemedi.")
        return

    # ── Kademe + CEFR bilgileri ──
    _kz_levels = [
        ("preschool", "Okul Oncesi", "Pre-A1", "#0ea5e9"),
        ("1", "1. Sinif", "Pre-A1", "#ef4444"),
        ("2", "2. Sinif", "Pre-A1", "#ef4444"),
        ("3", "3. Sinif", "A1", "#f97316"),
        ("4", "4. Sinif", "A1", "#f97316"),
        ("5", "5. Sinif", "A2", "#eab308"),
        ("6", "6. Sinif", "A2", "#eab308"),
        ("7", "7. Sinif", "B1", "#22c55e"),
        ("8", "8. Sinif", "B1", "#22c55e"),
        ("9", "9. Sinif", "B1", "#3b82f6"),
        ("10", "10. Sinif", "B1+", "#6366f1"),
        ("11", "11. Sinif", "B2", "#8b5cf6"),
        ("12", "12. Sinif", "B2+", "#a855f7"),
    ]

    # ── Summary stats ──
    _total_outcomes = 0
    _level_stats = []
    for _lk, _ln, _lc, _lcol in _kz_levels:
        _weeks = _kz_data.get(_lk, [])
        _count = 0
        for _w in _weeks:
            _oc = _w.get("outcome_codes", [])
            _count += len(_oc)
        _total_outcomes += _count
        _level_stats.append((_lk, _ln, _lc, _lcol, _count))

    # ── Stats row ──
    _st_cols = st.columns(4)
    _stats_items = [
        ("\U0001F3AF", "Toplam Kazanim", str(_total_outcomes), "#7c3aed"),
        ("\U0001F4DA", "Kademe Sayisi", "13", "#3b82f6"),
        ("\U0001F4C5", "Hafta/Kademe", "36", "#059669"),
        ("\U0001F30D", "CEFR Aralik", "Pre-A1 \u2192 B2+", "#0ea5e9"),
    ]
    for _si, _sc in enumerate(_stats_items):
        with _st_cols[_si]:
            st.markdown(
                f'<div style="background:linear-gradient(135deg,{_sc[3]}15,{_sc[3]}08);'
                f'border:1px solid {_sc[3]}30;border-radius:12px;padding:16px;text-align:center;">'
                f'<div style="font-size:1.6rem;">{_sc[0]}</div>'
                f'<div style="font-size:1.4rem;font-weight:800;color:{_sc[3]};margin:4px 0;">{_sc[2]}</div>'
                f'<div style="font-size:.75rem;color:#6b7280;">{_sc[1]}</div></div>',
                unsafe_allow_html=True,
            )

    st.markdown("<div style='height:12px'></div>", unsafe_allow_html=True)

    # ── Level selector ──
    _kz_sel_cols = st.columns([2, 2, 1])
    with _kz_sel_cols[0]:
        _kz_level_options = [f"{_ln} ({_lc}) — {_cnt} kazanim" for _lk, _ln, _lc, _lcol, _cnt in _level_stats]
        _kz_sel_idx = st.selectbox("Kademe Secin", range(len(_kz_level_options)), format_func=lambda i: _kz_level_options[i], key="kz_level_sel")
    _sel_lk, _sel_ln, _sel_lc, _sel_lcol, _sel_cnt = _level_stats[_kz_sel_idx]
    _sel_weeks = _kz_data.get(_sel_lk, [])

    # ── Week/Unit filter ──
    with _kz_sel_cols[1]:
        if _sel_lk == "preschool" or _sel_lk in ["9","10","11","12"]:
            _week_options = ["Tum Haftalar"] + [f"Hafta {_w.get('week',0)}: {_w.get('theme','')}" for _w in _sel_weeks if _w.get("outcome_codes")]
        else:
            # Find unique units
            _seen_units = set()
            _unit_opts = ["Tum Uniteler"]
            for _w in _sel_weeks:
                _u = _w.get("unit")
                if _u and _u not in _seen_units and _w.get("outcome_codes"):
                    _seen_units.add(_u)
                    _unit_opts.append(f"Unite {_u}: {_w.get('unit_theme','')}")
            _week_options = _unit_opts
        _kz_week_sel = st.selectbox("Filtre", _week_options, key="kz_week_sel")

    # ── Skill filter ──
    with _kz_sel_cols[2]:
        _skill_filter = st.selectbox("Beceri", ["Tumu", "Dinleme", "Konusma", "Okuma", "Yazma"], key="kz_skill_sel")

    _skill_map = {"Dinleme": "listening", "Konusma": "speaking", "Okuma": "reading", "Yazma": "writing"}
    _icons = {"listening": "\U0001F3A7", "speaking": "\U0001F5E3\uFE0F", "reading": "\U0001F4D6", "writing": "\u270D\uFE0F"}
    _colors = {"listening": "#7c3aed", "speaking": "#059669", "reading": "#2563eb", "writing": "#dc2626"}
    _labels = {"listening": "Dinleme", "speaking": "Konusma", "reading": "Okuma", "writing": "Yazma"}

    # ── Filter weeks ──
    _filtered_weeks = []
    for _w in _sel_weeks:
        if not _w.get("outcomes"):
            continue
        if _kz_week_sel == "Tum Haftalar" or _kz_week_sel == "Tum Uniteler":
            _filtered_weeks.append(_w)
        elif _kz_week_sel.startswith("Hafta "):
            _wn = int(_kz_week_sel.split(":")[0].replace("Hafta ", ""))
            if _w.get("week") == _wn:
                _filtered_weeks.append(_w)
        elif _kz_week_sel.startswith("Unite "):
            _un = int(_kz_week_sel.split(":")[0].replace("Unite ", ""))
            if _w.get("unit") == _un:
                _filtered_weeks.append(_w)

    if not _filtered_weeks:
        st.info("Secilen filtreye uygun kazanim bulunamadi.")
        return

    # ── Render outcomes ──
    _shown_units = set()
    for _w in _filtered_weeks:
        _oc = _w.get("outcomes", {})
        _week_num = _w.get("week", 0)
        _unit_num = _w.get("unit", None)
        _theme = _w.get("unit_theme", _w.get("theme", ""))
        _cefr = _oc.get("cefr", _sel_lc)

        # For grades 1-8, show unit header only once
        if _unit_num:
            if _unit_num in _shown_units:
                continue
            _shown_units.add(_unit_num)
            _header = f"Unite {_unit_num}: {_theme}"
        else:
            _header = f"Hafta {_week_num}: {_theme}"

        # Functions & Grammar
        _functions = _oc.get("functions", [])
        _grammar = _oc.get("grammar_targets", _oc.get("grammar_focus", []))
        if isinstance(_grammar, str):
            _grammar = [_grammar] if _grammar else []

        _func_tags = " ".join(
            f'<span style="background:rgba(99,102,241,0.12);color:#4f46e5;padding:2px 8px;'
            f'border-radius:8px;font-size:.7rem;display:inline-block;margin:1px;">{fn}</span>'
            for fn in _functions
        )
        _gram_tags = " ".join(
            f'<span style="background:rgba(234,179,8,0.15);color:#a16207;padding:2px 8px;'
            f'border-radius:8px;font-size:.7rem;display:inline-block;margin:1px;">{gm}</span>'
            for gm in _grammar
        )

        # Build skill cards
        _skills_to_show = ["listening", "speaking", "reading", "writing"]
        if _skill_filter != "Tumu":
            _skills_to_show = [_skill_map[_skill_filter]]

        _cards_html = ""
        _total_in_unit = 0
        for _sk in _skills_to_show:
            _outs = _oc.get(_sk, [])
            if not _outs:
                continue
            _total_in_unit += len(_outs)
            _items_html = ""
            for _o in _outs:
                _code = _o.get("code", "") if isinstance(_o, dict) else ""
                _desc = _o.get("desc", "") if isinstance(_o, dict) else str(_o)
                _items_html += (
                    f'<div style="display:flex;gap:8px;margin-bottom:4px;align-items:flex-start;">'
                    f'<span style="background:{_colors[_sk]};color:#fff;padding:2px 8px;border-radius:6px;'
                    f'font-size:.65rem;font-weight:700;white-space:nowrap;margin-top:2px;'
                    f'font-family:monospace;">{_code}</span>'
                    f'<span style="color:#94A3B8;font-size:.78rem;line-height:1.4;">{_desc}</span></div>'
                )
            _cards_html += (
                f'<div style="background:#fff;border:1px solid {_colors[_sk]}20;border-radius:12px;'
                f'padding:12px 14px;border-left:4px solid {_colors[_sk]};">'
                f'<div style="font-weight:700;font-size:.82rem;color:{_colors[_sk]};margin-bottom:8px;">'
                f'{_icons[_sk]} {_labels[_sk]} ({len(_outs)})</div>{_items_html}</div>'
            )

        if not _cards_html:
            continue

        # Meta info
        _meta = ""
        if _func_tags:
            _meta += f'<div style="margin-bottom:4px;"><span style="font-weight:600;font-size:.7rem;color:#6366f1;">Functions:</span> {_func_tags}</div>'
        if _gram_tags:
            _meta += f'<div><span style="font-weight:600;font-size:.7rem;color:#a16207;">Grammar:</span> {_gram_tags}</div>'

        with st.expander(f"\U0001F3AF {_header} ({_total_in_unit} kazanim | {_cefr})", expanded=(_kz_week_sel != "Tum Haftalar" and _kz_week_sel != "Tum Uniteler")):
            if _meta:
                st.markdown(
                    f'<div style="background:#111827;border:1px solid #e2e8f0;border-radius:10px;'
                    f'padding:10px 14px;margin-bottom:10px;">{_meta}</div>',
                    unsafe_allow_html=True,
                )
            st.markdown(
                f'<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">{_cards_html}</div>',
                unsafe_allow_html=True,
            )

    # ── Export section ──
    st.markdown("<div style='height:12px'></div>", unsafe_allow_html=True)
    st.markdown(
        '<div style="background:linear-gradient(135deg,#f5f3ff,#ede9fe);border:1px solid #c4b5fd;'
        'border-radius:12px;padding:12px 16px;margin-bottom:10px">'
        '<span style="color:#5b21b6;font-weight:700">\U0001F4E5 Kazanim Indirme</span></div>',
        unsafe_allow_html=True,
    )
    _exp_c1, _exp_c2, _exp_c3 = st.columns(3)
    with _exp_c1:
        _pdf_scope = st.selectbox(
            "Kapsam", ["Secili Filtre", "Tum Yil (36 Hafta)"],
            key="kz_pdf_scope",
        )
    with _exp_c2:
        _pdf_format = st.selectbox(
            "Format", ["PDF", "JSON"],
            key="kz_pdf_format",
        )
    with _exp_c3:
        st.markdown("<div style='height:28px'></div>", unsafe_allow_html=True)
        _do_export = st.button("\U0001F4E5 Indir", key="kz_export_btn", use_container_width=True, type="primary")

    if _do_export:
        _exp_weeks = _filtered_weeks if _pdf_scope == "Secili Filtre" else [w for w in _sel_weeks if w.get("outcomes")]
        if _pdf_format == "JSON":
            _export = {}
            for _w in _exp_weeks:
                _oc = _w.get("outcomes", {})
                _key = f"w{_w.get('week',0)}"
                _export[_key] = {
                    "week": _w.get("week"),
                    "unit": _w.get("unit"),
                    "theme": _w.get("unit_theme", _w.get("theme", "")),
                    "cefr": _oc.get("cefr", ""),
                    "outcome_codes": _w.get("outcome_codes", []),
                    "outcomes": _oc,
                }
            st.download_button(
                "\U0001F4BE JSON Indir",
                data=_kz_json.dumps(_export, ensure_ascii=False, indent=2),
                file_name=f"kazanimlar_{_sel_lk}.json",
                mime="application/json",
                key="kz_download_json",
            )
        else:
            try:
                _pdf_bytes = _generate_kazanim_pdf(_sel_ln, _sel_lc, _sel_lcol, _exp_weeks)
                _scope_label = "filtre" if _pdf_scope == "Secili Filtre" else "yillik"
                st.download_button(
                    "\U0001F4BE PDF Indir",
                    data=_pdf_bytes,
                    file_name=f"kazanimlar_{_sel_lk}_{_scope_label}.pdf",
                    mime="application/pdf",
                    key="kz_download_pdf",
                )
            except Exception as _pdf_err:
                st.error(f"PDF olusturma hatasi: {_pdf_err}")


def _render_curriculum_tab(key_prefix, level, content_registry=None, builder_registry=None):
    """Haftalik Plan sekmesi UI — 36 haftalik mufredat plani goruntuleme."""
    from views.yd_content import _build_week_content_html, _cached_curriculum_pdf
    weeks_data = _CURRICULUM.get(level, [])
    if not weeks_data:
        st.warning("Bu seviye için müfredat verisi bulunamadı.")
        return

    # Load outcomes from weekly_plans.json for this grade
    _grade_num = level.replace("grade", "").replace("preschool", "0")
    _wp_oc_cache_key = "_yd_wp_outcomes_v4"
    if _wp_oc_cache_key not in st.session_state:
        try:
            _wp_oc_path = _WP_PATH
            with open(_wp_oc_path, "r", encoding="utf-8") as _f:
                st.session_state[_wp_oc_cache_key] = _json.load(_f)
        except Exception:
            st.session_state[_wp_oc_cache_key] = {}
    _wp_all = st.session_state[_wp_oc_cache_key]
    _wp_grade_weeks = _wp_all.get(_grade_num, [])

    lvl_label = _CURRICULUM_LEVEL_LABELS.get(level, level)
    cefr = _CURRICULUM_CEFR.get(level, "")

    st.markdown(
        f'<div style="background:linear-gradient(135deg,#1e40af,#2563eb);color:#fff;'
        f'padding:16px 20px;border-radius:12px;margin-bottom:16px;text-align:center;">'
        f'<h3 style="margin:0;font-size:18px;">\U0001F4CB {lvl_label} — 36 Haftalık İngilizce Müfredat Planı</h3>'
        f'<p style="margin:4px 0 0;font-size:13px;opacity:0.9;">CEFR {cefr} | 10 ders saati/hafta (Pzt-Cum, 2×40dk)</p>'
        f'</div>',
        unsafe_allow_html=True,
    )

    # Hafta seçimi
    auto_wk = _curriculum_auto_week()
    col1, col2 = st.columns([3, 1])
    with col1:
        sel_week = st.selectbox(
            "Hafta Seç:",
            range(1, 37),
            index=auto_wk - 1,
            format_func=lambda w: f"Hafta {w}: {weeks_data[w - 1]['theme']} — {weeks_data[w - 1]['theme_tr']}",
            key=f"{key_prefix}_curr_week",
        )
    with col2:
        st.markdown("<div style='height:28px'></div>", unsafe_allow_html=True)
        if st.button("\U0001F4C5 Bu Haftaya Git", key=f"{key_prefix}_curr_auto"):
            sel_week = auto_wk

    wk = weeks_data[sel_week - 1]

    # Find outcomes from weekly_plans.json for this unit
    # _CURRICULUM weeks don't have "unit" field, so calculate from week number (4 weeks per unit)
    _unit_outcomes = None
    _cur_unit_num = wk.get("unit") or ((wk.get("week", 1) - 1) // 4 + 1)
    if _wp_grade_weeks and _cur_unit_num is not None:
        for _wpw in _wp_grade_weeks:
            if _wpw.get("unit") == _cur_unit_num and _wpw.get("outcomes"):
                _unit_outcomes = _wpw["outcomes"]
                break

    # Hafta başlığı
    _cefr_badge = ""
    if _unit_outcomes:
        _oc_cefr = _unit_outcomes.get("cefr", "")
        if _oc_cefr:
            _cefr_badge = (
                f'<span style="margin-left:12px;background:rgba(255,255,255,0.2);padding:2px 10px;'
                f'border-radius:8px;font-size:12px;font-weight:600;">{_oc_cefr}</span>'
            )
    st.markdown(
        f'<div style="background:linear-gradient(90deg,#1e1b4b,#312e81);color:#fff;'
        f'padding:12px 18px;border-radius:10px;margin:12px 0;">'
        f'<span style="font-size:22px;font-weight:700;">Hafta {wk["week"]}</span>'
        f'<span style="margin-left:12px;font-size:16px;">{wk["theme"]}</span>'
        f'<span style="margin-left:8px;font-size:14px;opacity:0.8;">({wk["theme_tr"]})</span>'
        f'{_cefr_badge}'
        f'</div>',
        unsafe_allow_html=True,
    )

    # ── Kazanimlar (Outcomes) ──
    if _unit_outcomes:
        _skill_icons = {"listening": "\U0001F3A7", "speaking": "\U0001F5E3\uFE0F", "reading": "\U0001F4D6", "writing": "\u270D\uFE0F"}
        _skill_colors = {"listening": "#7c3aed", "speaking": "#059669", "reading": "#2563eb", "writing": "#dc2626"}
        _skill_labels = {"listening": "Dinleme", "speaking": "Konusma", "reading": "Okuma", "writing": "Yazma"}

        _oc_functions = _unit_outcomes.get("functions", [])
        _oc_grammar = _unit_outcomes.get("grammar_targets", [])

        # Functions + Grammar bar
        _func_chips = ""
        for _fn in _oc_functions:
            _func_chips += (
                f'<span style="background:rgba(99,102,241,0.1);color:#4f46e5;padding:3px 10px;'
                f'border-radius:10px;font-size:12px;display:inline-block;margin:2px;">{_fn}</span>'
            )
        _gram_chips = ""
        for _gm in _oc_grammar:
            _gram_chips += (
                f'<span style="background:rgba(234,179,8,0.15);color:#a16207;padding:3px 10px;'
                f'border-radius:10px;font-size:12px;display:inline-block;margin:2px;">{_gm}</span>'
            )

        _func_gram_html = ""
        if _func_chips:
            _func_gram_html += f'<div style="margin-bottom:4px;"><span style="font-weight:600;font-size:12px;color:#6366f1;">Functions:</span> {_func_chips}</div>'
        if _gram_chips:
            _func_gram_html += f'<div><span style="font-weight:600;font-size:12px;color:#a16207;">Grammar:</span> {_gram_chips}</div>'

        # Skill outcomes grid
        _skill_cards = ""
        for _sk in ["listening", "speaking", "reading", "writing"]:
            _sk_outs = _unit_outcomes.get(_sk, [])
            if not _sk_outs:
                continue
            _sk_icon = _skill_icons[_sk]
            _sk_color = _skill_colors[_sk]
            _sk_label = _skill_labels[_sk]
            _sk_items = ""
