_ENG_PLACEMENT_PATH = os.path.join("data", "english", "placement_tests.json")


def _load_placement_tests() -> list:
    if os.path.exists(_ENG_PLACEMENT_PATH):
        try:
            with open(_ENG_PLACEMENT_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception as _exc:
            _logger.debug('Suppressed: %s', _exc)
            return []
    return []


def _save_placement_test(record: dict):
    data = _load_placement_tests()
    found = False
    for i, r in enumerate(data):
        if r.get("id") == record.get("id"):
            data[i] = record
            found = True
            break
    if not found:
        data.append(record)
    os.makedirs(os.path.dirname(_ENG_PLACEMENT_PATH), exist_ok=True)
    with open(_ENG_PLACEMENT_PATH, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def _render_placement_test():
    """Seviye Belirleme Testi (Placement Test) — CEFR otomatik atama."""
    from models.english_progress import (
        PLACEMENT_TEST_QUESTIONS, PlacementTestResult, calculate_placement_cefr,
    )
    import uuid as _uuid
    from datetime import datetime as _dt
    import random as _rnd

    st.markdown(
        '<div style="background:linear-gradient(135deg,#7c3aed,#2563eb);color:#fff;'
        'padding:18px 24px;border-radius:14px;margin-bottom:18px;">'
        '<div style="font-size:1.35rem;font-weight:700;">🎯 Seviye Belirleme Testi (Placement Test)</div>'
        '<div style="font-size:0.92rem;opacity:.85;margin-top:4px;">'
        'A1-B2 arasi 38 soru ile ogrencinin CEFR seviyesini otomatik belirler. '
        'Dilbilgisi, kelime bilgisi ve okuma anlama becerileri olculur.</div>'
        '</div>', unsafe_allow_html=True,
    )

    sinif = st.session_state.get("yd_sinif")
    sube = st.session_state.get("yd_sube")

    # ── Alt sekmeler: Yeni Test | Sonuclar ──
    pt_tabs = st.tabs(["  🆕 Yeni Test Uygula  ", "  📊 Test Sonuclari  "])

    # ══════════ YENİ TEST UYGULA ══════════
    with pt_tabs[0]:
        st.markdown("##### Ogrenci Bilgileri")
        c1, c2 = st.columns(2)
        with c1:
            ogrenci_adi = st.text_input("Ogrenci Adi Soyadi:", key="pt_ogrenci_adi", placeholder="Adi Soyadi giriniz...")
        with c2:
            st.markdown(f"**Sinif:** {sinif or '—'} &nbsp;|&nbsp; **Sube:** {sube or '—'}")

        if not ogrenci_adi:
            st.info("Teste baslamak icin ogrenci adi giriniz.")
            return

        # Session state ile test akisi yonet
        if "pt_started" not in st.session_state:
            st.session_state["pt_started"] = False
        if "pt_questions" not in st.session_state:
            st.session_state["pt_questions"] = []
        if "pt_answers" not in st.session_state:
            st.session_state["pt_answers"] = {}
        if "pt_submitted" not in st.session_state:
            st.session_state["pt_submitted"] = False
        if "pt_start_time" not in st.session_state:
            st.session_state["pt_start_time"] = None

        # Teste basla butonu
        if not st.session_state["pt_started"]:
            st.markdown(
                '<div style="background:#f0fdf4;border:1px solid #86efac;border-radius:10px;'
                'padding:16px;margin:12px 0;">'
                '<div style="font-weight:700;color:#166534;margin-bottom:8px;">📋 Test Hakkinda</div>'
                '<ul style="font-size:0.9rem;color:#94A3B8;margin:0;">'
                '<li><b>38 soru</b> — 4 seviye (A1, A2, B1, B2)</li>'
                '<li>Her seviyede <b>dilbilgisi, kelime bilgisi ve okuma anlama</b> sorulari</li>'
                '<li>Soru sirasi karistirilir</li>'
                '<li>Sonucta otomatik <b>CEFR seviyesi</b> atanir</li>'
                '<li>Ogretmen sonucu inceleyip override edebilir</li>'
                '</ul></div>', unsafe_allow_html=True,
            )

            if st.button("🚀 Teste Basla", key="pt_start_btn", type="primary", use_container_width=True):
                questions = list(PLACEMENT_TEST_QUESTIONS)
                _rnd.shuffle(questions)
                st.session_state["pt_questions"] = questions
                st.session_state["pt_answers"] = {}
                st.session_state["pt_started"] = True
                st.session_state["pt_submitted"] = False
                st.session_state["pt_start_time"] = _dt.now().isoformat()
                st.rerun()
            return

        # ── Test devam ediyor ──
        questions = st.session_state["pt_questions"]

        if not st.session_state["pt_submitted"]:
            # Seviye bazli gruplama ile sorulari goster
            level_colors = {"A1": "#22c55e", "A2": "#3b82f6", "B1": "#f59e0b", "B2": "#ef4444"}
            level_names = {"A1": "A1 — Baslangic", "A2": "A2 — Temel Iletisim", "B1": "B1 — Bagimsiz Kullanici", "B2": "B2 — Ust Orta"}
            skill_icons = {"grammar": "📝", "vocabulary": "📚", "reading": "📖"}

            # Ilerleme goster
            answered = len(st.session_state["pt_answers"])
            total = len(questions)
            progress = answered / total if total > 0 else 0
            st.progress(progress, text=f"Ilerleme: {answered}/{total} soru cevaplanmis")

            for idx, q in enumerate(questions):
                q_level = q["level"]
                q_skill = q["skill"]
                color = level_colors.get(q_level, "#6b7280")
                skill_icon = skill_icons.get(q_skill, "")

                st.markdown(
                    f'<div style="background:rgba(255,255,255,.03);border-left:4px solid {color};'
                    f'padding:8px 14px;border-radius:0 8px 8px 0;margin:8px 0 4px 0;">'
                    f'<span style="font-size:0.75rem;background:{color};color:#fff;padding:2px 8px;'
                    f'border-radius:4px;margin-right:8px;">{q_level}</span>'
                    f'<span style="font-size:0.8rem;color:#9ca3af;">{skill_icon} {q_skill.title()}</span>'
                    f'<div style="font-weight:600;margin-top:6px;font-size:0.95rem;">'
                    f'Soru {idx + 1}: {q["question"]}</div>'
                    f'</div>', unsafe_allow_html=True,
                )

                options = q["options"]
                selected = st.radio(
                    f"Cevaplayin:",
                    options=range(len(options)),
                    format_func=lambda x, opts=options: f"{chr(65 + x)}) {opts[x]}",
                    key=f"pt_q_{q['id']}",
                    horizontal=True,
                    index=st.session_state["pt_answers"].get(q["id"]),
                    label_visibility="collapsed",
                )
                if selected is not None:
                    st.session_state["pt_answers"][q["id"]] = selected

            # Gonder butonu
            st.markdown("---")
            unanswered = total - answered
            if unanswered > 0:
                st.warning(f"{unanswered} soru henuz cevaplanmamis. Tum sorulari cevaplamak tavsiye edilir.")

            if st.button("✅ Testi Tamamla ve Sonuclari Gor", key="pt_submit_btn", type="primary", use_container_width=True):
                st.session_state["pt_submitted"] = True
                st.rerun()
            return

        # ══════════ SONUC HESAPLAMA ══════════
        answers = st.session_state["pt_answers"]
        questions = st.session_state["pt_questions"]

        # Skorlama
        level_stats = {}  # {level: {correct: N, total: N}}
        skill_stats = {}  # {skill: {correct: N, total: N}}
        answer_details = []

        for q in questions:
            q_id = q["id"]
            level = q["level"]
            skill = q["skill"]
            correct_idx = q["answer"]
            selected_idx = answers.get(q_id)

            is_correct = selected_idx == correct_idx

            if level not in level_stats:
                level_stats[level] = {"correct": 0, "total": 0}
            level_stats[level]["total"] += 1
            if is_correct:
                level_stats[level]["correct"] += 1

            if skill not in skill_stats:
                skill_stats[skill] = {"correct": 0, "total": 0}
            skill_stats[skill]["total"] += 1
            if is_correct:
                skill_stats[skill]["correct"] += 1

            answer_details.append({
                "q_id": q_id,
                "level": level,
                "skill": skill,
                "selected": selected_idx,
                "correct": correct_idx,
                "is_correct": is_correct,
            })

        # Yuzde hesapla
        score_by_level = {}
        for lvl, stats in level_stats.items():
            score_by_level[lvl] = round((stats["correct"] / stats["total"]) * 100, 1) if stats["total"] > 0 else 0

        score_by_skill = {}
        for sk, stats in skill_stats.items():
            score_by_skill[sk] = round((stats["correct"] / stats["total"]) * 100, 1) if stats["total"] > 0 else 0

        total_correct = sum(1 for a in answer_details if a["is_correct"])
        total_questions = len(answer_details)
        total_score = round((total_correct / total_questions) * 100, 1) if total_questions > 0 else 0

        # CEFR hesapla
        assigned_cefr = calculate_placement_cefr(score_by_level)

        # Sure hesapla
        duration = 0
        if st.session_state.get("pt_start_time"):
            try:
                start = _dt.fromisoformat(st.session_state["pt_start_time"])
                duration = int((_dt.now() - start).total_seconds())
            except Exception as _exc:
                _logger.debug('Suppressed: %s', _exc)

        # ── Sonuc Karti ──
        cefr_colors = {"A1": "#22c55e", "A2": "#3b82f6", "B1": "#f59e0b", "B2": "#ef4444"}
        cefr_color = cefr_colors.get(assigned_cefr, "#6b7280")

        st.markdown(
            f'<div style="background:linear-gradient(135deg,{cefr_color}22,{cefr_color}11);'
            f'border:2px solid {cefr_color};border-radius:16px;padding:24px;margin:16px 0;text-align:center;">'
            f'<div style="font-size:0.9rem;color:#6b7280;">Atanan CEFR Seviyesi</div>'
            f'<div style="font-size:3rem;font-weight:800;color:{cefr_color};margin:8px 0;">{assigned_cefr}</div>'
            f'<div style="font-size:1.1rem;font-weight:600;">{ogrenci_adi}</div>'
            f'<div style="font-size:0.85rem;color:#9ca3af;margin-top:4px;">'
            f'Toplam: {total_correct}/{total_questions} dogru ({total_score}%) — '
            f'Sure: {duration // 60} dk {duration % 60} sn</div>'
            f'</div>', unsafe_allow_html=True,
        )

        # Seviye bazli detay
        st.markdown("##### Seviye Bazli Sonuclar")
        lvl_order = ["A1", "A2", "B1", "B2"]
        cols = st.columns(4)
        for i, lvl in enumerate(lvl_order):
            with cols[i]:
                stats = level_stats.get(lvl, {"correct": 0, "total": 0})
                score = score_by_level.get(lvl, 0)
                color = cefr_colors.get(lvl, "#6b7280")
                badge = "✅" if score >= 60 else "❌"
                st.markdown(
                    f'<div style="background:{color}15;border:1px solid {color}44;border-radius:10px;'
                    f'padding:12px;text-align:center;">'
                    f'<div style="font-size:1.4rem;font-weight:700;color:{color};">{lvl}</div>'
                    f'<div style="font-size:1.2rem;font-weight:600;">{score}%</div>'
                    f'<div style="font-size:0.8rem;color:#6b7280;">{stats["correct"]}/{stats["total"]} dogru</div>'
                    f'<div style="font-size:1.2rem;margin-top:4px;">{badge}</div>'
                    f'</div>', unsafe_allow_html=True,
                )

        # Beceri bazli detay
        st.markdown("##### Beceri Bazli Sonuclar")
        skill_labels = {"grammar": "📝 Dilbilgisi", "vocabulary": "📚 Kelime", "reading": "📖 Okuma"}
        sk_cols = st.columns(3)
        for i, (sk, label) in enumerate(skill_labels.items()):
            with sk_cols[i]:
                stats = skill_stats.get(sk, {"correct": 0, "total": 0})
                score = score_by_skill.get(sk, 0)
                bar_color = "#22c55e" if score >= 70 else ("#f59e0b" if score >= 50 else "#ef4444")
                st.markdown(
                    f'<div style="background:#111827;border:1px solid #e2e8f0;border-radius:10px;'
                    f'padding:12px;text-align:center;">'
                    f'<div style="font-size:0.95rem;font-weight:600;">{label}</div>'
                    f'<div style="font-size:1.3rem;font-weight:700;color:{bar_color};">{score}%</div>'
                    f'<div style="font-size:0.8rem;color:#6b7280;">{stats["correct"]}/{stats["total"]}</div>'
                    f'</div>', unsafe_allow_html=True,
                )

        # Ogretmen override
        st.markdown("---")
        st.markdown("##### Ogretmen Degerlendirmesi")
        cefr_options = ["A1", "A2", "B1", "B2"]
        default_idx = cefr_options.index(assigned_cefr) if assigned_cefr in cefr_options else 0

        c1, c2 = st.columns(2)
        with c1:
            override = st.selectbox(
                "CEFR Seviye (Override):",
                cefr_options,
                index=default_idx,
                key="pt_override_cefr",
                help="Otomatik atanan seviyeyi degistirmek isterseniz secin.",
            )
        with c2:
            ogretmen_notu = st.text_input("Ogretmen Notu:", key="pt_ogretmen_notu", placeholder="Opsiyonel not...")

        final_cefr = override if override != assigned_cefr else assigned_cefr

        # Kaydet
        if st.button("💾 Sonucu Kaydet", key="pt_save_btn", type="primary", use_container_width=True):
            record = PlacementTestResult(
                student_name=ogrenci_adi,
                sinif=sinif or 0,
                sube=sube or "",
                answers=answer_details,
                score_by_level=score_by_level,
                score_by_skill=score_by_skill,
                total_correct=total_correct,
                total_questions=total_questions,
                total_score=total_score,
                assigned_cefr=assigned_cefr,
                teacher_override_cefr=override if override != assigned_cefr else "",
                final_cefr=final_cefr,
                duration_seconds=duration,
            )
            _save_placement_test(record.to_dict())
            st.success(f"Sonuc kaydedildi! {ogrenci_adi} → CEFR: **{final_cefr}**")
            st.balloons()
            # Reset
            st.session_state["pt_started"] = False
            st.session_state["pt_submitted"] = False
            st.session_state["pt_questions"] = []
            st.session_state["pt_answers"] = {}

        # Yeni test baslat
        if st.button("🔄 Yeni Test Baslat", key="pt_new_test_btn"):
            st.session_state["pt_started"] = False
            st.session_state["pt_submitted"] = False
            st.session_state["pt_questions"] = []
            st.session_state["pt_answers"] = {}
            st.rerun()

    # ══════════ TEST SONUCLARI ══════════
    with pt_tabs[1]:
        st.markdown("##### 📊 Gecmis Placement Test Sonuclari")

        all_tests = _load_placement_tests()

        # Filtrele
        if sinif:
            filtered_tests = [t for t in all_tests if t.get("sinif") == sinif]
            if sube:
                filtered_tests = [t for t in filtered_tests if t.get("sube") == sube]
        else:
            filtered_tests = all_tests

        if not filtered_tests:
            st.info("Henuz kayitli placement test sonucu bulunmuyor.")
        else:
            filtered_tests.sort(key=lambda x: x.get("created_at", ""), reverse=True)

            # Ozet tablo
            import pandas as _pd
            rows = []
            for t in filtered_tests:
                rows.append({
                    "Tarih": t.get("created_at", "")[:16],
                    "Ogrenci": t.get("student_name", ""),
                    "Sinif": t.get("sinif", ""),
                    "Sube": t.get("sube", ""),
                    "Skor": f'{t.get("total_score", 0)}%',
                    "A1": f'{t.get("score_by_level", {}).get("A1", 0)}%',
                    "A2": f'{t.get("score_by_level", {}).get("A2", 0)}%',
                    "B1": f'{t.get("score_by_level", {}).get("B1", 0)}%',
                    "B2": f'{t.get("score_by_level", {}).get("B2", 0)}%',
                    "Atanan CEFR": t.get("assigned_cefr", ""),
                    "Final CEFR": t.get("final_cefr", ""),
                })
            df = _pd.DataFrame(rows)
            st.dataframe(df, use_container_width=True, hide_index=True)

            # Sinif dagilimi grafigi
            st.markdown("##### Sinif CEFR Dagilimi")
            cefr_counts = {}
            for t in filtered_tests:
                fc = t.get("final_cefr", t.get("assigned_cefr", "A1"))
                cefr_counts[fc] = cefr_counts.get(fc, 0) + 1

            if cefr_counts:
                chart_data = _pd.DataFrame({
                    "CEFR": list(cefr_counts.keys()),
                    "Ogrenci Sayisi": list(cefr_counts.values()),
                })
                st.bar_chart(chart_data.set_index("CEFR"))

            # Detay expander
            for idx, t in enumerate(filtered_tests):
                with st.expander(f"📋 {t.get('student_name', '')} — {t.get('final_cefr', '')} ({t.get('created_at', '')[:10]})"):
                    c1, c2, c3, c4 = st.columns(4)
                    with c1:
                        st.metric("Toplam Skor", f"{t.get('total_score', 0)}%")
                    with c2:
                        st.metric("Dogru/Toplam", f"{t.get('total_correct', 0)}/{t.get('total_questions', 0)}")
                    with c3:
                        st.metric("Atanan CEFR", t.get("assigned_cefr", ""))
                    with c4:
                        dur = t.get("duration_seconds", 0)
                        st.metric("Sure", f"{dur // 60} dk {dur % 60} sn")

                    # Seviye skorlari
                    sl = t.get("score_by_level", {})
                    sk = t.get("score_by_skill", {})
                    st.markdown(f"**Seviye:** A1: {sl.get('A1', 0)}% | A2: {sl.get('A2', 0)}% | B1: {sl.get('B1', 0)}% | B2: {sl.get('B2', 0)}%")
                    st.markdown(f"**Beceri:** Grammar: {sk.get('grammar', 0)}% | Vocabulary: {sk.get('vocabulary', 0)}% | Reading: {sk.get('reading', 0)}%")

                    override = t.get("teacher_override_cefr", "")
                    if override:
                        st.markdown(f"**Ogretmen Override:** {override}")


_ENG_ASSESSMENT_PATH = os.path.join("data", "english", "assessments.json")


def _load_eng_assessments() -> list:
    """Tum degerlendirme kayitlarini yukle."""
    if os.path.exists(_ENG_ASSESSMENT_PATH):
        try:
            with open(_ENG_ASSESSMENT_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception as _exc:
            _logger.debug('Suppressed: %s', _exc)
            return []
    return []


def _save_eng_assessment(record: dict):
    """Degerlendirme kaydini upsert (id bazli) olarak kaydet."""
    data = _load_eng_assessments()
    found = False
    for i, r in enumerate(data):
        if r.get("id") == record.get("id"):
            data[i] = record
            found = True
            break
    if not found:
        data.append(record)
    os.makedirs(os.path.dirname(_ENG_ASSESSMENT_PATH), exist_ok=True)
    with open(_ENG_ASSESSMENT_PATH, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


_ENG_EK_GONDERILER_PATH = os.path.join("data", "english", "ek_gonderiler.json")


def _load_eng_ek_gonderiler() -> list:
    """Tum ek gonderi kayitlarini yukle."""
    if os.path.exists(_ENG_EK_GONDERILER_PATH):
        try:
            with open(_ENG_EK_GONDERILER_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception as _exc:
            _logger.debug('Suppressed: %s', _exc)
            return []
    return []


def _save_eng_ek_gonderi(record: dict):
    """Ek gonderi kaydini ekle."""
    data = _load_eng_ek_gonderiler()
    data.append(record)
    os.makedirs(os.path.dirname(_ENG_EK_GONDERILER_PATH), exist_ok=True)
    with open(_ENG_EK_GONDERILER_PATH, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def _calc_assessment_scope(level, week_start, week_end) -> dict:
    """Secilen hafta araligindaki kapsam bilgisini hesapla."""
    curriculum = _CURRICULUM.get(level, [])
    themes, all_vocab, skills_set = [], set(), set()
    for w in curriculum:
        wn = w.get("week", 0)
        if week_start <= wn <= week_end:
            themes.append(w.get("theme_tr", w.get("theme", "")))
            all_vocab.update(w.get("vocab", []))
            for sk, sv in w.get("skills", {}).items():
                if sv and sv != "—":
                    skills_set.add(sk)
    return {
        "themes": themes,
        "vocab_count": len(all_vocab),
        "skills": skills_set,
        "week_count": week_end - week_start + 1,
        "cefr": _CURRICULUM_CEFR.get(level, ""),
    }


def _save_sinav_pdf(level, week_start, week_end):
    """Sinav PDF uret, kaydet, path don."""
    try:
        pdf_bytes = _premium_activity_pdf(level, week_start, week_end)
    except Exception as _exc:
        _logger.debug('Suppressed: %s', _exc)
        return None
    if not pdf_bytes:
        return None
    sinav_dir = os.path.join("data", "english", "sinav_pdfs")
    os.makedirs(sinav_dir, exist_ok=True)
    from datetime import datetime as _dt
    tarih = _dt.now().strftime("%Y-%m-%d")
    fname = f"sinav_{level}_H{week_start}-{week_end}_{tarih}.pdf"
    fpath = os.path.join(sinav_dir, fname)
    with open(fpath, "wb") as f:
        f.write(pdf_bytes)
    return fpath


