def _render_cefr_degerlendirme():
    """CEFR bazli performans olcumu (eski sinav/degerlendirme icerigi)."""
    from datetime import datetime as _dt
    import uuid as _uuid

    # ── Global filtreden sinif/sube/level al ──
    sinif = st.session_state.get("yd_sinif")
    sube = st.session_state.get("yd_sube")
    level = _yd_sinif_to_level(sinif)
    if level is None:
        st.info("Lütfen üst filtreden bir sinif seçiniz.")
        return

    cefr_label = _CURRICULUM_CEFR.get(level, "")
    level_label = _CURRICULUM_LEVEL_LABELS.get(level, level)

    st.markdown(
        f'<div style="background:#f0f9ff;border-left:4px solid #2563eb;padding:10px 16px;'
        f'border-radius:8px;margin-bottom:12px;">'
        f'<b>{level_label}</b> &nbsp;|&nbsp; CEFR: <b>{cefr_label}</b>'
        f'{" &nbsp;|&nbsp; Şube: <b>" + str(sube) + "</b>" if sube else ""}'
        f'</div>', unsafe_allow_html=True,
    )

    # ── Değerlendirme Türü ──
    st.markdown("##### Degerlendirme Turu")
    tur_options = [
        "Sene Sonu CEFR Testi (H1-32)",
        "Haftalik",
        "Aylik",
        "Manuel (hafta araligi)",
    ]
    tur = st.radio(
        "Tur seciniz:",
        tur_options,
        index=0,
        key="sinav_tur_radio",
        horizontal=True,
        label_visibility="collapsed",
    )

    # ── Tür'e göre hafta aralığı belirle ──
    week_start, week_end = 1, 32
    tur_key = "sene_sonu"

    if tur == tur_options[0]:
        # Sene Sonu — sabit
        week_start, week_end = 1, 32
        tur_key = "sene_sonu"
        st.caption("📌 Sene sonu degerlendirmesi: Hafta 1–32 sabit (32 haftalik performans)")

    elif tur == tur_options[1]:
        # Haftalık
        tur_key = "haftalik"
        curriculum = _CURRICULUM.get(level, [])
        max_week = max((w.get("week", 1) for w in curriculum), default=36)
        sel_week = st.selectbox(
            "Hafta seciniz:",
            list(range(1, max_week + 1)),
            format_func=lambda w: f"Hafta {w}",
            key="sinav_hafta_sel",
        )
        week_start = sel_week
        week_end = sel_week

    elif tur == tur_options[2]:
        # Aylık
        tur_key = "aylik"
        ay_list = list(_MONTH_WEEK_MAP.keys())
        sel_ay = st.selectbox("Ay seciniz:", ay_list, key="sinav_ay_sel")
        ws, we = _MONTH_WEEK_MAP[sel_ay]
        week_start, week_end = ws, we
        st.caption(f"📅 {sel_ay}: Hafta {ws}–{we}")

    else:
        # Manuel
        tur_key = "manuel"
        curriculum = _CURRICULUM.get(level, [])
        max_week = max((w.get("week", 1) for w in curriculum), default=36)
        ws, we = st.slider(
            "Hafta araligi seciniz:",
            min_value=1, max_value=max_week,
            value=(1, min(8, max_week)),
            key="sinav_hafta_slider",
        )
        week_start, week_end = ws, we

    # ── Kapsam Bilgisi ──
    scope = _calc_assessment_scope(level, week_start, week_end)
    skills_labels = {
        "listening": "🎧 Listening",
        "speaking": "🗣️ Speaking",
        "pre_reading": "📖 Reading",
        "reading": "📖 Reading",
        "pre_writing": "✍️ Writing",
        "writing": "✍️ Writing",
    }
    active_skills = []
    for sk in scope["skills"]:
        lbl = skills_labels.get(sk, sk)
        if lbl not in active_skills:
            active_skills.append(lbl)

    themes_display = ", ".join(scope["themes"][:12])
    if len(scope["themes"]) > 12:
        themes_display += f" ... (+{len(scope['themes']) - 12} tema daha)"

    st.markdown(
        f'<div style="background:linear-gradient(135deg,#eff6ff,#dbeafe);border:1px solid #93c5fd;'
        f'padding:14px 18px;border-radius:10px;margin:12px 0;">'
        f'<div style="font-weight:700;margin-bottom:6px;">📋 Kapsam Bilgisi</div>'
        f'<table style="width:100%;font-size:0.9rem;">'
        f'<tr><td style="width:140px;color:#64748b;">CEFR Seviye</td><td><b>{scope["cefr"]}</b></td></tr>'
        f'<tr><td style="color:#64748b;">Hafta Araligi</td><td><b>H{week_start}–H{week_end}</b> ({scope["week_count"]} hafta)</td></tr>'
        f'<tr><td style="color:#64748b;">Tema Sayisi</td><td><b>{len(scope["themes"])}</b></td></tr>'
        f'<tr><td style="color:#64748b;">Kelime Sayisi</td><td><b>~{scope["vocab_count"]}</b></td></tr>'
        f'<tr><td style="color:#64748b;">Beceriler</td><td>{" &nbsp;|&nbsp; ".join(active_skills) if active_skills else "—"}</td></tr>'
        f'<tr><td style="color:#64748b;">Temalar</td><td style="font-size:0.82rem;">{themes_display}</td></tr>'
        f'</table></div>', unsafe_allow_html=True,
    )

    # ── Sınav PDF İndir ──
    st.markdown("---")
    st.markdown("##### 📥 Sinav PDF")
    st.caption("Secilen hafta araligindaki egzersizlerden olusan sinav PDF'i olusturur.")

    col_pdf1, col_pdf2 = st.columns([1, 2])
    with col_pdf1:
        if st.button("📥 Sinav PDF Olustur", key="sinav_pdf_btn", use_container_width=True):
            with st.spinner("PDF olusturuluyor..."):
                pdf_path = _save_sinav_pdf(level, week_start, week_end)
                if pdf_path:
                    st.session_state["_sinav_pdf_path"] = pdf_path
                    st.session_state["_sinav_pdf_bytes"] = None
                    try:
                        with open(pdf_path, "rb") as pf:
                            st.session_state["_sinav_pdf_bytes"] = pf.read()
                    except Exception as _exc:
                        _logger.debug('Suppressed: %s', _exc)
                    st.success("PDF olusturuldu!")
                else:
                    st.warning("PDF olusturulamadi — bu hafta araligi icin icerik bulunamadi.")

    with col_pdf2:
        pdf_b = st.session_state.get("_sinav_pdf_bytes")
        if pdf_b:
            st.download_button(
                label="⬇️ PDF Indir",
                data=pdf_b,
                file_name=f"sinav_{level}_H{week_start}-{week_end}.pdf",
                mime="application/pdf",
                key="sinav_pdf_dl",
                use_container_width=True,
            )

    # ── CEFR Sonuç Girişi ──
    st.markdown("---")
    st.markdown("##### ✏️ CEFR Sonuc Girisi")
    st.caption("Ogrenci performansini CEFR kategorilerine gore 1-5 arasi puanlayin.")

    cefr_categories = [
        ("listening", "🎧 Listening"),
        ("speaking", "🗣️ Speaking"),
        ("reading", "📖 Reading"),
        ("writing", "✍️ Writing"),
        ("use_of_english", "📝 Use of English"),
    ]

    results = {}
    for cat_key, cat_label in cefr_categories:
        c1, c2 = st.columns([1, 2])
        with c1:
            puan = st.slider(
                f"{cat_label}",
                min_value=0, max_value=5, value=0,
                key=f"sinav_puan_{cat_key}",
                help="0 = Degerlendirilmedi, 1 = Baslangic, 5 = Mükemmel",
            )
        with c2:
            aciklama = st.text_input(
                "Not:",
                key=f"sinav_not_{cat_key}",
                placeholder=f"{cat_label} hakkinda kisa not...",
                label_visibility="collapsed",
            )
        results[cat_key] = {"puan": puan, "aciklama": aciklama}

    ogretmen_notu = st.text_area(
        "Ogretmen Genel Notu:",
        key="sinav_ogretmen_notu",
        placeholder="Genel degerlendirme notu (opsiyonel)...",
        height=80,
    )

    # ── Kaydet Butonu ──
    if st.button("💾 Degerlendirme Kaydet", key="sinav_kaydet_btn", use_container_width=True, type="primary"):
        # En az 1 kategori puanlanmis mi kontrol et
        any_score = any(r["puan"] > 0 for r in results.values())
        if not any_score:
            st.warning("Lütfen en az bir CEFR kategorisinde puan giriniz.")
        else:
            record = {
                "id": f"asmt_{_uuid.uuid4().hex[:8]}",
                "type": tur_key,
                "level": level,
                "sinif": sinif,
                "sube": sube or "",
                "cefr": cefr_label,
                "week_start": week_start,
                "week_end": week_end,
                "themes_covered": scope["themes"],
                "skills_covered": list(scope["skills"]),
                "pdf_path": st.session_state.get("_sinav_pdf_path", ""),
                "results": results,
                "ogretmen_notu": ogretmen_notu,
                "created_at": _dt.now().strftime("%Y-%m-%d %H:%M"),
            }
            _save_eng_assessment(record)
            st.success("Degerlendirme basariyla kaydedildi!")
            st.balloons()

    # ── Geçmiş Değerlendirmeler ──
    st.markdown("---")
    st.markdown("##### 📜 Gecmis Degerlendirmeler")

    all_assessments = _load_eng_assessments()
    # Filtrele: sinif + sube + level
    filtered = [
        a for a in all_assessments
        if a.get("level") == level
        and (not sube or a.get("sube") == sube)
        and a.get("sinif") == sinif
    ]

    if not filtered:
        st.info("Henuz kayitli degerlendirme bulunmamaktadir.")
    else:
        # En yeniden eskiye sirala
        filtered.sort(key=lambda x: x.get("created_at", ""), reverse=True)

        tur_labels = {
            "sene_sonu": "Sene Sonu",
            "haftalik": "Haftalik",
            "aylik": "Aylik",
            "manuel": "Manuel",
        }

        rows = []
        for a in filtered:
            r = a.get("results", {})
            rows.append({
                "Tarih": a.get("created_at", "—"),
                "Tur": tur_labels.get(a.get("type", ""), a.get("type", "")),
                "CEFR": a.get("cefr", ""),
                "Hafta": f"H{a.get('week_start', '')}-{a.get('week_end', '')}",
                "L": r.get("listening", {}).get("puan", 0),
                "S": r.get("speaking", {}).get("puan", 0),
                "R": r.get("reading", {}).get("puan", 0),
                "W": r.get("writing", {}).get("puan", 0),
                "UE": r.get("use_of_english", {}).get("puan", 0),
            })

        import pandas as _pd
        df = _pd.DataFrame(rows)
        st.dataframe(df, use_container_width=True, hide_index=True)

        # Detay expander
        for idx, a in enumerate(filtered):
            r = a.get("results", {})
            with st.expander(f"📋 {a.get('created_at', '')} — {tur_labels.get(a.get('type', ''), '')} (H{a.get('week_start', '')}-{a.get('week_end', '')})"):
                for cat_key, cat_label in cefr_categories:
                    cr = r.get(cat_key, {})
                    puan_val = cr.get("puan", 0)
                    stars = "⭐" * puan_val + "☆" * (5 - puan_val) if puan_val > 0 else "—"
                    note = cr.get("aciklama", "")
                    st.markdown(f"**{cat_label}:** {stars} {f'— _{note}_' if note else ''}")
                if a.get("ogretmen_notu"):
                    st.markdown(f"**Ogretmen Notu:** {a['ogretmen_notu']}")
                # PDF indirme
                pdf_p = a.get("pdf_path", "")
                if pdf_p and os.path.exists(pdf_p):
                    try:
                        with open(pdf_p, "rb") as pf:
                            st.download_button(
                                "📥 Sinav PDF",
                                data=pf.read(),
                                file_name=os.path.basename(pdf_p),
                                mime="application/pdf",
                                key=f"hist_pdf_{a.get('id', idx)}",
                            )
                    except Exception as _exc:
                        _logger.debug('Suppressed: %s', _exc)


