_ENG_SPEAKING_PATH = os.path.join("data", "english", "speaking_records.json")


def _load_speaking_records() -> list:
    if os.path.exists(_ENG_SPEAKING_PATH):
        try:
            with open(_ENG_SPEAKING_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception as _exc:
            _logger.debug('Suppressed: %s', _exc)
            return []
    return []


def _save_speaking_record(record: dict):
    data = _load_speaking_records()
    data.append(record)
    os.makedirs(os.path.dirname(_ENG_SPEAKING_PATH), exist_ok=True)
    with open(_ENG_SPEAKING_PATH, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


