def _render_speaking_assessment():
    """Konusma kayit ve rubrik bazli degerlendirme."""
    from models.english_progress import SPEAKING_RUBRIC_CRITERIA, SpeakingRecord
    from datetime import datetime as _dt

    st.markdown(
        '<div style="background:linear-gradient(135deg,#7c3aed,#a855f7);color:#fff;'
        'padding:16px 20px;border-radius:12px;margin-bottom:16px;">'
        '<div style="font-size:1.2rem;font-weight:700;">🗣️ Konusma Degerlendirme</div>'
        '<div style="font-size:0.85rem;opacity:.85;margin-top:4px;">'
        '5 kriterli rubrik: Pronunciation, Fluency, Vocabulary, Grammar, Interaction</div>'
        '</div>', unsafe_allow_html=True,
    )

    sinif = st.session_state.get("yd_sinif")
    sube = st.session_state.get("yd_sube")
    level = _yd_sinif_to_level(sinif)

    spk_tabs = st.tabs(["  🆕 Yeni Degerlendirme  ", "  📊 Gecmis Kayitlar  "])

    with spk_tabs[0]:
        st.markdown("##### Ogrenci & Gorev Bilgileri")
        c1, c2 = st.columns(2)
        with c1:
            ogrenci_adi = st.text_input("Ogrenci Adi:", key="spk_ogrenci", placeholder="Ad Soyad...")
        with c2:
            task_type = st.selectbox(
                "Gorev Turu:",
                list(_SPEAKING_TASK_TYPES.keys()),
                format_func=lambda k: _SPEAKING_TASK_TYPES[k],
                key="spk_task_type",
            )

        # CEFR seviyesine gore prompt oner
        cefr_key = "A1"
        if level:
            if "grade" in level:
                grade_num = int(level.replace("grade", "").replace("preschool", "0"))
                if grade_num <= 4:
                    cefr_key = "A1"
                elif grade_num <= 8:
                    cefr_key = "A2"
                elif grade_num <= 10:
                    cefr_key = "B1"
                else:
                    cefr_key = "B2"
            elif level == "preschool":
                cefr_key = "A1"

        prompts = _SPEAKING_PROMPTS.get(cefr_key, _SPEAKING_PROMPTS["A1"])

        c1, c2 = st.columns(2)
        with c1:
            task_title = st.text_input("Gorev Basligi:", key="spk_title", placeholder="Ornek: My Family")
        with c2:
            prompt_sel = st.selectbox("Hazir Prompt Sec (opsiyonel):", ["— Sec —"] + prompts, key="spk_prompt_sel")

        task_prompt = st.text_area(
            "Gorev Aciklamasi / Prompt:",
            value=prompt_sel if prompt_sel != "— Sec —" else "",
            key="spk_prompt",
            height=80,
            placeholder="Ogrenciye verilen gorev aciklamasi...",
        )

        duration = st.number_input("Konusma Suresi (saniye):", min_value=0, max_value=600, value=60, step=10, key="spk_duration")

        # Rubrik puanlama
        st.markdown("---")
        st.markdown("##### Rubrik Puanlama")

        rubric_scores = {}
        for crit in SPEAKING_RUBRIC_CRITERIA:
            st.markdown(f"**{crit['label']}**")
            c1, c2 = st.columns([1, 2])
            with c1:
                score = st.slider(
                    crit["label"],
                    min_value=0, max_value=crit["max"], value=0,
                    key=f"spk_rubric_{crit['key']}",
                    label_visibility="collapsed",
                )
                rubric_scores[crit["key"]] = score
            with c2:
                desc = crit["descriptors"].get(score, "Degerlendirilmedi" if score == 0 else "")
                color = "#22c55e" if score >= 4 else ("#f59e0b" if score >= 3 else ("#ef4444" if score >= 1 else "#9ca3af"))
                st.markdown(
                    f'<div style="padding:8px 12px;background:{color}15;border-left:3px solid {color};'
                    f'border-radius:0 6px 6px 0;margin-top:4px;font-size:0.85rem;">'
                    f'{score}/5 — {desc}</div>', unsafe_allow_html=True,
                )

        teacher_feedback = st.text_area("Ogretmen Geri Bildirimi:", key="spk_feedback", height=80, placeholder="Genel degerlendirme notu...")

        # Toplam skor
        total = sum(rubric_scores.values())
        max_total = sum(c["max"] for c in SPEAKING_RUBRIC_CRITERIA)
        pct = round((total / max_total) * 100, 1) if max_total > 0 else 0

        bar_color = "#22c55e" if pct >= 70 else ("#f59e0b" if pct >= 50 else "#ef4444")
        st.markdown(
            f'<div style="background:#111827;border:1px solid #e2e8f0;border-radius:10px;'
            f'padding:14px;margin:12px 0;text-align:center;">'
            f'<div style="font-size:0.85rem;color:#6b7280;">Toplam Skor</div>'
            f'<div style="font-size:2rem;font-weight:700;color:{bar_color};">{total}/{max_total} ({pct}%)</div>'
            f'</div>', unsafe_allow_html=True,
        )

        # Kaydet
        if st.button("💾 Konusma Degerlendirmesini Kaydet", key="spk_save_btn", type="primary", use_container_width=True):
            if not ogrenci_adi:
                st.warning("Ogrenci adi giriniz.")
            elif total == 0:
                st.warning("En az bir kriterde puan veriniz.")
            else:
                # CEFR speaking level belirle
                spk_cefr = "A1"
                if pct >= 80:
                    spk_cefr = "B2" if cefr_key == "B2" else ("B1" if cefr_key in ("B1", "B2") else "A2")
                elif pct >= 60:
                    spk_cefr = cefr_key
                elif pct >= 40:
                    spk_cefr = "A2" if cefr_key in ("B1", "B2") else "A1"

                record = SpeakingRecord(
                    student_name=ogrenci_adi,
                    sinif=sinif or 0,
                    sube=sube or "",
                    level=level or "",
                    task_type=task_type,
                    task_title=task_title,
                    task_prompt=task_prompt,
                    duration_seconds=duration,
                    rubric_scores=rubric_scores,
                    total_score=total,
                    max_score=max_total,
                    percentage=pct,
                    teacher_feedback=teacher_feedback,
                    cefr_speaking_level=spk_cefr,
                )
                _save_speaking_record(record.to_dict())
                st.success(f"Kaydedildi! {ogrenci_adi} — Speaking: {spk_cefr} ({pct}%)")
                st.balloons()

    with spk_tabs[1]:
        st.markdown("##### Gecmis Konusma Degerlendirmeleri")
        all_recs = _load_speaking_records()

        if sinif:
            filtered = [r for r in all_recs if r.get("sinif") == sinif]
            if sube:
                filtered = [r for r in filtered if r.get("sube") == sube]
        else:
            filtered = all_recs

        if not filtered:
            st.info("Henuz konusma degerlendirmesi bulunmuyor.")
        else:
            filtered.sort(key=lambda x: x.get("created_at", ""), reverse=True)
            import pandas as _pd
            rows = []
            for r in filtered:
                rs = r.get("rubric_scores", {})
                rows.append({
                    "Tarih": r.get("created_at", "")[:16],
                    "Ogrenci": r.get("student_name", ""),
                    "Gorev": _SPEAKING_TASK_TYPES.get(r.get("task_type", ""), r.get("task_type", "")),
                    "Pron.": rs.get("pronunciation", 0),
                    "Fluency": rs.get("fluency", 0),
                    "Vocab": rs.get("vocabulary", 0),
                    "Gram.": rs.get("grammar", 0),
                    "Inter.": rs.get("interaction", 0),
                    "Toplam": f'{r.get("percentage", 0)}%',
                    "CEFR": r.get("cefr_speaking_level", ""),
                })
            df = _pd.DataFrame(rows)
            st.dataframe(df, use_container_width=True, hide_index=True)

            # Detay
            for idx, r in enumerate(filtered):
                with st.expander(f"📋 {r.get('student_name', '')} — {r.get('created_at', '')[:10]}"):
                    st.markdown(f"**Gorev:** {r.get('task_title', '')} ({_SPEAKING_TASK_TYPES.get(r.get('task_type', ''), '')})")
                    st.markdown(f"**Prompt:** {r.get('task_prompt', '')}")
                    st.markdown(f"**Sure:** {r.get('duration_seconds', 0)} saniye")
                    st.markdown(f"**Skor:** {r.get('total_score', 0)}/{r.get('max_score', 25)} ({r.get('percentage', 0)}%)")
                    st.markdown(f"**CEFR Speaking:** {r.get('cefr_speaking_level', '')}")
                    if r.get("teacher_feedback"):
                        st.markdown(f"**Geri Bildirim:** {r['teacher_feedback']}")


