_ENG_CAMBRIDGE_PATH = os.path.join("data", "english", "cambridge_results.json")


def _load_cambridge_results() -> list:
    if os.path.exists(_ENG_CAMBRIDGE_PATH):
        try:
            with open(_ENG_CAMBRIDGE_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception as _exc:
            _logger.debug('Suppressed: %s', _exc)
            return []
    return []


def _save_cambridge_result(record: dict):
    data = _load_cambridge_results()
    data.append(record)
    os.makedirs(os.path.dirname(_ENG_CAMBRIDGE_PATH), exist_ok=True)
    with open(_ENG_CAMBRIDGE_PATH, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def _render_cambridge_prep():
    """Cambridge sinav hazirlik modulu — KET, PET, FCE."""
    from datetime import datetime as _dt
    import uuid as _uuid

    st.markdown(
        '<div style="background:linear-gradient(135deg,#dc2626,#b91c1c);color:#fff;'
        'padding:16px 20px;border-radius:12px;margin-bottom:16px;">'
        '<div style="font-size:1.2rem;font-weight:700;">🏅 Cambridge Sinav Hazirlik</div>'
        '<div style="font-size:0.85rem;opacity:.85;margin-top:4px;">'
        'KET (A2), PET (B1), FCE (B2) — Pratik sorular ve sinav formati calismalari</div>'
        '</div>', unsafe_allow_html=True,
    )

    sinif = st.session_state.get("yd_sinif")
    sube = st.session_state.get("yd_sube")
    level = _yd_sinif_to_level(sinif)

    # Seviyeye gore sinav oner
    recommended = "KET"
    if level and "grade" in level:
        gn = int(level.replace("grade", ""))
        if gn >= 11:
            recommended = "FCE"
        elif gn >= 9:
            recommended = "PET"

    # Sinav secimi
    exam_key = st.selectbox(
        "Cambridge Sinav Secimi:",
        list(_CAMBRIDGE_EXAMS.keys()),
        format_func=lambda k: f"{_CAMBRIDGE_EXAMS[k]['full_name']} (CEFR {_CAMBRIDGE_EXAMS[k]['cefr']})",
        index=list(_CAMBRIDGE_EXAMS.keys()).index(recommended),
        key="cambridge_exam_sel",
    )
    exam = _CAMBRIDGE_EXAMS[exam_key]

    st.markdown(
        f'<div style="background:#fef2f2;border:1px solid #fca5a5;border-radius:10px;'
        f'padding:12px 16px;margin-bottom:12px;">'
        f'<div style="font-weight:600;">{exam["full_name"]}</div>'
        f'<div style="font-size:0.85rem;color:#6b7280;margin-top:4px;">{exam["description"]}</div>'
        f'<div style="font-size:0.82rem;color:#9ca3af;margin-top:4px;">Bolumler: {" | ".join(exam["parts"])}</div>'
        f'</div>', unsafe_allow_html=True,
    )

    # Pratik sorulari goster
    practice = _CAMBRIDGE_PRACTICE_QUESTIONS.get(exam_key, {})
    if not practice:
        st.info(f"{exam_key} icin pratik sorular yakilmda eklenecektir.")
        return

    for part_name, sections in practice.items():
        st.markdown(f"##### {part_name}")
        for sec_idx, section in enumerate(sections):
            st.markdown(f"**{section.get('type', '').replace('_', ' ').title()}** — {section.get('instruction', '')}")

            if section.get("text"):
                st.markdown(
                    f'<div style="background:#111827;border-left:3px solid #3b82f6;padding:10px 14px;'
                    f'border-radius:0 8px 8px 0;margin:8px 0;font-size:0.9rem;font-style:italic;">'
                    f'{section["text"]}</div>', unsafe_allow_html=True,
                )

            items = section.get("items", [])
            for i, item in enumerate(items):
                if "sign" in item:
                    # Matching type
                    st.markdown(f"**{item['sign']}**")
                    sel = st.radio(
                        f"Seciniz:", item["options"],
                        key=f"cam_{exam_key}_{part_name}_{sec_idx}_{i}",
                        horizontal=True,
                        label_visibility="collapsed",
                    )
                elif "sentence" in item and "options" in item:
                    # Fill gap / multiple choice
                    st.markdown(f"_{item['sentence']}_")
                    sel = st.radio(
                        "Seciniz:", item["options"],
                        key=f"cam_{exam_key}_{part_name}_{sec_idx}_{i}",
                        horizontal=True,
                        label_visibility="collapsed",
                    )
                elif "question" in item:
                    st.markdown(f"**{item['question']}**")
                    sel = st.radio(
                        "Seciniz:", item["options"],
                        key=f"cam_{exam_key}_{part_name}_{sec_idx}_{i}",
                        horizontal=True,
                        label_visibility="collapsed",
                    )
                elif "base_word" in item:
                    st.markdown(f"_{item['sentence']}_ (Base: **{item['base_word']}**)")
                    st.text_input("Cevabiniz:", key=f"cam_{exam_key}_{part_name}_{sec_idx}_{i}", placeholder="...")

            if section.get("example"):
                with st.expander("Ornek Cevap"):
                    st.markdown(f"```\n{section['example']}\n```")

            if section.get("answers"):
                with st.expander("Cevap Anahtari"):
                    for ai, ans in enumerate(section["answers"]):
                        st.markdown(f"({ai + 1}) **{ans}**")

    # Sonuc kaydet
    st.markdown("---")
    ogrenci_adi = st.text_input("Ogrenci Adi (Kayit icin):", key="cam_student_name", placeholder="Ad Soyad...")
    cam_score = st.slider("Basari Puani (0-100):", 0, 100, 50, key="cam_score")

    if st.button("💾 Cambridge Sonuc Kaydet", key="cam_save_btn", type="primary", use_container_width=True):
        if ogrenci_adi:
            record = {
                "id": f"cam_{_uuid.uuid4().hex[:8]}",
                "student_name": ogrenci_adi,
                "sinif": sinif or 0,
                "sube": sube or "",
                "exam": exam_key,
                "exam_full": exam["full_name"],
                "cefr": exam["cefr"],
                "score": cam_score,
                "created_at": _dt.now().isoformat(),
            }
            _save_cambridge_result(record)
            st.success(f"Kaydedildi! {ogrenci_adi} — {exam['full_name']}: {cam_score}%")
        else:
            st.warning("Ogrenci adi giriniz.")

    # Gecmis sonuclar
    all_cam = _load_cambridge_results()
    if sinif:
        all_cam = [r for r in all_cam if r.get("sinif") == sinif]
        if sube:
            all_cam = [r for r in all_cam if r.get("sube") == sube]
    if all_cam:
        st.markdown("---")
        st.markdown("##### Gecmis Cambridge Sonuclari")
        import pandas as _pd
        rows = [{"Tarih": r.get("created_at", "")[:10], "Ogrenci": r.get("student_name", ""),
                 "Sinav": r.get("exam_full", ""), "Skor": f'{r.get("score", 0)}%'}
                for r in sorted(all_cam, key=lambda x: x.get("created_at", ""), reverse=True)]
        st.dataframe(_pd.DataFrame(rows), use_container_width=True, hide_index=True)


