def _render_self_assessment():
    """Ogrenci oz degerlendirme — CEFR Can-Do ifadeleri."""
    from datetime import datetime as _dt
    import uuid as _uuid

    st.markdown(
        '<div style="background:linear-gradient(135deg,#0891b2,#06b6d4);color:#fff;'
        'padding:16px 20px;border-radius:12px;margin-bottom:16px;">'
        '<div style="font-size:1.2rem;font-weight:700;">🪞 Oz Degerlendirme (Self-Assessment)</div>'
        '<div style="font-size:0.85rem;opacity:.85;margin-top:4px;">'
        'CEFR Can-Do ifadeleri ile ogrenci kendi seviyesini degerlendirir</div>'
        '</div>', unsafe_allow_html=True,
    )

    sinif = st.session_state.get("yd_sinif")
    sube = st.session_state.get("yd_sube")
    level = _yd_sinif_to_level(sinif)

    ogrenci_adi = st.text_input("Ogrenci Adi:", key="sa_ogrenci", placeholder="Ad Soyad...")

    # CEFR seviye sec
    cefr_key = "A1"
    if level and "grade" in level:
        gn = int(level.replace("grade", ""))
        if gn <= 4:
            cefr_key = "A1"
        elif gn <= 8:
            cefr_key = "A2"
        elif gn <= 10:
            cefr_key = "B1"
        else:
            cefr_key = "B2"

    cefr_sel = st.selectbox("CEFR Seviye:", ["A1", "A2", "B1", "B2"], index=["A1", "A2", "B1", "B2"].index(cefr_key), key="sa_cefr")
    can_do = _SELF_ASSESSMENT_CAN_DO.get(cefr_sel, {})

    if not can_do:
        st.info("Bu seviye icin Can-Do ifadeleri bulunmuyor.")
        return

    # Degerlendir
    skill_icons = {"listening": "🎧", "speaking": "🗣️", "reading": "📖", "writing": "✍️"}
    responses = {}

    for skill, statements in can_do.items():
        icon = skill_icons.get(skill, "")
        st.markdown(f"##### {icon} {skill.title()}")
        skill_responses = []
        for si, stmt in enumerate(statements):
            val = st.select_slider(
                stmt,
                options=["Hayir", "Biraz", "Cogunlukla", "Evet"],
                value="Biraz",
                key=f"sa_{cefr_sel}_{skill}_{si}",
            )
            skill_responses.append({"statement": stmt, "response": val})
        responses[skill] = skill_responses

    # Skor hesapla
    score_map = {"Hayir": 0, "Biraz": 1, "Cogunlukla": 2, "Evet": 3}
    skill_scores = {}
    total_score = 0
    total_max = 0

    for skill, items in responses.items():
        skill_total = sum(score_map.get(it["response"], 0) for it in items)
        skill_max = len(items) * 3
        skill_pct = round((skill_total / skill_max) * 100, 1) if skill_max > 0 else 0
        skill_scores[skill] = {"total": skill_total, "max": skill_max, "pct": skill_pct}
        total_score += skill_total
        total_max += skill_max

    overall_pct = round((total_score / total_max) * 100, 1) if total_max > 0 else 0

    # Sonuc karti
    bar_color = "#22c55e" if overall_pct >= 70 else ("#f59e0b" if overall_pct >= 50 else "#ef4444")
    st.markdown(
        f'<div style="background:#111827;border:1px solid #e2e8f0;border-radius:10px;'
        f'padding:14px;margin:12px 0;text-align:center;">'
        f'<div style="font-size:0.85rem;color:#6b7280;">Oz Degerlendirme Skoru ({cefr_sel})</div>'
        f'<div style="font-size:2rem;font-weight:700;color:{bar_color};">{overall_pct}%</div>'
        f'</div>', unsafe_allow_html=True,
    )

    # Beceri bazli
    sk_cols = st.columns(4)
    for i, (skill, data) in enumerate(skill_scores.items()):
        with sk_cols[i]:
            color = "#22c55e" if data["pct"] >= 70 else ("#f59e0b" if data["pct"] >= 50 else "#ef4444")
            st.markdown(
                f'<div style="text-align:center;padding:8px;">'
                f'<div style="font-size:0.8rem;color:#6b7280;">{skill_icons.get(skill, "")} {skill.title()}</div>'
                f'<div style="font-size:1.3rem;font-weight:700;color:{color};">{data["pct"]}%</div>'
                f'</div>', unsafe_allow_html=True,
            )

    # Kaydet
    if st.button("💾 Oz Degerlendirme Kaydet", key="sa_save_btn", type="primary", use_container_width=True):
        if not ogrenci_adi:
            st.warning("Ogrenci adi giriniz.")
        else:
            record = {
                "id": f"sa_{_uuid.uuid4().hex[:8]}",
                "student_name": ogrenci_adi,
                "sinif": sinif or 0,
                "sube": sube or "",
                "cefr_level": cefr_sel,
                "responses": responses,
                "skill_scores": skill_scores,
                "overall_pct": overall_pct,
                "created_at": _dt.now().isoformat(),
            }
            _save_self_assessment(record)
            st.success(f"Kaydedildi! {ogrenci_adi} — {cefr_sel} Oz Degerlendirme: {overall_pct}%")


