def _render_ielts_toefl_prep():
    """IELTS ve TOEFL sinav hazirlik."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#1e40af,#3b82f6);color:#fff;'
        'padding:16px 20px;border-radius:12px;margin-bottom:16px;">'
        '<div style="font-size:1.2rem;font-weight:700;">🌍 IELTS / TOEFL Hazirlik</div>'
        '<div style="font-size:0.85rem;opacity:.85;margin-top:4px;">'
        'Uluslararasi sinav hazirlik materyalleri ve pratik sorular</div>'
        '</div>', unsafe_allow_html=True,
    )

    exam_type = st.radio("Sinav Turu:", ["IELTS", "TOEFL"], horizontal=True, key="ielts_toefl_sel")

    if exam_type == "IELTS":
        sections = _IELTS_SECTIONS
        for section_name, section_data in sections.items():
            with st.expander(f"📋 {section_name} — {section_data['description']}"):
                # Tips
                st.markdown("**Ipuclari:**")
                for tip in section_data.get("tips", []):
                    st.markdown(f"- {tip}")

                # Practice
                for pi, pq in enumerate(section_data.get("practice", [])):
                    st.markdown(f"**Soru {pi + 1}:** {pq['question']}")
                    ans = st.text_input("Cevabiniz:", key=f"ielts_{section_name}_{pi}", placeholder="...")
                    if ans:
                        if ans.strip().upper() == pq["answer"].upper():
                            st.success("Dogru!")
                        else:
                            st.error(f"Yanlis. Dogru cevap: {pq['answer']}")

                # Tasks (Writing/Speaking)
                for ti, task in enumerate(section_data.get("tasks", [])):
                    st.markdown(f"**{task['name']}:** {task['prompt']}")
                    st.text_area("Cevabiniz:", key=f"ielts_task_{section_name}_{ti}", height=120)

                for pi, part in enumerate(section_data.get("parts", [])):
                    st.markdown(f"**{part['name']}:** {part['prompt']}")
    else:
        sections = _TOEFL_SECTIONS
        for section_name, section_data in sections.items():
            with st.expander(f"📋 {section_name} — {section_data['description']}"):
                st.markdown("**Ipuclari:**")
                for tip in section_data.get("tips", []):
                    st.markdown(f"- {tip}")


