def _render_ai_conversation():
    """AI konusma partneri — senaryo bazli pratik."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#7c3aed,#a855f7);color:#fff;'
        'padding:18px 24px;border-radius:14px;margin-bottom:18px;">'
        '<div style="font-size:1.35rem;font-weight:700;">🤖 AI Konusma Partneri</div>'
        '<div style="font-size:0.92rem;opacity:.85;margin-top:4px;">'
        'Farkli senaryolarda Ingilizce pratik yapin. Yanitlarinizi yazin, AI geri bildirim verir.</div>'
        '</div>', unsafe_allow_html=True,
    )

    sinif = st.session_state.get("yd_sinif")
    level = _yd_sinif_to_level(sinif)

    cefr_key = "A1-A2"
    if level and "grade" in level:
        gn = int(level.replace("grade", ""))
        if gn >= 11:
            cefr_key = "B2"
        elif gn >= 9:
            cefr_key = "B1"

    scenarios = _AI_CONVERSATION_SCENARIOS.get(cefr_key, _AI_CONVERSATION_SCENARIOS["A1-A2"])

    scenario_sel = st.selectbox(
        "Senaryo Seciniz:",
        range(len(scenarios)),
        format_func=lambda i: f"{scenarios[i]['scenario']} ({scenarios[i]['tr']}) — Rol: {scenarios[i]['role']}",
        key="ai_conv_scenario",
    )
    scn = scenarios[scenario_sel]

    st.markdown(
        f'<div style="background:#f5f3ff;border:1px solid #c4b5fd;border-radius:12px;'
        f'padding:16px;margin:12px 0;">'
        f'<div style="font-weight:700;font-size:1.1rem;">{scn["scenario"]}</div>'
        f'<div style="font-size:0.85rem;color:#6b7280;margin-top:4px;">Rolunuz: <b>{scn["role"]}</b></div>'
        f'</div>', unsafe_allow_html=True,
    )

    # Konusma akisi
    if "ai_conv_history" not in st.session_state:
        st.session_state["ai_conv_history"] = []

    # Baslangic mesajini goster
    st.markdown(
        f'<div style="background:#e0f2fe;border-radius:12px 12px 12px 4px;'
        f'padding:12px 16px;margin:8px 0;max-width:80%;">'
        f'<div style="font-size:0.75rem;color:#0284c7;font-weight:600;">AI Partner</div>'
        f'<div style="font-size:0.95rem;margin-top:4px;">{scn["starter"]}</div>'
        f'</div>', unsafe_allow_html=True,
    )

    # Gecmis mesajlari goster
    for msg in st.session_state["ai_conv_history"]:
        if msg["role"] == "user":
            st.markdown(
                f'<div style="background:#dbeafe;border-radius:12px 12px 4px 12px;'
                f'padding:12px 16px;margin:8px 0 8px auto;max-width:80%;text-align:right;">'
                f'<div style="font-size:0.75rem;color:#1d4ed8;font-weight:600;">Siz ({scn["role"]})</div>'
                f'<div style="font-size:0.95rem;margin-top:4px;">{msg["text"]}</div>'
                f'</div>', unsafe_allow_html=True,
            )
        else:
            st.markdown(
                f'<div style="background:#e0f2fe;border-radius:12px 12px 12px 4px;'
                f'padding:12px 16px;margin:8px 0;max-width:80%;">'
                f'<div style="font-size:0.75rem;color:#0284c7;font-weight:600;">AI Partner</div>'
                f'<div style="font-size:0.95rem;margin-top:4px;">{msg["text"]}</div>'
                f'</div>', unsafe_allow_html=True,
            )

    # Kullanici yaniti
    user_input = st.text_input("Yanitiniz (Ingilizce):", key="ai_conv_input", placeholder="Type your response in English...")

    c1, c2 = st.columns(2)
    with c1:
        if st.button("📤 Gonder", key="ai_conv_send", type="primary", use_container_width=True):
            if user_input.strip():
                st.session_state["ai_conv_history"].append({"role": "user", "text": user_input})

                # Basit kural bazli cevap (AI olmadan)
                response = _generate_simple_ai_response(scn, user_input, cefr_key)
                st.session_state["ai_conv_history"].append({"role": "ai", "text": response})
                st.rerun()
    with c2:
        if st.button("🔄 Yeni Konusma", key="ai_conv_reset", use_container_width=True):
            st.session_state["ai_conv_history"] = []
            st.rerun()

    # Ipucu
    with st.expander("💡 Yardim & Ipuclari"):
        st.markdown(f"**Senaryo:** {scn['scenario']} — {scn['tr']}")
        st.markdown(f"**Rolunuz:** {scn['role']}")
        st.markdown("**Ornek yanitlar:**")
        if cefr_key == "A1-A2":
            st.markdown("- Yes, please. / No, thank you.")
            st.markdown("- I would like... / Can I have...?")
            st.markdown("- My name is... / I am from...")
        elif cefr_key == "B1":
            st.markdown("- I think that... / In my opinion...")
            st.markdown("- Could you tell me more about...?")
            st.markdown("- I'd like to know...")
        else:
            st.markdown("- From my perspective... / I strongly believe...")
            st.markdown("- On the other hand... / Nevertheless...")
            st.markdown("- To elaborate on that point...")


def _generate_simple_ai_response(scenario: dict, user_input: str, cefr_level: str) -> str:
    """Basit kural bazli AI cevap uretici (OpenAI gerekmiyor)."""
    # Keyword bazli cevap
    inp = user_input.lower()
    scn = scenario["scenario"].lower()

    if "restaurant" in scn:
        if any(w in inp for w in ["order", "like", "want", "have"]):
            return "Great choice! Would you like anything to drink with that?"
        if any(w in inp for w in ["menu", "see"]):
            return "Of course! Here's our menu. We have some great specials today."
        if any(w in inp for w in ["bill", "check", "pay"]):
            return "Sure! Your total is $25.50. Cash or card?"
        return "I see! And would you like to try our special of the day?"

    if "shop" in scn:
        if any(w in inp for w in ["looking", "need", "want", "buy"]):
            return "We have a great selection! What size are you looking for?"
        if any(w in inp for w in ["how much", "price", "cost"]):
            return "This one is $29.99. We also have it in other colors."
        return "Is there anything else I can help you with?"

    if "friend" in scn or "meeting" in scn:
        if any(w in inp for w in ["name", "am", "i'm"]):
            return "Nice to meet you! Where are you from? What do you like to do in your free time?"
        if any(w in inp for w in ["hobby", "like", "enjoy"]):
            return "That sounds interesting! I enjoy reading and playing sports. Have you tried any sports?"
        return "Tell me more! What's your favorite thing about school?"

    if "interview" in scn:
        if any(w in inp for w in ["experience", "work", "job"]):
            return "That's impressive! Can you tell me about a challenge you faced at work and how you handled it?"
        if any(w in inp for w in ["skill", "strength"]):
            return "Those are valuable skills. Where do you see yourself in five years?"
        return "Thank you for sharing. Do you have any questions about the position?"

    if "doctor" in scn:
        if any(w in inp for w in ["pain", "hurt", "ache", "feel"]):
            return "I understand. How long have you been feeling this way? Have you taken any medication?"
        return "Let me check. Please describe your symptoms in more detail."

    # Genel cevap
    general_responses = [
        "That's a great point! Can you tell me more about that?",
        "Interesting! What else would you like to discuss?",
        "I understand. How does that make you feel?",
        "Good answer! Let's continue. What do you think about...?",
    ]
    return random.choice(general_responses)


