# Kademe -> level kodlari eslesmesi
_EBA_GAME_LEVELS = {
    "preschool": ["P", "A"],
    "primary": ["P", "A"],
    "secondary": ["P", "S", "A"],
    "high": ["S", "H", "A"],
}


_eba_game_counter = [0]

def _render_eba_games(level="primary"):
    """EBA Interaktif Oyunlar bolumu — kademe bazli filtreleme, kategori filtresi + arama + sayfalama."""
    _eba_game_counter[0] += 1
    _kp = f"ebag{_eba_game_counter[0]}"
    _base = _EBA_BASE_URL
    # Kademe bazli filtreleme
    _allowed = _EBA_GAME_LEVELS.get(level, ["P", "S", "H", "A"])
    _level_games = [g for g in _EBA_GAMES if g["lv"] in _allowed]
    _level_labels = {"preschool": "Okul Oncesi", "primary": "Ilkokul (1-4)", "secondary": "Ortaokul (5-8)", "high": "Lise (9-12)"}
    _lbl = _level_labels.get(level, level)
    st.markdown("---")
    st.markdown(
        f'<div style="background:linear-gradient(135deg,#7c3aed,#a855f7);color:#fff;'
        f'padding:16px 22px;border-radius:14px;margin-bottom:16px;">'
        f'<div style="font-size:1.2rem;font-weight:700;">🎮 EBA Interaktif Oyunlar ({len(_level_games)}) — {_lbl}</div>'
        f'<div style="font-size:0.88rem;opacity:.85;margin-top:4px;">'
        f'EBA resmi Ingilizce ogrenme oyunlari — Spelling, Vocabulary, Grammar, Songs ve daha fazlasi</div>'
        f'</div>', unsafe_allow_html=True,
    )
    # Kategori filtresi + arama
    _cats = sorted(set(g["cat"] for g in _level_games))
    fc1, fc2 = st.columns([1, 2])
    with fc1:
        _cat_sel = st.selectbox("Kategori", ["Tumu"] + _cats, key=f"{_kp}_cat")
    with fc2:
        _search = st.text_input("Oyun Ara", key=f"{_kp}_search", placeholder="Ornek: bingo, hello, animals...")
    _filtered = _level_games
    if _cat_sel != "Tumu":
        _filtered = [g for g in _filtered if g["cat"] == _cat_sel]
    if _search:
        _sq = _search.lower()
        _filtered = [g for g in _filtered if _sq in g["title"].lower() or _sq in g["cat"].lower()]
    # Sayfalama
    _per_page = 12
    _total_pages = max(1, (len(_filtered) + _per_page - 1) // _per_page)
    _page = st.number_input("Sayfa", 1, _total_pages, 1, key=f"{_kp}_page")
    _start = (_page - 1) * _per_page
    _page_items = _filtered[_start:_start + _per_page]
    st.caption(f"{len(_filtered)} oyun bulundu — Sayfa {_page}/{_total_pages}")
    _cat_colors = {
        "Spelling": ("#7c3aed", "#a855f7"), "Vocabulary": ("#0891b2", "#06b6d4"),
        "Numbers": ("#ea580c", "#f97316"), "Grammar": ("#dc2626", "#ef4444"),
        "Song": ("#db2777", "#ec4899"), "Speaking": ("#0d9488", "#14b8a6"),
        "Family": ("#9333ea", "#a855f7"), "Greetings": ("#2563eb", "#3b82f6"),
        "Letters": ("#7c3aed", "#a78bfa"), "Directions": ("#059669", "#10b981"),
        "Time": ("#d97706", "#f59e0b"), "Health": ("#16a34a", "#22c55e"),
        "Food": ("#ea580c", "#fb923c"), "Animals": ("#65a30d", "#84cc16"),
        "Weather": ("#0284c7", "#38bdf8"), "Daily Routine": ("#8b5cf6", "#a78bfa"),
        "Culture": ("#be185d", "#ec4899"), "Puzzle": ("#6d28d9", "#8b5cf6"),
        "Colors": ("#e11d48", "#f43f5e"),
    }
    cols_per_row = 3
    for ri in range(0, len(_page_items), cols_per_row):
        cols = st.columns(cols_per_row)
        for ci, col in enumerate(cols):
            gi = ri + ci
            if gi >= len(_page_items):
                break
            g = _page_items[gi]
            _c1, _c2 = _cat_colors.get(g["cat"], ("#6366f1", "#818cf8"))
            with col:
                st.markdown(
                    f'<div style="background:linear-gradient(135deg,#faf5ff,#f3e8ff);'
                    f'border:2px solid {_c1};border-radius:14px;padding:14px;'
                    f'text-align:center;margin-bottom:10px;min-height:200px;">'
                    f'<img src="{_base}{g["img"]}" style="width:100%;max-height:120px;'
                    f'object-fit:cover;border-radius:10px;margin-bottom:8px;"'
                    f' onerror="this.style.display=\'none\'">'
                    f'<div style="font-size:0.92rem;font-weight:700;color:#1e1b4b;'
                    f'margin-bottom:4px;line-height:1.3;">{g["title"]}</div>'
                    f'<div style="display:inline-block;background:linear-gradient(135deg,{_c1},{_c2});'
                    f'color:#fff;padding:2px 10px;border-radius:8px;font-size:0.72rem;'
                    f'font-weight:600;">{g["cat"]}</div>'
                    f'</div>',
                    unsafe_allow_html=True,
                )
                st.markdown(
                    f'<a href="{_base}{g["url"]}" target="_blank" style="'
                    f'display:block;background:linear-gradient(135deg,{_c1},{_c2});'
                    f'color:#fff;padding:9px 16px;border-radius:10px;text-decoration:none;'
                    f'font-size:0.88rem;font-weight:700;text-align:center;'
                    f'box-shadow:0 3px 10px {_c1}40;">🎮 Oyna</a>',
                    unsafe_allow_html=True,
                )


