def _build_en_fable_spotlight(title: str, text: str, word_count: int) -> str:
    """English fable icin spotlight HTML — kelimeye tikla Turkce anlamini gor.
    Uses inline onclick handlers (matching the working _build_spotlight_html pattern).
    Only embeds dictionary entries for words that appear in the tale (keeps HTML small).
    """
    import json as _j
    import re
    import html as _hm
    from utils.en_tr_dict import EN_TR_DICT

    safe_title = _hm.escape(title)

    # Collect unique words in the tale
    all_words_raw = set(re.findall(r"[A-Za-z']+", text.lower()))
    all_words = {w.strip("'") for w in all_words_raw if w.strip("'")}

    # Build subset dictionary — only words in this tale
    sub_dict = {}
    for w in all_words:
        if w in EN_TR_DICT:
            sub_dict[w] = EN_TR_DICT[w]
    dict_matches = len(sub_dict)

    # Paragraphs: each word gets inline onclick
    # Words WITH dictionary entry get extra "hw" class (spotlight highlight)
    # Sentences wrapped in <span class="sn"> for read-aloud highlighting
    paragraphs = text.split("\n")
    paras_html = ""
    sent_idx = 0  # global sentence counter
    for para in paragraphs:
        p = para.strip()
        if not p:
            continue
        # Split paragraph into sentences
        sentences = re.split(r'(?<=[.!?])\s+', p)
        para_parts = []
        for sent in sentences:
            if not sent.strip():
                continue
            tokens = re.findall(r"[A-Za-z']+|[^A-Za-z'\s]+|\s+", sent)
            word_parts = []
            for tok in tokens:
                if re.match(r"^[A-Za-z']+$", tok):
                    wl = tok.lower().strip("'")
                    safe_tok = _hm.escape(tok)
                    safe_wl = _hm.escape(wl).replace("'", "\\'")
                    cls = "ew hw" if wl in sub_dict else "ew"
                    word_parts.append(
                        f'<span class="{cls}" onclick="sw(this,\'{safe_wl}\')">{safe_tok}</span>'
                    )
                else:
                    word_parts.append(_hm.escape(tok))
            para_parts.append(f'<span class="sn" data-i="{sent_idx}">{"".join(word_parts)}</span>')
            sent_idx += 1
        paras_html += '<p class="fp">' + " ".join(para_parts) + "</p>\n"
    total_sentences = sent_idx

    # Build the HTML — use string concat for dict to avoid f-string brace issues
    css = """<style>
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:'Georgia','Palatino',serif;background:linear-gradient(180deg,#1a1520,#0f0d13);color:#e8e0d4;padding:0;overflow-x:hidden}
.fw{max-width:700px;margin:0 auto;padding:16px 20px}
.fh{display:flex;align-items:center;gap:14px;padding:14px 18px;margin-bottom:12px;background:linear-gradient(135deg,#064e3b,#065f46);border-radius:14px;border:1px solid rgba(16,185,129,.2)}
.fh h1{font-size:1.15rem;color:#ecfdf5;font-weight:700;line-height:1.3}
.fh .sub{font-size:.78rem;color:#6ee7b7;margin-top:2px}
.fh .wc{margin-left:auto;background:linear-gradient(135deg,#10b981,#059669);border-radius:16px;padding:5px 12px;text-align:center;flex-shrink:0}
.fh .wc .num{font-size:.95rem;font-weight:800;color:#fff}
.fh .wc .lbl{font-size:.55rem;color:rgba(255,255,255,.8)}
.ib{display:flex;gap:10px;margin-bottom:12px;padding:10px 14px;background:rgba(255,255,255,.05);border-radius:10px;border:1px solid rgba(255,255,255,.08);align-items:center;font-size:.82rem;color:#94a3b8;flex-wrap:wrap}
.ib b{color:#10b981;font-size:.95rem;margin:0 2px}
.sc{max-height:480px;overflow-y:auto;padding-right:4px;position:relative}
.fp{font-size:1.02rem;line-height:2;margin-bottom:12px;color:#d4ccc0;text-align:justify;text-indent:1.5em}
.sn{transition:all .3s;border-radius:4px;padding:2px 0}
.sn.rd{background:linear-gradient(135deg,rgba(59,130,246,.18),rgba(99,102,241,.12));box-shadow:0 0 16px rgba(59,130,246,.15);border-radius:6px;padding:2px 4px}
.sn.rd .ew{color:#93c5fd !important}
.sn.rd .ew.hw{color:#fde68a !important;text-shadow:0 0 10px rgba(251,191,36,.3)}
.sn.done{opacity:.55}
.ab{display:flex;gap:8px;margin-bottom:12px;padding:10px 14px;background:linear-gradient(135deg,rgba(59,130,246,.1),rgba(99,102,241,.08));border-radius:12px;border:1px solid rgba(59,130,246,.2);align-items:center}
.ab button{padding:8px 16px;border-radius:8px;border:none;font-weight:700;font-size:.82rem;cursor:pointer;transition:all .15s;display:flex;align-items:center;gap:5px}
.ab button:hover{filter:brightness(1.15);transform:scale(1.03)}
.ab .bplay{background:linear-gradient(135deg,#3b82f6,#2563eb);color:#fff}
.ab .bslow{background:linear-gradient(135deg,#8b5cf6,#7c3aed);color:#fff}
.ab .bstop{background:rgba(255,255,255,.1);color:#94a3b8}
.ab .sinfo{margin-left:auto;font-size:.78rem;color:#64748b}
.ab .sinfo b{color:#3b82f6}
.ew{cursor:pointer;transition:all .15s;padding:1px 2px;border-radius:3px;border-bottom:1px dotted transparent;position:relative}
.ew.hw{color:#fbbf24;font-style:italic;font-weight:600;border-bottom:2px dotted rgba(251,191,36,.4);text-shadow:0 0 8px rgba(251,191,36,.15)}
.ew.hw:hover{color:#fef08a;background:rgba(245,197,66,.15);border-bottom-color:#fbbf24;text-shadow:0 0 12px rgba(251,191,36,.3)}
.ew:hover{color:#fde68a;background:rgba(245,197,66,.08);border-bottom-color:rgba(245,197,66,.2)}
.ew.on{color:#fff;background:linear-gradient(135deg,rgba(251,191,36,.3),rgba(245,158,11,.25));border-bottom:2px solid #fbbf24;font-weight:700;text-shadow:0 0 10px rgba(251,191,36,.4);border-radius:4px}
.ew.seen{color:#6ee7b7;border-bottom:1px dotted rgba(16,185,129,.3)}
#tp{display:none;position:absolute;z-index:9999;background:linear-gradient(135deg,#2d1f3d,#1e1533);border:1.5px solid rgba(16,185,129,.4);border-radius:14px;padding:16px 20px;box-shadow:0 12px 40px rgba(0,0,0,.6);min-width:260px;max-width:360px;animation:pi .2s ease-out}
@keyframes pi{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
#tp.show{display:block}
.tp-lbl{font-size:.7rem;color:#64748b;text-transform:uppercase;letter-spacing:1px;margin-bottom:2px}
.tp-w{font-size:1.3rem;font-weight:800;color:#fbbf24;letter-spacing:.5px}
.tp-arr{font-size:1.1rem;color:#475569;margin:6px 0;text-align:center}
.tp-lbl2{font-size:.7rem;color:#64748b;text-transform:uppercase;letter-spacing:1px;margin-bottom:2px}
.tp-t{font-size:1.15rem;color:#a78bfa;font-weight:700;line-height:1.4}
.tp-n{font-size:.85rem;color:#64748b;font-style:italic}
.tp-b{display:flex;gap:6px;margin-top:10px}
.tp-b button{flex:1;padding:8px 0;border-radius:8px;border:none;font-weight:700;font-size:.8rem;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:4px;transition:all .15s}
.tp-b button:hover{filter:brightness(1.15)}
.ben{background:linear-gradient(135deg,#3b82f6,#2563eb);color:#fff}
.btr{background:linear-gradient(135deg,#10b981,#059669);color:#fff}
.bx{background:rgba(255,255,255,.08);color:#94a3b8;flex:0 !important;padding:8px 12px !important}
</style>"""

    body_html = f"""<div class="fw">
  <div class="fh">
    <div><h1>{safe_title}</h1><div class="sub">Kelimeye tıkla, Türkçesini gör</div></div>
    <div class="wc"><div class="num">~{word_count}</div><div class="lbl">WORD</div></div>
  </div>
  <div class="ib">
    Tıklanan: <b id="cc">0</b> &bull;
    Sözlükte: <b id="fc">0</b> / {dict_matches} &bull;
    Farklı kelime: <b>{len(all_words)}</b>
  </div>
  <div class="ab">
    <button class="bplay" id="bplay" onclick="readAloud(0.9)">🔊 Sesli Oku</button>
    <button class="bslow" onclick="readAloud(0.6)">🐌 Yavaş Oku</button>
    <button class="bstop" onclick="stopRead()">⏹ Durdur</button>
    <span class="sinfo">Cümle: <b id="si">0</b> / {total_sentences}</span>
  </div>
  <div class="sc" id="sc">
    {paras_html}
    <div id="tp">
      <div class="tp-lbl">ENGLISH</div>
      <div class="tp-w" id="tw"></div>
      <div class="tp-arr">▼</div>
      <div class="tp-lbl2">TURKCE KARSILIGI</div>
      <div id="tt"></div>
      <div class="tp-b">
        <button class="ben" onclick="spk('en')">🔊 İngilizce Oku</button>
        <button class="btr" onclick="spk('tr')">🔊 Türkçe Oku</button>
        <button class="bx" onclick="htp()">✕</button>
      </div>
    </div>
  </div>
</div>"""

    # JS uses inline onclick sw() — no addEventListener needed
    # Dict injected via string concat to avoid f-string brace issues
    dict_json = _j.dumps(sub_dict, ensure_ascii=False)

    js = (
        "<script>\nvar D="
        + dict_json
        + """;
var cc=0,fc=0,cw='',ct='',seen={};
function sw(el,w){
  if(!w)return;
  cc++;document.getElementById('cc').textContent=cc;
  var prev=document.querySelectorAll('.ew.on');
  for(var i=0;i<prev.length;i++)prev[i].classList.remove('on');
  el.classList.add('on');
  if(!seen[w]){
    seen[w]=1;el.classList.add('seen');
    var all=document.querySelectorAll('.ew');
    for(var j=0;j<all.length;j++){
      if(all[j].textContent.toLowerCase().replace(/'/g,'')===w)all[j].classList.add('seen');
    }
  }
  cw=w;
  var tr=D[w]||'';ct=tr;
  document.getElementById('tw').textContent='"'+w+'"';
  var tt=document.getElementById('tt');
  if(tr){
    tt.innerHTML='<span style="font-size:1.15rem;font-weight:700;color:#a78bfa;">\"'+tr+'\"</span><br><span style="font-size:.82rem;color:#94a3b8;margin-top:3px;display:inline-block;">\"'+w+'\" kelimesinin Türkçe karşılığı \"'+tr+'\" demektir.</span>';
    tt.className='tp-t';fc++;document.getElementById('fc').textContent=fc
  } else {
    tt.innerHTML='<span style="color:#64748b;font-style:italic;">Bu kelime sözlükte bulunamadı.</span>';
    tt.className='tp-n'
  }
  var tp=document.getElementById('tp');
  var r=el.getBoundingClientRect();
  var sc=document.getElementById('sc');
  var sr=sc.getBoundingClientRect();
  var top=r.bottom-sr.top+sc.scrollTop+4;
  var left=r.left-sr.left;
  if(left+300>sc.offsetWidth)left=sc.offsetWidth-310;
  if(left<0)left=4;
  tp.style.top=top+'px';tp.style.left=left+'px';
  tp.classList.add('show');
  spk('en');
}
function htp(){
  document.getElementById('tp').classList.remove('show');
  var prev=document.querySelectorAll('.ew.on');
  for(var i=0;i<prev.length;i++)prev[i].classList.remove('on');
}
document.addEventListener('click',function(e){
  if(!e.target.closest('.ew')&&!e.target.closest('#tp'))htp();
});
function spk(lang){
  var text=lang==='tr'?ct:cw;
  if(!text)return;
  try{window.speechSynthesis.cancel()}catch(e){}
  try{
    var u=new SpeechSynthesisUtterance(text);
    u.lang=lang==='tr'?'tr-TR':'en-US';u.rate=0.85;
    window.speechSynthesis.speak(u);
  }catch(e){}
}
var reading=false,rIdx=-1,rRate=0.9,paused=false;
var sns=document.querySelectorAll('.sn');
function hlSent(i){
  for(var k=0;k<sns.length;k++){
    sns[k].classList.remove('rd');
    if(k<i)sns[k].classList.add('done');
    else sns[k].classList.remove('done');
  }
  if(i>=0&&i<sns.length){
    sns[i].classList.add('rd');
    sns[i].scrollIntoView({behavior:'smooth',block:'center'});
  }
  document.getElementById('si').textContent=Math.min(i+1,sns.length);
}
function readSent(i){
  if(!reading||i>=sns.length){stopRead();return}
  rIdx=i;hlSent(i);
  var txt=sns[i].textContent.trim();
  if(!txt){readSent(i+1);return}
  try{
    var u=new SpeechSynthesisUtterance(txt);
    u.lang='en-US';u.rate=rRate;u.pitch=1;
    u.onend=function(){if(reading&&!paused)readSent(i+1)};
    u.onerror=function(){if(reading)readSent(i+1)};
    window.speechSynthesis.speak(u);
  }catch(e){readSent(i+1)}
}
function readAloud(rate){
  if(paused){paused=false;window.speechSynthesis.resume();document.getElementById('bplay').innerHTML='⏸ Duraklat';return}
  if(reading){paused=true;window.speechSynthesis.pause();document.getElementById('bplay').innerHTML='▶ Devam Et';return}
  reading=true;paused=false;rRate=rate;
  document.getElementById('bplay').innerHTML='⏸ Duraklat';
  for(var k=0;k<sns.length;k++)sns[k].classList.remove('done','rd');
  readSent(0);
}
function stopRead(){
  reading=false;paused=false;rIdx=-1;
  try{window.speechSynthesis.cancel()}catch(e){}
  document.getElementById('bplay').innerHTML='🔊 Sesli Oku';
  for(var k=0;k<sns.length;k++)sns[k].classList.remove('rd','done');
  document.getElementById('si').textContent='0';
}
</script>"""
    )

    return "<!DOCTYPE html><html><head><meta charset=\"utf-8\">" + css + "</head><body>" + body_html + js + "</body></html>"


def _render_reading_library():
    """Okuma kutuphanesi — seviyeli okuma metinleri ve kavrama sorulari."""
    # Kill any lingering audio from other tabs
    st.components.v1.html(
        "<script>(function(){"
        "try{window.parent.speechSynthesis.cancel()}catch(e){}"
        "try{window.parent.document.querySelectorAll('iframe').forEach(function(f){"
        "  try{f.contentWindow.speechSynthesis.cancel()}catch(e){}"
        "  try{var aa=f.contentWindow.document.querySelectorAll('audio,video');"
        "    aa.forEach(function(a){try{a.pause();a.src=''}catch(e){}});}catch(e){}"
        "  var ns=['AC','audioCtx','_aC','ac'];"
        "  ns.forEach(function(n){try{if(f.contentWindow[n]&&f.contentWindow[n].state!=='closed')f.contentWindow[n].close()}catch(e){}});"
        "})}catch(e){}"
        "var k=0;var iv=setInterval(function(){k++;try{window.parent.speechSynthesis.cancel()}catch(e){}"
        "if(k>=6)clearInterval(iv)},500);"
        "})();</script>",
        height=0,
    )
    st.markdown(
        '<div style="background:linear-gradient(135deg,#92400e,#d97706);color:#fff;'
        'padding:18px 24px;border-radius:14px;margin-bottom:18px;">'
        '<div style="font-size:1.35rem;font-weight:700;">📖 Okuma Kutuphanesi</div>'
        '<div style="font-size:0.92rem;opacity:.85;margin-top:4px;">'
        'CEFR seviyenize uygun okuma kaynaklari — basliga tiklayarak acin</div>'
        '</div>', unsafe_allow_html=True,
    )

    sinif = st.session_state.get("yd_sinif")
    level = _yd_sinif_to_level(sinif)

    cefr_key = "A1"
    if level and "grade" in level:
        gn = int(level.replace("grade", ""))
        if gn <= 4:
            cefr_key = "A1"
        elif gn <= 8:
            cefr_key = "A2"
        elif gn <= 10:
            cefr_key = "B1"
        else:
            cefr_key = "B2"

    cefr_sel = st.selectbox("Seviye:", ["A1", "A2", "B1", "B2"], index=["A1", "A2", "B1", "B2"].index(cefr_key), key="reader_cefr")

    # ── Section navigation ──
    _RL_SECTIONS = [
        ("classics", "📚 Klasik Eserler Kutuphanesi (85 Ingilizce Kitap)", "#7c3aed"),
        ("en_tales", "📖 English Literature — Spotlight Reading (345 Tale)", "#10b981"),
        ("graded", "📖 Graded Readers (Okuma Metinleri)", "#d97706"),
        ("pdf", "📚 PDF Kitap Kutuphanesi", "#2563eb"),
        ("meb", "🇹🇷 MEB Ingilizce Hikaye Kitaplari", "#ef4444"),
        ("eba_books", "🎓 EBA Ingilizce Hikaye Kitaplari", "#06b6d4"),
        ("eba_songs", "🎵 EBA Ingilizce Sarkilar", "#8b5cf6"),
        ("eba_cartoons", "🎬 EBA Animasyonlar (77 Video)", "#f97316"),
    ]
    if "_rl_open" not in st.session_state:
        st.session_state["_rl_open"] = None

    # Section header CSS
    st.markdown(
        '<style>'
        '[data-testid="stButton"] button[kind="secondary"][key^="rl_sec_"],'
        'div[data-testid="stVerticalBlock"] > div > div > div > button[kind="secondary"]{'
        'text-align:left !important;justify-content:flex-start !important;'
        'font-weight:700 !important;font-size:1rem !important;'
        'border:2px solid rgba(212,168,67,.3) !important;'
        'border-radius:12px !important;padding:14px 20px !important;'
        'margin-bottom:4px !important;'
        'background:linear-gradient(135deg,rgba(30,25,20,.95),rgba(20,18,15,.98)) !important;'
        'color:#d4a843 !important;transition:all .3s !important}'
        '</style>',
        unsafe_allow_html=True,
    )

    # Render clickable section headers
    for _sec_key, _sec_title, _sec_color in _RL_SECTIONS:
        _is_open = st.session_state["_rl_open"] == _sec_key
        _arrow = "▼" if _is_open else "▶"
        if st.button(
            f"{_arrow}  {_sec_title}",
            key=f"rl_sec_{_sec_key}",
            use_container_width=True,
        ):
            st.session_state["_rl_open"] = None if _is_open else _sec_key
            st.rerun()
        if not _is_open:
            continue

        # ── SECTION: Klasik Eserler (English classics from Gutenberg) ──
        if _sec_key == "classics":
            import os as _os
            _kitaplar_dir = _os.path.join(_os.path.dirname(__file__), "..", "data", "kutuphane", "kitaplar")
            from views._e_kitap_indir import render_kitap_indir
            render_kitap_indir(_kitaplar_dir, lang_filter="en")
