# DİJİTAL KAYNAKLAR SEKMESİ (PDF Flipbook)
# ══════════════════════════════════════════════════════════════════════════════

_ENG_DIJITAL_KAYNAKLAR_PATH = os.path.join(
    "data", "english", "dijital_kaynaklar.json")


def _load_dijital_kaynaklar() -> list:
    """Tum dijital kaynak kayitlarini yukle."""
    if os.path.exists(_ENG_DIJITAL_KAYNAKLAR_PATH):
        try:
            with open(_ENG_DIJITAL_KAYNAKLAR_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception as _exc:
            _logger.debug('Suppressed: %s', _exc)
            return []
    return []


def _save_dijital_kaynak(record: dict):
    """Dijital kaynak kaydini ekle."""
    data = _load_dijital_kaynaklar()
    data.append(record)
    os.makedirs(os.path.dirname(_ENG_DIJITAL_KAYNAKLAR_PATH), exist_ok=True)
    with open(_ENG_DIJITAL_KAYNAKLAR_PATH, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def _delete_dijital_kaynak(kaynak_id: str):
    """Dijital kaynagi id ile sil."""
    data = _load_dijital_kaynaklar()
    data = [r for r in data if r.get("id") != kaynak_id]
    os.makedirs(os.path.dirname(_ENG_DIJITAL_KAYNAKLAR_PATH), exist_ok=True)
    with open(_ENG_DIJITAL_KAYNAKLAR_PATH, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def _build_flipbook_html(pdf_base64: str, title: str) -> str:
    """PDF base64 verisinden flipbook HTML/JS olustur — buyuk goruntu + sesli okuma."""
    return f'''<!DOCTYPE html>
<html><head><meta charset="utf-8">
<style>
*{{margin:0;padding:0;box-sizing:border-box}}
body{{background:#0B0F19;display:flex;flex-direction:column;align-items:center;
      font-family:'Segoe UI',sans-serif;overflow-x:hidden;overflow-y:auto;
      padding:8px 0}}
.book-header{{color:#fff;font-size:20px;font-weight:700;margin:4px 0 8px;
              text-align:center;text-shadow:0 2px 8px rgba(0,0,0,.5)}}
.book-wrapper{{position:relative;background:#94A3B8;border-radius:12px;
               box-shadow:0 8px 32px rgba(0,0,0,.5),inset 0 0 60px rgba(0,0,0,.2);
               padding:10px;perspective:1500px;width:98%;max-width:1100px;overflow:hidden}}
#pdf-canvas{{display:block;margin:0 auto;border-radius:4px;
             transition:transform .5s cubic-bezier(.4,.0,.2,1),opacity .3s;
             transform-origin:center center;max-width:100%;
             box-shadow:0 2px 16px rgba(0,0,0,.3)}}
#pdf-canvas.flip-right{{transform:rotateY(-12deg) scale(.97);opacity:.7}}
#pdf-canvas.flip-left{{transform:rotateY(12deg) scale(.97);opacity:.7}}
.click-zone{{position:absolute;top:10px;bottom:56px;cursor:pointer;z-index:10}}
.click-zone.left{{left:10px;width:45%}}
.click-zone.right{{right:10px;width:45%}}
.click-zone:hover{{background:rgba(255,255,255,.03)}}
.controls{{display:flex;align-items:center;justify-content:center;gap:10px;
           padding:8px 0 2px;width:100%;flex-wrap:wrap}}
.controls button{{background:linear-gradient(135deg,#2563eb,#1e40af);color:#fff;
                  border:none;padding:9px 22px;border-radius:8px;cursor:pointer;
                  font-size:14px;font-weight:600;transition:all .2s;
                  box-shadow:0 2px 8px rgba(37,99,235,.4)}}
.controls button:hover{{transform:translateY(-1px);
                        box-shadow:0 4px 12px rgba(37,99,235,.6)}}
.controls button:disabled{{opacity:.4;cursor:not-allowed;transform:none}}
#page-info{{color:#e2e8f0;font-size:14px;font-weight:600;
            min-width:80px;text-align:center}}
.loading{{color:#60a5fa;font-size:16px;text-align:center;padding:40px}}
.tts-bar{{display:flex;align-items:center;justify-content:center;gap:10px;
          padding:6px 0;flex-wrap:wrap}}
.tts-bar button{{border:none;padding:8px 18px;border-radius:8px;cursor:pointer;
                 font-size:13px;font-weight:600;transition:all .2s}}
#btnSpeak{{background:linear-gradient(135deg,#16a34a,#15803d);color:#fff;
           box-shadow:0 2px 8px rgba(22,163,74,.4)}}
#btnSpeak:hover{{transform:translateY(-1px)}}
#btnSpeak.speaking{{background:linear-gradient(135deg,#dc2626,#b91c1c);
                    animation:pulse 1.2s infinite}}
#btnStop{{background:linear-gradient(135deg,#dc2626,#b91c1c);color:#fff;
          box-shadow:0 2px 8px rgba(220,38,38,.4)}}
#ttsSpeed{{background:#334155;color:#e2e8f0;border:1px solid #475569;
           padding:6px 10px;border-radius:6px;font-size:13px;font-weight:600}}
#ttsStatus{{color:#94a3b8;font-size:12px;font-style:italic}}
@keyframes pulse{{0%,100%{{opacity:1}}50%{{opacity:.6}}}}
</style>
</head><body>
<div class="book-header">📚 {title}</div>
<div class="book-wrapper" id="bookWrapper">
  <canvas id="pdf-canvas"></canvas>
  <div class="click-zone left" id="zoneLeft"></div>
  <div class="click-zone right" id="zoneRight"></div>
  <div class="controls">
    <button id="btnPrev" onclick="prevPage()">◀ Onceki</button>
    <span id="page-info">Yukleniyor...</span>
    <button id="btnNext" onclick="nextPage()">Sonraki ▶</button>
  </div>
  <div class="tts-bar">
    <button id="btnSpeak" onclick="speakPage()">🔊 Sesli Oku</button>
    <button id="btnStop" onclick="stopSpeak()" style="display:none">⏹ Durdur</button>
    <select id="ttsSpeed" onchange="updateRate()">
      <option value="0.6">🐢 Yavas</option>
      <option value="0.8" selected>🔉 Normal</option>
      <option value="1.0">🔊 Hizli</option>
      <option value="1.2">⚡ Cok Hizli</option>
    </select>
    <span id="ttsStatus"></span>
  </div>
</div>
<div class="loading" id="loadMsg">PDF yukleniyor...</div>

<script src="https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js"></script>
<script>
pdfjsLib.GlobalWorkerOptions.workerSrc =
  "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";

const pdfData = atob("{pdf_base64}");
let pdfDoc = null, pageNum = 1, pageCount = 0, rendering = false;
let pageTextCache = {{}};
let ttsRate = 0.8, isSpeaking = false;
const canvas = document.getElementById("pdf-canvas");
const ctx = canvas.getContext("2d");

async function loadPDF() {{
  try {{
    const loadingTask = pdfjsLib.getDocument({{data: pdfData}});
    pdfDoc = await loadingTask.promise;
    pageCount = pdfDoc.numPages;
    document.getElementById("loadMsg").style.display = "none";
    document.getElementById("bookWrapper").style.display = "block";
    renderPage(pageNum);
  }} catch(e) {{
    document.getElementById("loadMsg").textContent = "PDF yuklenemedi: " + e.message;
  }}
}}

async function renderPage(num) {{
  if (rendering) return;
  rendering = true;
  const page = await pdfDoc.getPage(num);
  const wrapper = document.getElementById("bookWrapper");
  const maxW = wrapper.clientWidth - 20;
  const vp0 = page.getViewport({{scale: 1}});
  const scale = maxW / vp0.width;
  const viewport = page.getViewport({{scale: scale}});
  canvas.height = viewport.height;
  canvas.width = viewport.width;
  await page.render({{canvasContext: ctx, viewport: viewport}}).promise;
  document.getElementById("page-info").textContent = num + " / " + pageCount;
  document.getElementById("btnPrev").disabled = (num <= 1);
  document.getElementById("btnNext").disabled = (num >= pageCount);
  rendering = false;
}}

async function getPageText(num) {{
  if (pageTextCache[num]) return pageTextCache[num];
  try {{
    const page = await pdfDoc.getPage(num);
    const tc = await page.getTextContent();
    const txt = tc.items.map(i => i.str).join(' ').replace(/\\s+/g,' ').trim();
    pageTextCache[num] = txt;
    return txt;
  }} catch(e) {{ return ''; }}
}}

function updateRate() {{
  ttsRate = parseFloat(document.getElementById('ttsSpeed').value);
}}

function findEngVoice() {{
  const vs = speechSynthesis.getVoices();
  const pref = ['Google UK English Female','Google US English','Microsoft Zira',
                'Microsoft Jenny','Samantha','Karen','Daniel'];
  for (const p of pref) {{
    const v = vs.find(v => v.name.includes(p) && v.lang.startsWith('en'));
    if (v) return v;
  }}
  return vs.find(v => v.lang.startsWith('en')) || null;
}}

async function speakPage() {{
  const txt = await getPageText(pageNum);
  if (!txt) {{
    document.getElementById('ttsStatus').textContent = 'Bu sayfada metin yok';
    setTimeout(() => document.getElementById('ttsStatus').textContent = '', 3000);
    return;
  }}
  speechSynthesis.cancel();
  isSpeaking = true;
  document.getElementById('btnSpeak').classList.add('speaking');
  document.getElementById('btnSpeak').innerHTML = '🔊 Okunuyor...';
  document.getElementById('btnStop').style.display = 'inline-block';
  document.getElementById('ttsStatus').textContent = '';

  // Split long text into chunks (max ~180 chars at sentence boundaries)
  const sentences = txt.match(/[^.!?]+[.!?]+|[^.!?]+$/g) || [txt];
  let chunks = [], cur = '';
  for (const s of sentences) {{
    if ((cur + s).length > 180 && cur) {{ chunks.push(cur.trim()); cur = s; }}
    else {{ cur += s; }}
  }}
  if (cur.trim()) chunks.push(cur.trim());

  let ci = 0;
  function speakNext() {{
    if (ci >= chunks.length || !isSpeaking) {{
      isSpeaking = false;
      document.getElementById('btnSpeak').classList.remove('speaking');
      document.getElementById('btnSpeak').innerHTML = '🔊 Sesli Oku';
      document.getElementById('btnStop').style.display = 'none';
      return;
    }}
    const u = new SpeechSynthesisUtterance(chunks[ci]);
    u.lang = 'en-US'; u.rate = ttsRate; u.pitch = 1.05; u.volume = 1.0;
    const v = findEngVoice(); if (v) u.voice = v;
    u.onend = () => {{ ci++; speakNext(); }};
    u.onerror = () => {{ ci++; speakNext(); }};
    speechSynthesis.speak(u);
  }}
  speakNext();
}}

function stopSpeak() {{
  isSpeaking = false;
  speechSynthesis.cancel();
  document.getElementById('btnSpeak').classList.remove('speaking');
  document.getElementById('btnSpeak').innerHTML = '🔊 Sesli Oku';
  document.getElementById('btnStop').style.display = 'none';
}}

function flipAndRender(dir) {{
  if (rendering) return;
  stopSpeak();
  const cls = dir === "next" ? "flip-right" : "flip-left";
  canvas.classList.add(cls);
  setTimeout(() => {{
    if (dir === "next" && pageNum < pageCount) pageNum++;
    else if (dir === "prev" && pageNum > 1) pageNum--;
    renderPage(pageNum).then(() => {{
      canvas.classList.remove(cls);
    }});
  }}, 250);
}}

function nextPage() {{ flipAndRender("next"); }}
function prevPage() {{ flipAndRender("prev"); }}

document.getElementById("zoneLeft").addEventListener("click", prevPage);
document.getElementById("zoneRight").addEventListener("click", nextPage);

document.addEventListener("keydown", (e) => {{
  if (e.key === "ArrowRight" || e.key === " ") nextPage();
  else if (e.key === "ArrowLeft") prevPage();
}});

speechSynthesis.getVoices();

document.getElementById("bookWrapper").style.display = "none";
loadPDF();
</script>
</body></html>'''


def _render_dijital_kaynaklar_tab():
    """Yabanci Dil Dijital Kaynaklar sekmesi — PDF flipbook goruntuleyici."""
    import base64
    import uuid as _uuid
    from datetime import datetime as _dt

    # ── Premium gradient header ──
    st.markdown(
        '<div style="background:linear-gradient(135deg,#0B0F19,#1e40af);color:#fff;'
        'padding:18px 24px;border-radius:14px;margin-bottom:18px;">'
        '<div style="font-size:1.35rem;font-weight:700;">'
        '📚 Dijital Kaynaklar</div>'
        '<div style="font-size:0.92rem;opacity:.85;margin-top:4px;">'
        'PDF kitaplari flipbook olarak goruntuleyin — '
        'sayfa sayfa cevirin</div></div>',
        unsafe_allow_html=True,
    )

    # ── Global filtreden level al ──
    sinif = st.session_state.get("yd_sinif")
    level = _yd_sinif_to_level(sinif)
    level_label = _CURRICULUM_LEVEL_LABELS.get(level, "Tum Seviyeler")

    # ── PDF Yükle ──
    with st.expander("📤 Yeni Kaynak Yukle", expanded=False):
        c1, c2 = st.columns(2)
        with c1:
            dk_baslik = st.text_input(
                "Baslik:",
                key="dk_baslik",
                placeholder="Ornek: English Story Book - Level 1",
            )
        with c2:
            dk_kategori = st.selectbox(
                "Kategori:",
                ["Hikaye Kitabi", "Calisma Kagidi", "Gramer",
                 "Sozluk", "Sarki / Siir", "Diger"],
                key="dk_kategori",
            )
        dk_level = st.selectbox(
            "Seviye:",
            list(_CURRICULUM_LEVEL_LABELS.keys()),
            format_func=lambda x: _CURRICULUM_LEVEL_LABELS.get(x, x),
            index=(list(_CURRICULUM_LEVEL_LABELS.keys()).index(level)
                   if level in _CURRICULUM_LEVEL_LABELS else 0),
            key="dk_level_sel",
        )
        dk_file = st.file_uploader(
            "PDF Dosya Sec",
            type=["pdf"],
            key="dk_pdf_file",
        )
        if dk_file:
            from utils.security import validate_upload
            _ok, _msg = validate_upload(dk_file, allowed_types=["pdf"], max_mb=50)
            if not _ok:
                st.error(f"⚠️ {_msg}")
                dk_file = None
        if st.button("📤 Kaynak Yukle", key="dk_upload_btn",
                      use_container_width=True, type="primary"):
            if not dk_baslik or not dk_baslik.strip():
                st.warning("Lutfen bir baslik giriniz.")
            elif not dk_file:
                st.warning("Lutfen bir PDF dosyasi seciniz.")
            else:
                dk_dir = os.path.join("data", "english", "dijital_kaynaklar")
                os.makedirs(dk_dir, exist_ok=True)
                uid = _uuid.uuid4().hex[:8]
                fname = f"dk_{uid}_{dk_file.name}"
                fpath = os.path.join(dk_dir, fname)
                with open(fpath, "wb") as f:
                    f.write(dk_file.getbuffer())
                record = {
                    "id": f"dk_{uid}",
                    "baslik": dk_baslik.strip(),
                    "dosya_adi": dk_file.name,
                    "dosya_yolu": fpath,
                    "level": dk_level,
                    "kategori": dk_kategori,
                    "created_by": st.session_state.get(
                        "auth_user", {}).get("username", ""),
                    "created_at": _dt.now().isoformat(),
                }
                _save_dijital_kaynak(record)
                st.success(f"'{dk_baslik.strip()}' basariyla yuklendi!")
                st.rerun()

    # ── Kaynak Kütüphanesi ──
    st.markdown("##### 📖 Kaynak Kutuphanesi")
    all_kaynaklar = _load_dijital_kaynaklar()

    # Filtreler
    fc1, fc2 = st.columns(2)
    with fc1:
        fil_level = st.selectbox(
            "Seviye Filtre:",
            ["Tumu"] + list(_CURRICULUM_LEVEL_LABELS.keys()),
            format_func=lambda x: "Tumu" if x == "Tumu"
            else _CURRICULUM_LEVEL_LABELS.get(x, x),
            key="dk_fil_level",
        )
    with fc2:
        kat_options = ["Tumu", "Hikaye Kitabi", "Calisma Kagidi",
                       "Gramer", "Sozluk", "Sarki / Siir", "Diger"]
        fil_kat = st.selectbox(
            "Kategori Filtre:", kat_options, key="dk_fil_kat")

    filtered = all_kaynaklar
    if fil_level != "Tumu":
        filtered = [k for k in filtered if k.get("level") == fil_level]
    if fil_kat != "Tumu":
        filtered = [k for k in filtered if k.get("kategori") == fil_kat]

    # En yeniden eskiye
    filtered.sort(key=lambda x: x.get("created_at", ""), reverse=True)

    if not filtered:
        st.info("Kayitli dijital kaynak bulunmamaktadir. "
                "Yukaridaki formu kullanarak PDF yukleyebilirsiniz.")
        return

    # Kart grid (3'lü)
    kat_icons = {
        "Hikaye Kitabi": "📕", "Calisma Kagidi": "📗",
        "Gramer": "📘", "Sozluk": "📙",
        "Sarki / Siir": "🎵", "Diger": "📄",
    }

    cols = st.columns(3)
    for idx, k in enumerate(filtered):
        with cols[idx % 3]:
            icon = kat_icons.get(k.get("kategori", ""), "📄")
            lbl = _CURRICULUM_LEVEL_LABELS.get(
                k.get("level", ""), k.get("level", ""))
            st.markdown(
                f'<div style="background:linear-gradient(135deg,#111827,#e2e8f0);'
                f'border:1px solid #cbd5e1;border-radius:12px;padding:14px;'
                f'margin-bottom:10px;text-align:center;">'
                f'<div style="font-size:2.5rem;">{icon}</div>'
                f'<div style="font-weight:700;font-size:0.9rem;margin:4px 0;">'
                f'{k.get("baslik", "—")}</div>'
                f'<div style="font-size:0.78rem;color:#64748b;">'
                f'{k.get("kategori", "")} | {lbl}</div>'
                f'</div>',
                unsafe_allow_html=True,
            )
            if st.button(
                f"📖 Ac",
                key=f"dk_open_{k.get('id', idx)}",
                use_container_width=True,
            ):
                st.session_state["dk_active_id"] = k.get("id")

            if st.button(
                "🗑️ Sil",
                key=f"dk_del_{k.get('id', idx)}",
                use_container_width=True,
            ):
                fpath = k.get("dosya_yolu", "")
                if fpath and os.path.exists(fpath):
                    try:
                        os.remove(fpath)
                    except Exception as _exc:
                        _logger.debug('Suppressed: %s', _exc)
                _delete_dijital_kaynak(k.get("id", ""))
                st.success("Kaynak silindi.")
                st.rerun()

    # ── Flipbook Görüntüleyici ──
    active_id = st.session_state.get("dk_active_id")
    if active_id:
        active_k = next(
            (k for k in all_kaynaklar if k.get("id") == active_id), None)
        if active_k:
            pdf_path = active_k.get("dosya_yolu", "")
            if pdf_path and os.path.exists(pdf_path):
                st.markdown("---")
                st.markdown(
                    f'##### 📖 {active_k.get("baslik", "Flipbook")}')
                try:
                    with open(pdf_path, "rb") as f:
                        pdf_bytes = f.read()
                    pdf_b64 = base64.b64encode(pdf_bytes).decode("utf-8")
                    html = _build_flipbook_html(
                        pdf_b64, active_k.get("baslik", ""))
                    st.components.v1.html(html, height=750, scrolling=False)
                except Exception as e:
                    st.error(f"PDF yuklenirken hata: {e}")
            else:
                st.warning("PDF dosyasi bulunamadi.")


def _render_activity_pdf_tab():
    """Etkinlik Kitabi PDF — Kademe > Sinif > Plan Turu > Secim > PDF."""
    import json as _json
    from datetime import date as _date_cls, timedelta as _td_cls

    # ── HEADER (Gold Premium) ──
    st.markdown(
        '<div style="background:linear-gradient(135deg,#0B0F19 0%,#94A3B8 50%,#0B0F19 100%);'
        'color:#f5e6c8;padding:24px 28px;border-radius:16px;margin-bottom:20px;'
        'border:2px solid #0ea5e9;position:relative;overflow:hidden;'
        'box-shadow:0 4px 20px rgba(14,165,233,.15);">'
        '<div style="position:absolute;top:0;left:0;right:0;height:4px;'
        'background:linear-gradient(90deg,#0ea5e9,#38bdf8,#7dd3fc,#38bdf8,#0ea5e9);"></div>'
        '<h3 style="margin:0;font-size:22px;font-weight:800;color:#38bdf8;">Etkinlik Kitabi PDF</h3>'
        '<p style="margin:4px 0 0;font-size:13px;color:#7dd3fc;">'
        'Kademe ve plan turune gore etkinlik kitabi PDF olusturun</p>'
        '</div>',
        unsafe_allow_html=True,
    )

    # ── Akademik hafta ──
    _today = _date_cls.today()
    _day_keys_map = {0: "mon", 1: "tue", 2: "wed", 3: "thu", 4: "fri"}
    _today_day_key = _day_keys_map.get(_today.weekday(), "mon")

    def _get_cur_week():
        yr = _today.year if _today.month >= 9 else _today.year - 1
        sep1 = _date_cls(yr, 9, 1)
        dtm = (7 - sep1.weekday()) % 7
        fm = sep1 + _td_cls(days=dtm) if sep1.weekday() != 0 else sep1
        start = fm + _td_cls(weeks=1)
        diff = (_today - start).days
        if diff < 0:
            return 1
        rw = diff // 7 + 1
        if rw > 20:
            rw -= 2
        return max(1, min(rw, 36))

    _cur_week = _get_cur_week()

    # ══════════════════════════════════════════════════
    # 1) KADEME + SINIF + PLAN TURU (3 sutun)
    # ══════════════════════════════════════════════════
    _KADEME = {
        "Okul Oncesi": ["preschool"],
        "Ilkokul": ["grade1", "grade2", "grade3", "grade4"],
        "Ortaokul": ["grade5", "grade6", "grade7", "grade8"],
        "Lise": ["grade9", "grade10", "grade11", "grade12"],
    }
    col1, col2, col3 = st.columns(3)
    with col1:
        sel_kademe = st.selectbox("Kademe:", list(_KADEME.keys()), key="ap_kademe")
    _levels = _KADEME[sel_kademe]
    with col2:
        if len(_levels) == 1:
            sel_level = _levels[0]
            st.text_input("Sinif:", value=_CURRICULUM_LEVEL_LABELS.get(sel_level, sel_level),
                          disabled=True, key="ap_sinif_show")
        else:
            sel_level = st.selectbox("Sinif:", _levels,
                                     format_func=lambda k: _CURRICULUM_LEVEL_LABELS.get(k, k),
                                     key="ap_sinif")
    with col3:
        plan_type = st.selectbox("Plan Turu:", ["Gunluk", "Haftalik", "Yillik"], key="ap_plan")

    # ── Year plan entegrasyonu ──
    import json as _json_ap2
    _yp_data_ap = {}
    try:
        try:
            from utils.tenant import get_data_path as _gdp2
            _yp_path2 = os.path.join(_gdp2("english"), "year_plans.json")
        except Exception:
            _yp_path2 = "data/english/year_plans.json"
        with open(_yp_path2, "r", encoding="utf-8") as _yp_f2:
            _yp_data_ap = _json_ap2.load(_yp_f2)
    except Exception as _exc:
        _logger.debug('Suppressed: %s', _exc)
    _yp_match_ap = None
    for _ypk2, _ypv2 in _yp_data_ap.items():
        if _ypv2.get("level") == sel_level:
            _yp_match_ap = _ypv2
            break
    if _yp_match_ap:
        st.markdown(
            '<div style="background:#eff6ff;border-left:4px solid #1D4ED8;border-radius:0 8px 8px 0;'
            'padding:10px 14px;margin-bottom:12px;font-size:.82rem;color:#1e40af;">'
            'Bu sinif icin Plan & Etkinlik Olusturma sekmesinden etkinlik kitabi olusturulmus. '
            f'({_yp_match_ap.get("year", "")}, {_yp_match_ap.get("created_at", "")})</div>',
            unsafe_allow_html=True,
        )

    # ── Veri yukle ──
    _grade_num = sel_level.replace("grade", "")
    _is_plan_aligned = sel_level.startswith("grade") and _grade_num.isdigit()
    _is_preschool_act = sel_level == "preschool"

    if _is_plan_aligned:
        _wp_path = _WP_PATH
        _wp_data_act = {}
        if os.path.exists(_wp_path):
            with open(_wp_path, "r", encoding="utf-8") as _f:
                _wp_data_act = _json.load(_f)
        _wp_weeks = _wp_data_act.get(_grade_num, [])
        n_weeks = len(_wp_weeks) if _wp_weeks else 36
        if not _wp_weeks:
            # Haftalik plan yoksa curriculum verisini dene
            weeks_data = _CURRICULUM.get(sel_level, [])
            if weeks_data:
                _is_plan_aligned = False
                n_weeks = len(weeks_data)
            else:
                st.warning("Bu sinif icin plan verisi bulunamadi.")
                return
    else:
        weeks_data = _CURRICULUM.get(sel_level, [])
        if not weeks_data:
            st.warning("Bu seviye icin mufredat verisi bulunamadi.")
            return
        n_weeks = len(weeks_data)

    def _wk_label(w):
        if _is_plan_aligned:
            return f"Hafta {w}: {_wp_weeks[w-1].get('unit_theme_tr','')} ({_wp_weeks[w-1].get('unit_theme','')})"
        return f"Hafta {w}: {weeks_data[w-1]['theme']} - {weeks_data[w-1]['theme_tr']}"

    # ══════════════════════════════════════════════════
    # 2) ALT SECIM (plan turune gore)
    # ══════════════════════════════════════════════════
    start_w, end_w = 1, n_weeks
    _act_day_filter = None

    if plan_type == "Gunluk":
        c_a, c_b = st.columns(2)
        with c_a:
            day_sel = st.selectbox("Secim:", ["Bugun", "Tarih Sec"], key="ap_g_sel")
        if day_sel == "Bugun":
            start_w = end_w = _cur_week
            _act_day_filter = _today_day_key
            _dn = _DAY_LABELS.get(_today_day_key, (_today_day_key, ""))[0]
            with c_b:
                st.markdown(
                    f'<div style="background:#EFF6FF;border-left:4px solid #1D4ED8;'
                    f'border-radius:8px;padding:12px 16px;margin-top:25px;">'
                    f'<span style="color:#1D4ED8;font-weight:700;">{_dn}</span>'
                    f'<span style="color:#94A3B8;font-size:13px;"> | Hafta {_cur_week} | '
                    f'{_today.strftime("%d.%m.%Y")}</span></div>',
                    unsafe_allow_html=True)
        else:
            # Akademik yil hesapla
            _ay_start = _today.year if _today.month >= 9 else _today.year - 1
            _ay_end = _ay_start + 1
            _min_date = _date_cls(_ay_start, 9, 1)
            _max_date = _date_cls(_ay_end, 6, 30)
            with c_b:
                sel_date = st.date_input(
                    f"Tarih ({_ay_start}-{_ay_end}):",
                    value=_today, min_value=_min_date, max_value=_max_date,
                    key="ap_g_date")
            # Secilen tarihten hafta ve gun hesapla
            _sel_wd = sel_date.weekday()
            if _sel_wd > 4:
                st.warning("Hafta sonu secildi. Lutfen hafta ici bir gun secin.")
                _sel_wd = 4  # Cuma'ya dusur
            _sel_day_key = _day_keys_map.get(_sel_wd, "mon")
            # Akademik hafta hesapla
            _sep1 = _date_cls(_ay_start, 9, 1)
            _dtm = (7 - _sep1.weekday()) % 7
            _fm = _sep1 + _td_cls(days=_dtm) if _sep1.weekday() != 0 else _sep1
            _acad_start = _fm + _td_cls(weeks=1)
            _diff_days = (sel_date - _acad_start).days
            if _diff_days < 0:
                _sel_wk = 1
            else:
                _sel_wk = _diff_days // 7 + 1
                if _sel_wk > 20:
                    _sel_wk -= 2  # Yariyil tatili
            _sel_wk = max(1, min(_sel_wk, n_weeks))
            start_w = end_w = _sel_wk
            _act_day_filter = _sel_day_key
            _dn2 = _DAY_LABELS.get(_sel_day_key, (_sel_day_key, ""))[0]
            st.markdown(
                f'<div style="background:#EFF6FF;border-left:4px solid #1D4ED8;'
                f'border-radius:8px;padding:10px 16px;margin-top:4px;">'
                f'<span style="color:#1D4ED8;font-weight:700;">{_dn2}</span>'
                f'<span style="color:#94A3B8;font-size:13px;"> | Hafta {_sel_wk} | '
                f'{sel_date.strftime("%d.%m.%Y")} | {_ay_start}-{_ay_end}</span></div>',
                unsafe_allow_html=True)

    elif plan_type == "Haftalik":
        c_a, c_b = st.columns(2)
        with c_a:
            wk_sel = st.selectbox("Secim:", ["Bu Hafta", "Hafta Sec"], key="ap_h_sel")
        if wk_sel == "Bu Hafta":
            start_w = end_w = _cur_week
            _mon, _fri = _academic_week_dates(_cur_week)
            _rng = ""
            if _mon and _fri:
                _rng = f"{_mon.strftime('%d.%m.%Y')} - {_fri.strftime('%d.%m.%Y')}"
            with c_b:
                st.markdown(
                    f'<div style="background:#ECFDF5;border-left:4px solid #059669;'
                    f'border-radius:8px;padding:12px 16px;margin-top:25px;">'
                    f'<span style="color:#059669;font-weight:700;">Hafta {_cur_week}</span>'
                    f'<span style="color:#94A3B8;font-size:13px;"> | {_rng}</span></div>',
                    unsafe_allow_html=True)
        else:
            with c_b:
                sel_wk = st.selectbox("Hafta:", range(1, n_weeks + 1),
                                       index=min(_cur_week - 1, n_weeks - 1),
                                       format_func=_wk_label, key="ap_h_wk")
            start_w = end_w = sel_wk

    elif plan_type == "Yillik":
        c_a, c_b = st.columns(2)
        with c_a:
            yr_sel = st.selectbox("Secim:", ["Tum Yil", "Donem Sec", "Aralik Sec"], key="ap_y_sel")
        if yr_sel == "Tum Yil":
            start_w, end_w = 1, n_weeks
            _ay = _today.year if _today.month >= 9 else _today.year - 1
            with c_b:
                st.markdown(
                    f'<div style="background:#F5F3FF;border-left:4px solid #7C3AED;'
                    f'border-radius:8px;padding:12px 16px;margin-top:25px;">'
                    f'<span style="color:#7C3AED;font-weight:700;">{_ay}-{_ay+1}</span>'
                    f'<span style="color:#94A3B8;font-size:13px;"> | 36 Hafta | 360 Saat</span></div>',
                    unsafe_allow_html=True)
        elif yr_sel == "Donem Sec":
            with c_b:
                sel_d = st.selectbox("Donem:", ["1. Donem (Hafta 1-18)", "2. Donem (Hafta 19-36)"],
                                      key="ap_y_donem")
            if "1." in sel_d:
                start_w, end_w = 1, min(18, n_weeks)
            else:
                start_w, end_w = 19, min(36, n_weeks)
        else:
            c1, c2 = st.columns(2)
            with c1:
                start_w = st.selectbox("Baslangic:", range(1, n_weeks + 1),
                                        format_func=lambda w: f"Hafta {w}", key="ap_y_s")
            with c2:
                end_w = st.selectbox("Bitis:", range(start_w, n_weeks + 1),
                                      index=min(start_w + 3, n_weeks) - start_w,
                                      format_func=lambda w: f"Hafta {w}", key="ap_y_e")

    # ══════════════════════════════════════════════════
    # 3) BILGI KARTLARI (Dashboard stili)
    # ══════════════════════════════════════════════════
    total_weeks = end_w - start_w + 1
    _days_per_week = 1 if _act_day_filter else 5
    total_hours = total_weeks * _days_per_week * 2
    est_pages = 2 + total_hours + total_weeks
    lvl_label = _CURRICULUM_LEVEL_LABELS.get(sel_level, sel_level)
    cefr = _CURRICULUM_CEFR.get(sel_level, "")

    _stats = [
        ("Sinif", lvl_label, "#1D4ED8", "#EFF6FF"),
        ("CEFR", cefr, "#059669", "#ECFDF5"),
        ("Hafta", str(total_weeks), "#7C3AED", "#F5F3FF"),
        ("Ders Saati", str(total_hours), "#B45309", "#FFFBEB"),
        ("~Sayfa", f"{est_pages}+", "#B91C1C", "#FFF1F2"),
    ]
    _sc = st.columns(len(_stats))
    for _i, (_l, _v, _c, _b) in enumerate(_stats):
        with _sc[_i]:
            st.markdown(
                f'<div style="background:{_b};border-left:4px solid {_c};'
                f'border-radius:10px;padding:14px 16px;text-align:center;">'
                f'<div style="font-size:11px;color:#94A3B8;text-transform:uppercase;font-weight:700;">{_l}</div>'
                f'<div style="font-size:22px;font-weight:800;color:{_c};margin-top:2px;">{_v}</div>'
                f'</div>', unsafe_allow_html=True)

    # ══════════════════════════════════════════════════
    # 4) PDF OLUSTUR BUTONU
    # ══════════════════════════════════════════════════
    st.markdown("<div style='height:8px'></div>", unsafe_allow_html=True)
    _gen_key = f"ap_gen_{sel_level}_{start_w}_{end_w}_{_act_day_filter}_v5"
    if st.session_state.get(_gen_key):
        with st.spinner("PDF olusturuluyor..."):
            if _is_preschool_act:
                from views._gen_activity_book import generate_preschool_activity_book_pdf as _gen_ab_pk
                pdf_bytes = _gen_ab_pk(start_w, end_w, _act_day_filter)
            elif _is_plan_aligned:
                from views._gen_activity_book import generate_activity_book_pdf as _gen_ab
                pdf_bytes = _gen_ab(_grade_num, start_w, end_w, _act_day_filter)
            else:
                pdf_bytes = _cached_premium_activity_pdf(sel_level, start_w, end_w, None)
        if pdf_bytes:
            if _act_day_filter:
                fname = f"etkinlik_{sel_level}_H{start_w}_{_act_day_filter}.pdf"
            elif start_w == end_w:
                fname = f"etkinlik_{sel_level}_H{start_w}.pdf"
            elif start_w == 1 and end_w == n_weeks:
                fname = f"etkinlik_{sel_level}_yillik.pdf"
            else:
                fname = f"etkinlik_{sel_level}_H{start_w}-{end_w}.pdf"
            st.download_button(
                label=f"PDF Indir ({lvl_label} | {plan_type})",
                data=pdf_bytes, file_name=fname, mime="application/pdf",
                key=f"ap_dl_{sel_level}_{start_w}_{end_w}_{_act_day_filter}_v5",
                use_container_width=True)
            _mb = len(pdf_bytes) / 1024 / 1024
            st.markdown(
                f'<div style="background:#ECFDF5;border-left:4px solid #059669;'
                f'border-radius:8px;padding:10px 16px;margin-top:8px;">'
                f'<span style="color:#059669;font-weight:700;">{lvl_label}</span>'
                f'<span style="color:#94A3B8;"> | Hafta {start_w}-{end_w} | {_mb:.1f} MB</span></div>',
                unsafe_allow_html=True)
        else:
            st.error("PDF olusturulamadi.")
    else:
        def _ap_gen_cb(_k):
            st.session_state[_k] = True
        st.button(
            f"PDF Olustur ({lvl_label} | {plan_type})",
            key=f"ap_btn_{sel_level}_{start_w}_{end_w}_{_act_day_filter}_v5",
            use_container_width=True, type="primary",
            on_click=_ap_gen_cb, args=(_gen_key,))


