def _load_coursebook_page_map(grade_int):
    """Kitap sayfa haritasını yükle. Yoksa boş dict döner."""
    import os as _os
    _path = _os.path.join("data", "english", f"coursebook_page_map_{grade_int}.json")
    if _os.path.exists(_path):
        try:
            with open(_path, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            pass
    return {}


def _get_book_page_for_btn(btn_type, unit_num, page_map):
    """btn_type ve ünite numarasından kitap sayfa numarasını döndürür."""
    section = _BTN_TO_BOOK_SECTION.get(btn_type)
    if not section or not page_map:
        return None
    unit_map = page_map.get(str(unit_num), {})
    return unit_map.get(section)


