def _render_ortaokul_english():
    """Ortaokul Ingilizce -- Kolej Dil Programi (5-8. sinif, A2.1->A2.4)."""
    from views.yd_content import _render_unit_outcomes_expander, _render_interactive_lesson_plan_expander, _render_preschool_english
