def _render_activity_pdf_section(grade: int, key_prefix: str):
    """Etkinlik Kitabi PDF — sinif bazli (her sinifin kendi sekmesinde)."""
    import json as _json
    from datetime import date as _date_cls, timedelta as _td_cls

    _kp = f"actpdf_{key_prefix}"

    # ── HEADER ──
    st.markdown(
        '<div style="background:linear-gradient(135deg,#0B0F19 0%,#94A3B8 50%,#0B0F19 100%);'
        'color:#f5e6c8;padding:20px 24px;border-radius:14px;margin-bottom:16px;'
        'border:2px solid #0ea5e9;position:relative;overflow:hidden;'
        'box-shadow:0 4px 20px rgba(14,165,233,.15);">'
        '<div style="position:absolute;top:0;left:0;right:0;height:3px;'
        'background:linear-gradient(90deg,#0ea5e9,#38bdf8,#7dd3fc,#38bdf8,#0ea5e9);"></div>'
        '<h3 style="margin:0;font-size:20px;font-weight:800;color:#38bdf8;">'
        'Etkinlik Kitabi PDF — Diamond 3D Edition</h3>'
        '<p style="margin:4px 0 0;font-size:12px;color:#7dd3fc;">'
        'Plan turune gore etkinlik kitabi PDF olusturun</p>'
        '</div>',
        unsafe_allow_html=True,
    )

    # ── Level ──
    sel_level = "preschool" if grade == 0 else f"grade{grade}"
    _grade_num = str(grade)
    _is_preschool_act = grade == 0
    lvl_label = _CURRICULUM_LEVEL_LABELS.get(sel_level, sel_level)
    cefr = _CURRICULUM_CEFR.get(sel_level, "")

    # ── Akademik hafta ──
    _today = _date_cls.today()
    _day_keys_map = {0: "mon", 1: "tue", 2: "wed", 3: "thu", 4: "fri"}
    _today_day_key = _day_keys_map.get(_today.weekday(), "mon")

    def _get_cur_week_act():
        yr = _today.year if _today.month >= 9 else _today.year - 1
        sep1 = _date_cls(yr, 9, 1)
        dtm = (7 - sep1.weekday()) % 7
        fm = sep1 + _td_cls(days=dtm) if sep1.weekday() != 0 else sep1
        start = fm + _td_cls(weeks=1)
        diff = (_today - start).days
        if diff < 0:
            return 1
        rw = diff // 7 + 1
        if rw > 20:
            rw -= 2
        return max(1, min(rw, 36))

    _cur_week = _get_cur_week_act()

    # ── Plan turu ──
    plan_type = st.selectbox("Plan Turu:", ["Gunluk", "Haftalik", "Yillik"], key=f"{_kp}_plan")

    # ── Veri yukle ──
    _is_plan_aligned = not _is_preschool_act
    _wp_weeks = []
    n_weeks = 36
    weeks_data = []

    if _is_plan_aligned:
        _wp_data_act = {}
        if os.path.exists(_WP_PATH):
            with open(_WP_PATH, "r", encoding="utf-8") as _f:
                _wp_data_act = _json.load(_f)
        _wp_weeks = _wp_data_act.get(_grade_num, [])
        n_weeks = len(_wp_weeks) if _wp_weeks else 36
        if not _wp_weeks:
            weeks_data = _CURRICULUM.get(sel_level, [])
            if weeks_data:
                _is_plan_aligned = False
                n_weeks = len(weeks_data)
            else:
                st.info("Bu sinif icin plan verisi bulunamadi.")
                return
    else:
        weeks_data = _CURRICULUM.get(sel_level, [])
        if weeks_data:
            n_weeks = len(weeks_data)

    def _wk_label_act(w):
        if _is_plan_aligned and _wp_weeks:
            wd = _wp_weeks[w - 1] if w <= len(_wp_weeks) else {}
            return f"Hafta {w}: {wd.get('unit_theme_tr', '')} ({wd.get('unit_theme', '')})"
        if weeks_data and w <= len(weeks_data):
            wd = weeks_data[w - 1]
            return f"Hafta {w}: {wd.get('theme', '')} - {wd.get('theme_tr', '')}"
        return f"Hafta {w}"

    # ── Secim ──
    start_w, end_w = 1, n_weeks
    _act_day_filter = None

    if plan_type == "Gunluk":
        c_a, c_b = st.columns(2)
        with c_a:
            day_sel = st.selectbox("Secim:", ["Bugun", "Tarih Sec"], key=f"{_kp}_g_sel")
        if day_sel == "Bugun":
            start_w = end_w = _cur_week
            _act_day_filter = _today_day_key
            _dn = _DAY_LABELS.get(_today_day_key, (_today_day_key, ""))[0]
            with c_b:
                st.markdown(
                    f'<div style="background:#EFF6FF;border-left:4px solid #1D4ED8;'
                    f'border-radius:8px;padding:12px 16px;margin-top:25px;">'
                    f'<span style="color:#1D4ED8;font-weight:700;">{_dn}</span>'
                    f'<span style="color:#94A3B8;font-size:13px;"> | Hafta {_cur_week} | '
                    f'{_today.strftime("%d.%m.%Y")}</span></div>',
                    unsafe_allow_html=True)
        else:
            _ay_start = _today.year if _today.month >= 9 else _today.year - 1
            _ay_end = _ay_start + 1
            with c_b:
                sel_date = st.date_input(
                    f"Tarih ({_ay_start}-{_ay_end}):",
                    value=_today,
                    min_value=_date_cls(_ay_start, 9, 1),
                    max_value=_date_cls(_ay_end, 6, 30),
                    key=f"{_kp}_g_date")
            _sel_wd = sel_date.weekday()
            if _sel_wd > 4:
                st.warning("Hafta sonu secildi. Cuma gunu kullaniliyor.")
                _sel_wd = 4
            _sel_day_key = _day_keys_map.get(_sel_wd, "mon")
            _sep1 = _date_cls(_ay_start, 9, 1)
            _dtm = (7 - _sep1.weekday()) % 7
            _fm = _sep1 + _td_cls(days=_dtm) if _sep1.weekday() != 0 else _sep1
            _acad_start = _fm + _td_cls(weeks=1)
            _diff_days = (sel_date - _acad_start).days
            _sel_wk = max(1, min((_diff_days // 7 + 1) - (2 if _diff_days // 7 + 1 > 20 else 0), n_weeks)) if _diff_days >= 0 else 1
            start_w = end_w = _sel_wk
            _act_day_filter = _sel_day_key

    elif plan_type == "Haftalik":
        c_a, c_b = st.columns(2)
        with c_a:
            wk_sel = st.selectbox("Secim:", ["Bu Hafta", "Hafta Sec"], key=f"{_kp}_h_sel")
        if wk_sel == "Bu Hafta":
            start_w = end_w = _cur_week
            _mon, _fri = _academic_week_dates(_cur_week)
            _rng = f"{_mon.strftime('%d.%m.%Y')} - {_fri.strftime('%d.%m.%Y')}" if _mon and _fri else ""
            with c_b:
                st.markdown(
                    f'<div style="background:#ECFDF5;border-left:4px solid #059669;'
                    f'border-radius:8px;padding:12px 16px;margin-top:25px;">'
                    f'<span style="color:#059669;font-weight:700;">Hafta {_cur_week}</span>'
                    f'<span style="color:#94A3B8;font-size:13px;"> | {_rng}</span></div>',
                    unsafe_allow_html=True)
        else:
            with c_b:
                sel_wk = st.selectbox("Hafta:", range(1, n_weeks + 1),
                                       index=min(_cur_week - 1, n_weeks - 1),
                                       format_func=_wk_label_act, key=f"{_kp}_h_wk")
            start_w = end_w = sel_wk

    elif plan_type == "Yillik":
        c_a, c_b = st.columns(2)
        with c_a:
            yr_sel = st.selectbox("Secim:", ["Tum Yil", "Donem Sec", "Aralik Sec"], key=f"{_kp}_y_sel")
        if yr_sel == "Tum Yil":
            start_w, end_w = 1, n_weeks
        elif yr_sel == "Donem Sec":
            with c_b:
                sel_d = st.selectbox("Donem:", ["1. Donem (Hafta 1-18)", "2. Donem (Hafta 19-36)"],
                                      key=f"{_kp}_y_donem")
            if "1." in sel_d:
                start_w, end_w = 1, min(18, n_weeks)
            else:
                start_w, end_w = 19, min(36, n_weeks)
        else:
            c1, c2 = st.columns(2)
            with c1:
                start_w = st.selectbox("Baslangic:", range(1, n_weeks + 1),
                                        format_func=lambda w: f"Hafta {w}", key=f"{_kp}_y_s")
            with c2:
                end_w = st.selectbox("Bitis:", range(start_w, n_weeks + 1),
                                      index=min(start_w + 3, n_weeks) - start_w,
                                      format_func=lambda w: f"Hafta {w}", key=f"{_kp}_y_e")

    # ── Bilgi kartlari ──
    total_weeks = end_w - start_w + 1
    _days_per_week = 1 if _act_day_filter else 5
    total_hours = total_weeks * _days_per_week * 2
    est_pages = 2 + total_hours + total_weeks

    _stats = [
        ("Sinif", lvl_label, "#1D4ED8", "#EFF6FF"),
        ("CEFR", cefr, "#059669", "#ECFDF5"),
        ("Hafta", str(total_weeks), "#7C3AED", "#F5F3FF"),
        ("Ders Saati", str(total_hours), "#B45309", "#FFFBEB"),
        ("~Sayfa", f"{est_pages}+", "#B91C1C", "#FFF1F2"),
    ]
    _sc = st.columns(len(_stats))
    for _i, (_l, _v, _c, _b) in enumerate(_stats):
        with _sc[_i]:
            st.markdown(
                f'<div style="background:{_b};border-left:4px solid {_c};'
                f'border-radius:10px;padding:14px 16px;text-align:center;">'
                f'<div style="font-size:11px;color:#94A3B8;text-transform:uppercase;font-weight:700;">{_l}</div>'
                f'<div style="font-size:22px;font-weight:800;color:{_c};margin-top:2px;">{_v}</div>'
                f'</div>', unsafe_allow_html=True)

    # ── PDF olustur ──
    st.markdown("<div style='height:8px'></div>", unsafe_allow_html=True)
    _gen_key = f"{_kp}_gen_{start_w}_{end_w}_{_act_day_filter}_v5"
    if st.session_state.get(_gen_key):
        with st.spinner("PDF olusturuluyor..."):
            if _is_preschool_act:
                from views._gen_activity_book import generate_preschool_activity_book_pdf as _gen_ab_pk
                pdf_bytes = _gen_ab_pk(start_w, end_w, _act_day_filter)
            elif _is_plan_aligned:
                from views._gen_activity_book import generate_activity_book_pdf as _gen_ab
                pdf_bytes = _gen_ab(_grade_num, start_w, end_w, _act_day_filter)
            else:
                pdf_bytes = _cached_premium_activity_pdf(sel_level, start_w, end_w, None)
        if pdf_bytes:
            if _act_day_filter:
                fname = f"etkinlik_{sel_level}_H{start_w}_{_act_day_filter}.pdf"
            elif start_w == end_w:
                fname = f"etkinlik_{sel_level}_H{start_w}.pdf"
            elif start_w == 1 and end_w == n_weeks:
                fname = f"etkinlik_{sel_level}_yillik.pdf"
            else:
                fname = f"etkinlik_{sel_level}_H{start_w}-{end_w}.pdf"
            st.download_button(
                label=f"PDF Indir ({lvl_label} | {plan_type})",
                data=pdf_bytes, file_name=fname, mime="application/pdf",
                key=f"{_kp}_dl_{start_w}_{end_w}_{_act_day_filter}_v5",
                use_container_width=True)
            _mb = len(pdf_bytes) / 1024 / 1024
            st.markdown(
                f'<div style="background:#ECFDF5;border-left:4px solid #059669;'
                f'border-radius:8px;padding:10px 16px;margin-top:8px;">'
                f'<span style="color:#059669;font-weight:700;">{lvl_label}</span>'
                f'<span style="color:#94A3B8;"> | Hafta {start_w}-{end_w} | {_mb:.1f} MB</span></div>',
                unsafe_allow_html=True)
        else:
            st.error("PDF olusturulamadi.")
    else:
        def _ap_gen_cb2(_k):
            st.session_state[_k] = True
        st.button(
            f"PDF Olustur ({lvl_label} | {plan_type})",
            key=f"{_kp}_btn_{start_w}_{end_w}_{_act_day_filter}_v5",
            use_container_width=True, type="primary",
            on_click=_ap_gen_cb2, args=(_gen_key,))


def _render_play_learn_tab(key_prefix: str):
    """Play & Learn Book — Okul Öncesi Etkinlik Kitabı."""
    from views.play_learn_preschool import build_play_learn_pages, build_full_play_learn_book

    _level_key = "preschool"
    _curriculum_data = _CURRICULUM.get(_level_key, [])
    _weeks = _curriculum_data if isinstance(_curriculum_data, list) else _curriculum_data.get("weeks", [])

    if not _weeks:
        st.warning("Okul öncesi müfredat verisi bulunamadı.")
        return

    styled_header(
        "Play & Learn Book",
        "Boyama • Eşleştirme • Labirent • Çizgi tamamlama • Görsel sınıflandırma",
        icon="\U0001F388",
    )

    _pl_c1, _pl_c2 = st.columns([1, 1])
    with _pl_c1:
        _pl_scope = st.radio(
            "Kapsam",
            ["\U0001F4C5 Tek Hafta", "\U0001F4DA Tüm Haftalar"],
            horizontal=True,
            key=f"{key_prefix}_pl_scope",
        )
    with _pl_c2:
        if "\U0001F4C5" in _pl_scope:
            _pl_week = st.number_input(
                "Hafta", min_value=1, max_value=len(_weeks), value=1,
                key=f"{key_prefix}_pl_week",
            )

    if "\U0001F4C5" in _pl_scope:
        _sel_w = None
        for _w in _weeks:
            if _w.get("week") == _pl_week:
                _sel_w = _w
                break
        if _sel_w:
            _th = _sel_w.get("theme", "")
            _th_tr = _sel_w.get("theme_tr", "")
            _vc = _sel_w.get("vocab", [])
            st.markdown(
                f'<div style="background:#fff5f5;border:2px solid #fca5a5;border-radius:10px;'
                f'padding:10px 16px;margin:8px 0;">'
                f'<div style="font-weight:700;color:#dc2626;">Hafta {_pl_week}: {_th}</div>'
                f'<div style="font-size:.82rem;color:#6b7280;">{_th_tr}</div>'
                f'<div style="font-size:.75rem;color:#94a3b8;margin-top:3px;">'
                f'Kelimeler: {", ".join(_vc[:8])}</div></div>',
                unsafe_allow_html=True,
            )

        if st.button("\U0001F3A8 Etkinlikleri Oluştur", key=f"{key_prefix}_pl_gen",
                     type="primary", use_container_width=True):
            st.session_state[f"{key_prefix}_pl_ok"] = True

        if st.session_state.get(f"{key_prefix}_pl_ok"):
            _pages = build_play_learn_pages(_pl_week, _weeks)
            if not _pages:
                st.error("Bu hafta için etkinlik üretilemedi.")
                return
            _pt = st.tabs([f"\U0001F4D6 Sayfa {i+1}" for i in range(len(_pages))])
            for _pi, _ptab in enumerate(_pt):
                with _ptab:
                    st.components.v1.html(_pages[_pi], height=1100, scrolling=True)
            _full = "\n<hr style='page-break-after:always;'>\n".join(_pages)
            st.download_button(
                "\U0001F4E5 HTML Olarak İndir",
                data=_full.encode("utf-8"),
                file_name=f"play_learn_week{_pl_week}.html",
                mime="text/html",
                key=f"{key_prefix}_pl_dl",
                use_container_width=True,
            )
    else:
        st.info(f"Okul Öncesi — {len(_weeks)} hafta için Play & Learn Book üretilecek.")
        if st.button("\U0001F4DA Tüm Kitabı Oluştur", key=f"{key_prefix}_pl_gen_all",
                     type="primary", use_container_width=True):
            with st.spinner("Tüm haftalar için etkinlikler hazırlanıyor..."):
                _all_data = build_full_play_learn_book(_weeks)
            if not _all_data:
                st.error("Üretilemedi.")
                return
            st.success(f"{len(_all_data)} hafta için Play & Learn Book hazır!")
            for item in _all_data:
                with st.expander(f"Hafta {item['week']}: {item['theme']}", expanded=False):
                    _sub_tabs = st.tabs([f"Sayfa {j+1}" for j in range(len(item['pages']))])
                    for _j, _st2 in enumerate(_sub_tabs):
                        with _st2:
                            st.components.v1.html(item["pages"][_j], height=1100, scrolling=True)
            _all_html_parts = []
            for item in _all_data:
                for pg in item["pages"]:
                    _all_html_parts.append(pg)
            _full_all = "\n<hr style='page-break-after:always;'>\n".join(_all_html_parts)
            st.download_button(
                f"\U0001F4E5 Tüm Kitabı İndir ({len(_all_data)} hafta)",
                data=_full_all.encode("utf-8"),
                file_name="play_learn_full.html",
                mime="text/html",
                key=f"{key_prefix}_pl_dl_all",
                use_container_width=True,
            )


