_KDG_USERS_PATH = os.path.join("data", "english", "kdg_users.json")


def _kdg_load_users() -> list[dict]:
    if os.path.exists(_KDG_USERS_PATH):
        try:
            with open(_KDG_USERS_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
        except Exception:
            return []
    return []


def _kdg_save_users(users: list[dict]):
    os.makedirs(os.path.dirname(_KDG_USERS_PATH), exist_ok=True)
    with open(_KDG_USERS_PATH, "w", encoding="utf-8") as f:
        json.dump(users, f, ensure_ascii=False, indent=2)


def _kdg_get_user(username: str) -> dict | None:
    for u in _kdg_load_users():
        if u.get("username", "").lower() == username.lower():
            return u
    return None


def _kdg_update_user(username: str, updates: dict):
    users = _kdg_load_users()
    for u in users:
        if u.get("username", "").lower() == username.lower():
            u.update(updates)
            u["last_login"] = datetime.now().isoformat()
            break
    _kdg_save_users(users)


def _kdg_login_screen() -> str | None:
    """Bireysel giriş/kayıt ekranı. Giriş yapan kullanıcı adını döner."""
    # Zaten giriş yapılmış mı?
    if st.session_state.get("kdg_user"):
        return st.session_state["kdg_user"]

    st.markdown(
        '<div style="background:linear-gradient(135deg,#1e1b4b,#312e81);color:#fff;'
        'padding:28px;border-radius:18px;text-align:center;margin-bottom:20px">'
        '<div style="font-size:2.5rem;margin-bottom:8px">🌟</div>'
        '<div style="font-size:1.6rem;font-weight:800;letter-spacing:.5px">Kişisel Dil Gelişimi</div>'
        '<div style="font-size:.92rem;opacity:.8;margin-top:6px">'
        'CEFR Uyumlu A1→C2 İngilizce Öğrenim Platformu</div>'
        '<div style="font-size:.78rem;opacity:.6;margin-top:8px">'
        'Bireysel hesabınızla giriş yapın — ilerlemeniz kaydedilir</div>'
        '</div>', unsafe_allow_html=True,
    )

    tab_login, tab_register = st.tabs(["🔑 Giriş Yap", "📝 Yeni Kayıt"])

    with tab_login:
        un = st.text_input("Kullanıcı Adı", key="kdg_login_un", placeholder="Kullanıcı adınız...")
        pw = st.text_input("Şifre", type="password", key="kdg_login_pw", placeholder="Şifreniz...")
        if st.button("🔑 Giriş Yap", key="kdg_login_btn", type="primary", use_container_width=True):
            if not un or not pw:
                st.error("Kullanıcı adı ve şifre gereklidir.")
            else:
                user = _kdg_get_user(un)
                if user and user.get("password") == pw:
                    st.session_state["kdg_user"] = un
                    _kdg_update_user(un, {})
                    st.success(f"✅ Hoş geldin, {user.get('display_name', un)}! Kaldığın yerden devam edebilirsin.")
                    st.rerun()
                else:
                    st.error("❌ Kullanıcı adı veya şifre hatalı.")

    with tab_register:
        from datetime import datetime as _dt
        reg_name = st.text_input("Ad Soyad", key="kdg_reg_name", placeholder="Tam adınız...")
        reg_un = st.text_input("Kullanıcı Adı Seç", key="kdg_reg_un", placeholder="Benzersiz kullanıcı adı...")
        reg_pw = st.text_input("Şifre Belirle", type="password", key="kdg_reg_pw", placeholder="En az 4 karakter...")
        reg_pw2 = st.text_input("Şifre Tekrar", type="password", key="kdg_reg_pw2", placeholder="Şifrenizi doğrulayın...")
        reg_level = st.selectbox("Başlangıç Seviyesi (tahmini)", _CEFR_LEVELS, index=0, key="kdg_reg_level")
        reg_goal = st.text_input("Hedefin (opsiyonel)", placeholder="Ör: B2 seviyesine ulaşmak...", key="kdg_reg_goal")

        if st.button("📝 Kayıt Ol", key="kdg_reg_btn", type="primary", use_container_width=True):
            if not reg_name or not reg_un or not reg_pw:
                st.error("Ad, kullanıcı adı ve şifre zorunludur.")
            elif len(reg_pw) < 4:
                st.error("Şifre en az 4 karakter olmalı.")
            elif reg_pw != reg_pw2:
                st.error("Şifreler eşleşmiyor.")
            elif _kdg_get_user(reg_un):
                st.error("Bu kullanıcı adı zaten alınmış.")
            else:
                users = _kdg_load_users()
                new_user = {
                    "username": reg_un,
                    "password": reg_pw,
                    "display_name": reg_name,
                    "start_level": reg_level,
                    "current_level": reg_level,
                    "goal": reg_goal,
                    "registered_at": _dt.now().isoformat(),
                    "last_login": _dt.now().isoformat(),
                    "total_sessions": 0,
                    "total_xp": 0,
                    "writing_history": [],
                    "speaking_history": [],
                    "dialog_history": [],
                    "vocab_history": [],
                    "quiz_scores": [],
                    "streak_days": 0,
                    "last_active_date": "",
                    "notes": "",
                }
                users.append(new_user)
                _kdg_save_users(users)
                st.session_state["kdg_user"] = reg_un
                st.success(f"✅ Hoş geldin, {reg_name}! Hesabın oluşturuldu. Öğrenmeye başla!")
                st.rerun()

    return None


def _render_kdg_tab():
    """Kişisel Dil Gelişimi — CEFR Uyumlu Diamond Premium öğrenim sistemi."""
    # ── Sistem oturumundan kullanıcı al (ayrı giriş yok) ──
    _sys_user = st.session_state.get("auth_user", {})
    kdg_user = _sys_user.get("username", "user")
    display_name = _sys_user.get("name", kdg_user)
    st.session_state["kdg_user"] = kdg_user

    # KDG profili yoksa otomatik oluştur (XP/istatistik takibi için)
    user_data = _kdg_get_user(kdg_user)
    if not user_data:
        from datetime import datetime as _dt
        users = _kdg_load_users()
        users.append({
            "username": kdg_user,
            "password": "",
            "display_name": display_name,
            "start_level": "A1",
            "current_level": "A1",
            "goal": "",
            "registered_at": _dt.now().isoformat(),
            "last_login": _dt.now().isoformat(),
            "total_sessions": 0,
            "total_xp": 0,
            "writing_history": [],
            "speaking_history": [],
            "dialog_history": [],
            "vocab_history": [],
            "quiz_scores": [],
            "streak_days": 0,
            "last_active_date": "",
        })
        _kdg_save_users(users)
        user_data = _kdg_get_user(kdg_user)

    # Oturum sayacı güncelle
    if user_data and not st.session_state.get("kdg_session_counted"):
        _kdg_update_user(kdg_user, {
            "total_sessions": user_data.get("total_sessions", 0) + 1,
            "last_active_date": datetime.now().strftime("%Y-%m-%d"),
        })
        st.session_state["kdg_session_counted"] = True

    # Profil bar
    cur_level = user_data.get("current_level", "A1") if user_data else "A1"
    sessions = user_data.get("total_sessions", 0) if user_data else 0
    xp = user_data.get("total_xp", 0) if user_data else 0
    st.markdown(
        f'<div style="background:linear-gradient(135deg,#1e1b4b,#312e81);color:#fff;'
        f'padding:12px 20px;border-radius:12px;margin-bottom:12px;'
        f'display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">'
        f'<div style="display:flex;align-items:center;gap:10px">'
        f'<span style="font-size:1.5rem">👤</span>'
        f'<div><b style="font-size:1rem">{display_name}</b>'
        f'<div style="font-size:.75rem;opacity:.7">Seviye: {cur_level} | {sessions} oturum | {xp} XP</div></div>'
        f'</div>'
        f'<div style="display:flex;gap:14px;font-size:.8rem;opacity:.8">'
        f'<span>🔥 Seri: {user_data.get("streak_days", 0)} gün</span>'
        f'<span>🎯 {user_data.get("goal", "Belirlenmedi")}</span>'
        f'</div>'
        f'</div>', unsafe_allow_html=True,
    )

    # ── Ana sekmeler ──
    kdg_sub = st.tabs([
        "🌟 KDG Platform",
        "🤖 AI Yazı Analizi",
        "🎤 AI Konuşma",
        "💬 AI Diyalog",
        "📚 AI Kelime",
        "📊 İstatistik & Plan",
        "⚙️ Profilim",
    ])

    with kdg_sub[0]:
        from views.kdg_engine import build_kdg_html
        st.components.v1.html(build_kdg_html(kdg_user), height=900, scrolling=True)
        styled_info_banner(
            f"**Hoş geldin, {display_name}!** İlerleme tarayıcında kaydedilir. "
            f"AI sekmelerindeki çalışmalar sunucuya kaydedilir.",
            "info",
        )

    with kdg_sub[1]:
        _kdg_ai_writing()
        _kdg_save_activity(kdg_user, "writing")

    with kdg_sub[2]:
        _kdg_ai_speaking()
        _kdg_save_activity(kdg_user, "speaking")

    with kdg_sub[3]:
        _kdg_ai_dialog()

    with kdg_sub[4]:
        _kdg_ai_vocab()

    with kdg_sub[5]:
        _kdg_ai_stats()

    with kdg_sub[6]:
        _kdg_profile_tab(kdg_user)


