# KDG AI — YAZMA ANALİZİ
# ══════════════════════════════════════════════════════════════════════════════
def _kdg_get_openai():
    """OpenAI client al."""
    api_key = os.environ.get("OPENAI_API_KEY", "")
    if not api_key:
        try:
            api_key = st.secrets.get("OPENAI_API_KEY", "")
        except Exception:
            pass
    if not api_key:
        return None
    try:
        from openai import OpenAI
        return OpenAI(api_key=api_key)
    except Exception:
        return None


def _kdg_ai_call(system: str, user: str, max_tokens: int = 1200, temp: float = 0.4) -> str:
    """GPT-4o-mini çağrısı."""
    client = _kdg_get_openai()
    if not client:
        return "[OPENAI_API_KEY bulunamadı]"
    try:
        r = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[{"role": "system", "content": system}, {"role": "user", "content": user}],
            max_tokens=max_tokens, temperature=temp,
        )
        return r.choices[0].message.content or ""
    except Exception as e:
        return f"[Hata: {e}]"


_CEFR_LEVELS = ["A1", "A2", "B1", "B2", "C1", "C2"]


