# KDG AI — DİYALOG SİMÜLASYONU
# ══════════════════════════════════════════════════════════════════════════════
def _kdg_ai_dialog():
    """AI ile interaktif İngilizce konuşma pratiği."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#dc2626,#f87171);color:#fff;'
        'padding:18px 24px;border-radius:14px;margin-bottom:18px;">'
        '<div style="font-size:1.3rem;font-weight:700">💬 AI Diyalog Pratiği</div>'
        '<div style="font-size:.88rem;opacity:.85;margin-top:4px">'
        'GPT-4o ile gerçek zamanlı İngilizce sohbet pratiği yapın — seviyenize uygun, hata düzeltmeli</div>'
        '</div>', unsafe_allow_html=True,
    )

    c1, c2 = st.columns(2)
    with c1:
        level = st.selectbox("Seviye", _CEFR_LEVELS, index=1, key="kdg_dlg_level")
    with c2:
        scenario = st.selectbox("Senaryo", [
            "🏪 Alışveriş — At the shop",
            "🍕 Restoran — Ordering food",
            "✈️ Havalimanı — At the airport",
            "🏨 Otel — Hotel check-in",
            "🏥 Doktor — At the doctor",
            "📞 Telefon — Phone call",
            "🎓 Okul — School registration",
            "🗺️ Yol Tarifi — Asking directions",
            "👋 Tanışma — Meeting someone new",
            "🎯 Serbest — Free conversation",
        ], key="kdg_dlg_scenario")

    # Chat geçmişi
    if "kdg_chat" not in st.session_state:
        st.session_state["kdg_chat"] = []

    if st.button("🔄 Yeni Diyalog Başlat", key="kdg_dlg_new"):
        st.session_state["kdg_chat"] = []
        with st.spinner("AI partner hazırlanıyor..."):
            opening = _kdg_ai_call(
                system=(
                    f"You are a friendly English conversation partner. Level: CEFR {level}. "
                    f"Scenario: {scenario}.\n"
                    f"Speak ONLY in English at {level} level. Keep sentences appropriate for {level}.\n"
                    f"Start the conversation with a greeting or opening line for this scenario. "
                    f"One sentence only. Be natural and friendly."
                ),
                user="Start the conversation.",
                max_tokens=100, temp=0.7,
            )
        st.session_state["kdg_chat"].append({"role": "ai", "text": opening})
        st.rerun()

    # Chat gösterimi
    for msg in st.session_state.get("kdg_chat", []):
        if msg["role"] == "ai":
            st.markdown(
                f'<div style="background:linear-gradient(135deg,#1e3a5f,#2563eb);color:#fff;'
                f'border-radius:14px 14px 14px 4px;padding:12px 16px;margin:6px 40px 6px 0;font-size:13px">'
                f'🤖 <b>AI Partner:</b> {msg["text"]}</div>', unsafe_allow_html=True,
            )
        elif msg["role"] == "user":
            st.markdown(
                f'<div style="background:linear-gradient(135deg,#166534,#22c55e);color:#fff;'
                f'border-radius:14px 14px 4px 14px;padding:12px 16px;margin:6px 0 6px 40px;font-size:13px;text-align:right">'
                f'👤 <b>Sen:</b> {msg["text"]}</div>', unsafe_allow_html=True,
            )
        elif msg["role"] == "correction":
            st.markdown(
                f'<div style="background:rgba(251,191,36,.08);border:1px solid rgba(251,191,36,.3);'
                f'border-radius:10px;padding:10px 14px;margin:2px 20px;font-size:11px;color:#fbbf24">'
                f'📝 <b>Düzeltme:</b> {msg["text"]}</div>', unsafe_allow_html=True,
            )

    # Kullanıcı mesajı
    user_msg = st.text_input("Mesajınız (İngilizce):", placeholder="Type in English...", key="kdg_dlg_input")
    if user_msg and st.button("📤 Gönder", key="kdg_dlg_send", type="primary"):
        st.session_state["kdg_chat"].append({"role": "user", "text": user_msg})

        history = "\n".join(
            f"{'AI' if m['role']=='ai' else 'Student'}: {m['text']}"
            for m in st.session_state["kdg_chat"]
            if m["role"] in ("ai", "user")
        )

        with st.spinner("AI yanıt hazırlıyor..."):
            response = _kdg_ai_call(
                system=(
                    f"You are an English conversation partner at CEFR {level} level.\n"
                    f"Scenario: {scenario}\n\n"
                    f"RULES:\n"
                    f"1. Respond naturally IN ENGLISH at {level} level (1-2 sentences)\n"
                    f"2. After your response, on a NEW LINE write 'CORRECTION:' followed by:\n"
                    f"   - If the student made errors: explain each error in TURKISH and give the correct form\n"
                    f"   - If no errors: write 'Harika! Hatasız yazdınız. ✅'\n"
                    f"3. Keep conversation flowing naturally\n"
                    f"4. If student writes in Turkish, gently ask them to try in English"
                ),
                user=f"CONVERSATION HISTORY:\n{history}",
                max_tokens=400, temp=0.6,
            )

        # Parse response and correction
        if "CORRECTION:" in response:
            parts = response.split("CORRECTION:", 1)
            ai_reply = parts[0].strip()
            correction = parts[1].strip()
        else:
            ai_reply = response.strip()
            correction = ""

        st.session_state["kdg_chat"].append({"role": "ai", "text": ai_reply})
        if correction:
            st.session_state["kdg_chat"].append({"role": "correction", "text": correction})
        st.rerun()

    # Diyalog sonunda rapor
    chat_msgs = [m for m in st.session_state.get("kdg_chat", []) if m["role"] == "user"]
    if len(chat_msgs) >= 5:
        if st.button("📊 Diyalog Raporu Al", key="kdg_dlg_report"):
            history = "\n".join(
                f"{'AI' if m['role']=='ai' else 'Student' if m['role']=='user' else 'Correction'}: {m['text']}"
                for m in st.session_state["kdg_chat"]
            )
            with st.spinner("Diyalog raporu hazırlanıyor..."):
                report = _kdg_ai_call(
                    system=(
                        "You are a CEFR examiner reviewing a student-AI conversation. "
                        "Provide a comprehensive report in TURKISH.\n\n"
                        "FORMAT:\n"
                        "## 📊 DIYALOG SKORU (0-100)\n\n"
                        "## 🎯 CEFR SEVİYE TAHMİNİ\n\n"
                        "## ✅ GÜÇLÜ YANLAR\n- Kelime çeşitliliği, yapı kullanımı, iletişim becerisi\n\n"
                        "## ❌ TEKRARLAYAN HATALAR\n- Pattern olarak gördüğün hataları listele\n\n"
                        "## 📈 GELİŞİM ÖNERİLERİ\n- 5 somut pratik önerisi\n\n"
                        "## 🏆 GENEL DEĞERLENDİRME\n- 2-3 cümle özet"
                    ),
                    user=f"Target level: {level}\nScenario: {scenario}\n\nFULL CONVERSATION:\n{history}",
                    max_tokens=1200,
                )
            st.markdown(f"""<div style="background:linear-gradient(135deg,#0B0F19,#94A3B8);border-radius:14px;
                padding:20px;border-left:4px solid #f59e0b;color:#e2e8f0;font-size:13px;line-height:1.8">
                {report.replace(chr(10), '<br>')}
            </div>""", unsafe_allow_html=True)


