        ".end.show{display:flex}.end h2{font-size:34px;color:#e9d5ff;margin:8px}.end p{color:#c4b5fd;font-size:18px}"
        ".rbtn{padding:14px 40px;font-size:18px;font-weight:700;border-radius:50px;border:2px solid rgba(196,181,253,.3);"
        "cursor:pointer;color:#fff;margin-top:16px;background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 20px rgba(124,58,237,.4);transition:all .3s}.rbtn:hover{transform:scale(1.08)}"
        "</style></head><body><div class='w'><div class='ct'>"
        "<div class='hdr'><h2>&#127912; Color Hunt</h2></div>"
        "<div class='score' id='sc'>0 / 6</div>"
        "<div class='prog' id='pg'></div>"
        "<div class='prompt' id='pr'>Find RED!</div>"
