        ".anim.no{animation:sh .4s ease}"
        "@keyframes walk{0%,100%{transform:translateY(0)}50%{transform:translateY(-8px)}}"
        "@keyframes bounce{0%{transform:scale(1)}50%{transform:scale(1.3)}100%{transform:scale(1)}}"
        "@keyframes sh{0%,100%{transform:translateX(0)}25%{transform:translateX(-8px)}75%{transform:translateX(8px)}}"
        ".prog{display:flex;gap:5px;margin:8px 0;flex-wrap:wrap;justify-content:center}"
