        "</div>"
        "<div class='end' id='ed'><div style='font-size:80px'>&#127942;</div>"
        "<h2 id='et'></h2><p id='es'></p>"
        "<div class='rbtn' onclick='init()'>Play Again</div></div></div>"
        "<script>"
        "var A=[['&#128054;','DOG'],['&#128049;','CAT'],['&#128048;','RABBIT'],['&#128059;','BEAR'],"
        "['&#128056;','FROG'],['&#128053;','MONKEY'],['&#128055;','PIG'],['&#128046;','COW']];"
        "var pool,qi=0,pts=0,cur,TOT=8,AC=new(window.AudioContext||window.webkitAudioContext);"
