        "function pick(o,el){if(el.classList.contains('ok')||el.classList.contains('no'))return;"
        "if(o[1]===cur[1]){el.classList.add('ok');pts++;snd(523,.3);snd(659,.3);"
        "setTimeout(function(){qi++;show()},1000)}else{el.classList.add('no');snd(200,.3)}}"
        "function endG(){document.getElementById('et').textContent="
        "pts>=7?'Amazing! \\u{1F929}':pts>=5?'Good Job! \\u{1F60A}':'Try Again! \\u{1F4AA}';"
        "document.getElementById('es').textContent=pts+' / '+TOT+' correct';"
        "document.getElementById('ed').classList.add('show')}"
        "init();</script></body></html>"
