        "b.onclick=function(){pick(o,b)};op.appendChild(b)});"
        "setTimeout(function(){spk(cur.q)},300)}"
        "function pick(o,el){if(el.classList.contains('ok')||el.classList.contains('no'))return;"
        "if(o===cur.a){el.classList.add('ok');pts++;snd(523,.3);snd(659,.3);"
