        "<script>"
        "var ST=[{em:'&#128054;',txt:'The dog is playing in the park. The dog is happy!',q:'Where is the dog?',a:'Park',b:'School'},"
        "{em:'&#128049;',txt:'The cat drinks milk. The cat is white.',q:'What does the cat drink?',a:'Milk',b:'Water'},"
