        "function init(){document.getElementById('ed').classList.remove('show');pool=shuf(OP.slice());qi=0;pts=0;"
        "var pg=document.getElementById('pg');pg.innerHTML='';"
        "for(var i=0;i<TOT;i++){var d=document.createElement('div');d.className='dot';d.id='d'+i;pg.appendChild(d)}show()}"
        "function show(){if(qi>=TOT){endG();return}cur=pool[qi];"
        "document.getElementById('sc').textContent=pts+' / '+TOT;"
        "for(var i=0;i<TOT;i++){var d=document.getElementById('d'+i);d.className='dot';"
        "if(i<qi)d.classList.add('dn');if(i===qi)d.classList.add('cur')}"
        "document.getElementById('fw').textContent=cur.w;"
        "document.getElementById('fe').innerHTML=cur.e;"
