        "<div class='rbtn' onclick='init()'>Play Again</div></div></div>"
        "<script>"
        "var BC=[{c:'#ef4444',n:'RED'},{c:'#3b82f6',n:'BLUE'},{c:'#22c55e',n:'GREEN'},"
        "{c:'#eab308',n:'YELLOW'},{c:'#f97316',n:'ORANGE'},{c:'#a855f7',n:'PURPLE'}];"
        "var pool,qi=0,pts=0,cur,TOT=6,AC=new(window.AudioContext||window.webkitAudioContext);"
        "function snd(f,d){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}var o=AC.createOscillator(),g=AC.createGain();o.connect(g);g.connect(AC.destination);"
        "o.frequency.value=f;g.gain.value=.15;o.start();g.gain.exponentialRampToValueAtTime(.001,AC.currentTime+d);o.stop(AC.currentTime+d)}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';u.rate=.8;"
        "speechSynthesis.cancel();speechSynthesis.speak(u)}catch(e){}}"
        "function shuf(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var t=a[i];a[i]=a[j];a[j]=t}return a}"
        "function sayColor(){spk(cur.n)}"
        "function init(){document.getElementById('ed').classList.remove('show');pool=shuf(BC.slice());qi=0;pts=0;"
        "var pg=document.getElementById('pg');pg.innerHTML='';"
        "for(var i=0;i<TOT;i++){var d=document.createElement('div');d.className='dot';d.id='d'+i;pg.appendChild(d)}show()}"
        "function show(){if(qi>=TOT){endG();return}cur=pool[qi];"
        "document.getElementById('sc').textContent=pts+' / '+TOT;"
        "for(var i=0;i<TOT;i++){var d=document.getElementById('d'+i);d.className='dot';"
        "if(i<qi)d.classList.add('dn');if(i===qi)d.classList.add('cur')}"
        "document.getElementById('pr').textContent='Tap the '+cur.n+' balloon!';"
        "var bl=document.getElementById('bl');bl.innerHTML='';var opts=shuf(BC.slice());"
        "opts.forEach(function(o){var b=document.createElement('div');b.className='bal';"
