        "speechSynthesis.cancel();speechSynthesis.speak(u)}catch(e){}}"
        "function shuf(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var t=a[i];a[i]=a[j];a[j]=t}return a}"
