        "<title>Dialogue Choose</title><style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "body{font-family:'Segoe UI',sans-serif;background:linear-gradient(135deg,#1a0533,#0d0221);color:#e9d5ff;min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center}"
