        "<button class='ebtn' onclick='init()'>Play Again</button></div>"
        "<script>"
        "var AC=new(window.AudioContext||window.webkitAudioContext)();"
        "function snd(f,d){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}var o=AC.createOscillator(),g=AC.createGain();o.connect(g);g.connect(AC.destination);o.type='sine';o.frequency.value=f;g.gain.value=.15;o.start();g.gain.exponentialRampToValueAtTime(.001,AC.currentTime+d);o.stop(AC.currentTime+d)}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';u.rate=.8;speechSynthesis.cancel();speechSynthesis.speak(u)}catch(e){}}"
        "var DATA=["
        "{s:'🏪 At the store: You want to buy apples.',a:['I would like some apples, please.','The weather is nice.','I can run fast.'],c:0},"
        "{s:'🏫 At school: The teacher asks your name.',a:['I like pizza.','My name is Alex.','It is raining.'],c:1},"
        "{s:'🍽️ At a restaurant: You are hungry.',a:['Can I see the menu, please?','I have a dog.','She is my friend.'],c:0},"
        "{s:'🏥 At the doctor: Your head hurts.',a:['I like books.','My head hurts.','It is Monday.'],c:1},"
        "{s:'🚌 On the bus: You want to sit down.',a:['Excuse me, is this seat free?','I have two cats.','The sky is blue.'],c:0},"
        "{s:'📞 On the phone: Someone calls you.',a:['I can swim.','Hello, who is calling?','The ball is red.'],c:1},"
        "{s:'🎂 At a birthday party: Someone gives you a gift.',a:['It is cold today.','Thank you very much!','I go to school.'],c:1},"
        "{s:'🗺️ On the street: You are lost.',a:['Excuse me, where is the park?','I like ice cream.','She can dance.'],c:0}];"
        "var rnd=0,score=0,canClick=true;"
        "function init(){rnd=0;score=0;document.getElementById('endScr').classList.remove('show');next()}"
        "function next(){if(rnd>=8){endGame();return}canClick=true;var d=DATA[rnd];"
