        "document.getElementById('rn').textContent=rnd+1;document.getElementById('sc').textContent=score;"
        "var ch=document.getElementById('chs');ch.innerHTML='';"
        "d.a.forEach(function(a,i){var b=document.createElement('div');b.className='ch';b.textContent=a;"
        "b.onclick=function(){pick(b,i===d.c,a)};ch.appendChild(b)})}"
        "function pick(el,ok,txt){if(!canClick)return;canClick=false;"
        "if(ok){el.classList.add('ok');score++;snd(523,.2);spk(txt);document.getElementById('sc').textContent=score}"
        "else{el.classList.add('no');snd(180,.3)}"
        "rnd++;setTimeout(next,1200)}"
        "function endGame(){document.getElementById('et').textContent='Great Roleplay!';document.getElementById('es').textContent='Score: '+score+' / 8';"
        "document.getElementById('endScr').classList.add('show');spk('Awesome! Score '+score+' out of 8')}"
