        "{s:'This is ___ umbrella.',o:['a','an','the'],c:1},"
        "{s:'He ___ swim very fast.',o:['can','can\\'t','is'],c:0},"
        "{s:'The dogs ___ in the garden.',o:['is','are','am'],c:1},"
        "{s:'I ___ a student.',o:['is','are','am'],c:2},"
        "{s:'She ___ ride a bike yet.',o:['can','can\\'t','are'],c:1},"
        "{s:'There is ___ egg on the table.',o:['a','an','the'],c:1},"
        "{s:'We ___ happy today.',o:['is','are','am'],c:1}];"
        "var rnd=0,score=0,canClick=true;"
