        ".gbox{background:rgba(168,85,247,.13);border:2px solid rgba(168,85,247,.4);border-radius:20px;padding:30px;max-width:480px;width:90%;text-align:center}"
        "h1{font-size:1.5em;margin-bottom:8px;color:#c084fc}"
        ".info{font-size:.95em;margin-bottom:10px;color:#d8b4fe}"
        ".request{font-size:1.2em;margin:12px 0;color:#fbbf24;background:rgba(168,85,247,.12);border-radius:12px;padding:12px}"
        ".grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin:14px 0}"
