        ".ebtn{margin-top:18px;padding:12px 36px;font-size:1.1em;border-radius:12px;border:none;background:linear-gradient(135deg,#a855f7,#7c3aed);color:#fff;cursor:pointer}"
        "</style></head><body><div class='gbox'>"
        "<h1>Synonym Spark ✨</h1>"
