        "<div class='opts' id='opts'></div></div>"
        "<div id='endScr'><h1 id='et'></h1><p id='es' style='font-size:1.2em;margin-top:10px;color:#d8b4fe'></p>"
        "<button class='ebtn' onclick='init()'>Play Again</button></div>"
        "<script>"
        "var AC=new(window.AudioContext||window.webkitAudioContext)();"
        "function snd(f,d){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}var o=AC.createOscillator(),g=AC.createGain();o.connect(g);g.connect(AC.destination);o.type='sine';o.frequency.value=f;g.gain.value=.15;o.start();g.gain.exponentialRampToValueAtTime(.001,AC.currentTime+d);o.stop(AC.currentTime+d)}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';u.rate=.8;speechSynthesis.cancel();speechSynthesis.speak(u)}catch(e){}}"
        "var DATA=["
        "{w:'big',ans:'large',opts:['small','large','fast','old']},"
