        "{w:'fast',ans:'quick',opts:['slow','quick','heavy','dark']},"
        "{w:'small',ans:'tiny',opts:['huge','tiny','loud','soft']},"
        "{w:'sad',ans:'unhappy',opts:['unhappy','bright','warm','funny']},"
