        "{w:'begin',ans:'start',opts:['end','start','sleep','walk']},"
        "{w:'angry',ans:'mad',opts:['calm','mad','nice','shy']},"
        "{w:'scared',ans:'afraid',opts:['brave','afraid','proud','kind']}];"
