# ── FUNC 18: Reading Karaoke ──
def _build_elem_reading_karaoke_html():
    return (
        "<!DOCTYPE html><html lang='en'><head><meta charset='UTF-8'>"
        "<meta name='viewport' content='width=device-width,initial-scale=1'>"
        "<title>Reading Karaoke</title><style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "body{font-family:'Segoe UI',sans-serif;background:linear-gradient(135deg,#1a0533,#0d0221);color:#e9d5ff;min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center}"
        ".gbox{background:rgba(168,85,247,.13);border:2px solid rgba(168,85,247,.4);border-radius:20px;padding:30px;max-width:540px;width:90%;text-align:center}"
        "h1{font-size:1.5em;margin-bottom:8px;color:#c084fc}"
        ".info{font-size:.95em;margin-bottom:12px;color:#d8b4fe}"
        ".sentence{font-size:1.3em;line-height:2;margin:18px 0;min-height:60px;display:flex;flex-wrap:wrap;gap:6px;justify-content:center}"
        ".sentence span{padding:4px 8px;border-radius:6px;transition:.3s}"
        ".sentence span.hl{background:rgba(168,85,247,.4);color:#fbbf24;transform:scale(1.1)}"
        ".sentence span.done{color:#22c55e}"
        ".btns{display:flex;gap:12px;justify-content:center;margin:14px 0}"
        ".abtn{padding:12px 28px;font-size:1.05em;border-radius:12px;border:none;background:linear-gradient(135deg,#a855f7,#7c3aed);color:#fff;cursor:pointer}"
        ".abtn:hover{background:linear-gradient(135deg,#c084fc,#a855f7)}"
        ".abtn:disabled{opacity:.4;cursor:not-allowed}"
        "#endScr{display:none;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(13,2,33,.93);z-index:99;flex-direction:column;align-items:center;justify-content:center}"
        "#endScr.show{display:flex}"
        ".ebtn{margin-top:18px;padding:12px 36px;font-size:1.1em;border-radius:12px;border:none;background:linear-gradient(135deg,#a855f7,#7c3aed);color:#fff;cursor:pointer}"
        "</style></head><body><div class='gbox'>"
        "<h1>Reading Karaoke 🎤</h1>"
        "<div class='info'>Sentence <span id='sn'>1</span>/6</div>"
        "<div class='sentence' id='sent'></div>"
        "<div class='btns'><button class='abtn' id='playBtn' onclick='playSentence()'>▶ Play</button>"
        "<button class='abtn' id='nextBtn' onclick='nextSentence()' disabled>Next →</button></div></div>"
        "<div id='endScr'><h1 id='et'>Reading Complete!</h1><p id='es' style='font-size:1.2em;margin-top:10px;color:#d8b4fe'>You read all 6 sentences!</p>"
        "<button class='ebtn' onclick='init()'>Read Again</button></div>"
        "<script>"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';u.rate=.8;speechSynthesis.cancel();speechSynthesis.speak(u);return u}catch(e){return null}}"
        "var SENTS=['The cat sits on the mat.','I like to eat red apples.','She goes to school every day.',"
        "'The bird sings a happy song.','We play in the park together.','He reads a book before bed.'];"
        "var si=0,playing=false;"
        "function init(){si=0;document.getElementById('endScr').classList.remove('show');showSentence()}"
        "function showSentence(){if(si>=6){document.getElementById('endScr').classList.add('show');spk('Great reading!');return}"
        "document.getElementById('sn').textContent=si+1;playing=false;"
        "document.getElementById('playBtn').disabled=false;document.getElementById('nextBtn').disabled=true;"
        "var words=SENTS[si].split(' '),box=document.getElementById('sent');box.innerHTML='';"
        "words.forEach(function(w,i){var s=document.createElement('span');s.textContent=w;s.id='w'+i;box.appendChild(s)})}"
        "function playSentence(){if(playing)return;playing=true;document.getElementById('playBtn').disabled=true;"
        "var words=SENTS[si].split(' '),idx=0;"
        "spk(SENTS[si]);"
        "var interval=setInterval(function(){if(idx>0){var prev=document.getElementById('w'+(idx-1));if(prev){prev.classList.remove('hl');prev.classList.add('done')}}"
        "if(idx>=words.length){clearInterval(interval);document.getElementById('nextBtn').disabled=false;return}"
        "var cur=document.getElementById('w'+idx);if(cur)cur.classList.add('hl');idx++},600)}"
        "function nextSentence(){si++;showSentence()}"
        "init();</script></body></html>"
    )


# ── FUNC 19: Writing Postcard ──
def _build_elem_writing_postcard_html():
    return (
        "<!DOCTYPE html><html lang='en'><head><meta charset='UTF-8'>"
        "<meta name='viewport' content='width=device-width,initial-scale=1'>"
        "<title>Writing Postcard</title><style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "body{font-family:'Segoe UI',sans-serif;background:linear-gradient(135deg,#1a0533,#0d0221);color:#e9d5ff;min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center}"
        ".gbox{background:rgba(168,85,247,.13);border:2px solid rgba(168,85,247,.4);border-radius:20px;padding:30px;max-width:520px;width:90%;text-align:center}"
        "h1{font-size:1.5em;margin-bottom:8px;color:#c084fc}"
        ".info{font-size:.95em;margin-bottom:12px;color:#d8b4fe}"
        ".postcard{background:rgba(168,85,247,.1);border:2px solid rgba(168,85,247,.3);border-radius:16px;padding:20px;margin:14px 0;text-align:left;font-size:1.05em;line-height:1.8;color:#f0abfc}"
        ".postcard select{background:rgba(168,85,247,.25);color:#fbbf24;border:2px solid rgba(168,85,247,.5);border-radius:8px;padding:4px 8px;font-size:1em;cursor:pointer;margin:0 2px}"
        ".postcard select option{background:#1a0533;color:#e9d5ff}"
        ".abtn{margin:8px;padding:12px 28px;font-size:1.05em;border-radius:12px;border:none;background:linear-gradient(135deg,#a855f7,#7c3aed);color:#fff;cursor:pointer}"
        ".msg{font-size:1.05em;min-height:24px;color:#fbbf24;margin:8px 0}"
        "#endScr{display:none;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(13,2,33,.93);z-index:99;flex-direction:column;align-items:center;justify-content:center}"
        "#endScr.show{display:flex}"
        ".ebtn{margin-top:18px;padding:12px 36px;font-size:1.1em;border-radius:12px;border:none;background:linear-gradient(135deg,#a855f7,#7c3aed);color:#fff;cursor:pointer}"
        "</style></head><body><div class='gbox'>"
        "<h1>Writing Postcard 📮</h1>"
        "<div class='info'>Card <span id='cn'>1</span>/4 &nbsp;|&nbsp; Score: <span id='sc'>0</span></div>"
        "<div class='postcard' id='card'></div>"
        "<div class='msg' id='msg'></div>"
        "<button class='abtn' onclick='sendCard()'>📨 Send Postcard</button></div>"
        "<div id='endScr'><h1 id='et'></h1><p id='es' style='font-size:1.2em;margin-top:10px;color:#d8b4fe'></p>"
        "<button class='ebtn' onclick='init()'>Write Again</button></div>"
        "<script>"
        "var AC=new(window.AudioContext||window.webkitAudioContext)();"
        "function snd(f,d){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}var o=AC.createOscillator(),g=AC.createGain();o.connect(g);g.connect(AC.destination);o.type='sine';o.frequency.value=f;g.gain.value=.15;o.start();g.gain.exponentialRampToValueAtTime(.001,AC.currentTime+d);o.stop(AC.currentTime+d)}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';u.rate=.8;speechSynthesis.cancel();speechSynthesis.speak(u)}catch(e){}}"
        "var CARDS=["
        "{tmpl:'Dear {0},<br>I am having a {1} time in London.<br>The weather is {2}.<br>See you soon!',blanks:["
        "{opts:['Mom','Teacher','Doctor'],ans:0},"
        "{opts:['wonderful','terrible','boring'],ans:0},"
        "{opts:['sunny','dangerous','scary'],ans:0}]},"
        "{tmpl:'Hello {0}!<br>Today I went to the {1}.<br>I saw many {2}.<br>It was fun!',blanks:["
        "{opts:['Friend','Mr. Book','Miss Chair'],ans:0},"
        "{opts:['zoo','bathroom','garage'],ans:0},"
        "{opts:['animals','tables','walls'],ans:0}]},"
        "{tmpl:'Hi {0},<br>I {1} a new bike yesterday.<br>It is {2} and fast!<br>Wish you were here.',blanks:["
        "{opts:['Dad','Pencil','Cloud'],ans:0},"
        "{opts:['got','ate','drank'],ans:0},"
        "{opts:['red','angry','sleepy'],ans:0}]},"
        "{tmpl:'Dear {0},<br>We are at the {1} today.<br>I love {2} in the waves!<br>Love, Alex',blanks:["
        "{opts:['Grandma','Desk','Shoe'],ans:0},"
        "{opts:['beach','office','kitchen'],ans:0},"
        "{opts:['swimming','reading','cooking'],ans:0}]}];"
        "var ci=0,score=0;"
        "function init(){ci=0;score=0;document.getElementById('endScr').classList.remove('show');showCard()}"
        "function showCard(){if(ci>=4){endGame();return}"
        "document.getElementById('cn').textContent=ci+1;document.getElementById('sc').textContent=score;document.getElementById('msg').textContent='';"
        "var c=CARDS[ci],html=c.tmpl;"
        "c.blanks.forEach(function(b,i){var sel='<select id=\"sel'+i+'\">';b.opts.forEach(function(o,j){sel+='<option value=\"'+j+'\">'+o+'</option>'});sel+='</select>';html=html.replace('{'+i+'}',sel)});"
        "document.getElementById('card').innerHTML=html}"
        "function sendCard(){var c=CARDS[ci],allCorrect=true;"
        "c.blanks.forEach(function(b,i){var sel=document.getElementById('sel'+i);if(parseInt(sel.value)!==b.ans)allCorrect=false});"
        "if(allCorrect){snd(523,.2);score++;document.getElementById('sc').textContent=score;"
        "document.getElementById('msg').textContent='Postcard sent!';spk('Postcard sent successfully!');ci++;setTimeout(showCard,1200)}"
        "else{snd(180,.3);document.getElementById('msg').textContent='Check your words and try again!'}}"
        "function endGame(){document.getElementById('et').textContent='Mail Delivered!';document.getElementById('es').textContent='Score: '+score+' / 4';"
        "document.getElementById('endScr').classList.add('show');spk('All postcards sent! Score '+score+' out of 4')}"
        "init();</script></body></html>"
    )


