def _get_yd_assessment_store() -> YdAssessmentStore:
    return YdAssessmentStore()


def _olcme36_styled_header(title: str, subtitle: str = ""):
    st.markdown(
        f'<div style="background:linear-gradient(135deg,#881337,#be123c);color:#fff;'
        f'padding:18px 22px;border-radius:12px;margin-bottom:16px;text-align:center;">'
        f'<h3 style="margin:0;font-size:20px;">{title}</h3>'
        f'<p style="margin:4px 0 0;font-size:13px;opacity:0.85;">{subtitle}</p>'
        f'</div>',
        unsafe_allow_html=True,
    )


def _render_olcme_36_hafta_tab():
    """36 Hafta Olcme Degerlendirme — ogretmen sinav olusturur, ogrenci cozer, otomatik degerlendirilir."""
    _olcme36_styled_header(
        "36 Hafta Olcme Degerlendirme",
        "Haftalik sinav olustur | Quiz / Yazili / Deneme hazirla | Otomatik degerlendirme",
    )

    _g_yil, _g_sinif, _g_sube, _g_level = _yd_get_global_filters()
    if not _g_sinif or not _g_sube or not _g_level:
        st.warning("Lutfen ustdeki filtrelerden **Sinif** ve **Sube** seciniz.")
        return

    store = _get_yd_assessment_store()

    tab_names = [
        "📖 Ders Defteri",
        "Haftalik Konu Takibi",
        "Sinav Olustur",
        "Ogrenci Sinavlari",
        "Sinav Sonuclari",
        "Quiz / Yazili / Deneme",
    ]
    tabs = st.tabs(tab_names)

    # ── TAB 0: Ders Defteri (Günlük ders isleme motoru) ──
    with tabs[0]:
        _render_ders_defteri(store, _g_level, _g_sinif, _g_sube)

    # ── TAB 1: Haftalik Konu Takibi (Teacher marks covered weeks) ──
    with tabs[1]:
        _render_olcme36_konu_takibi(store, _g_level, _g_sinif, _g_sube)

    # ── TAB 2: Sinav Olustur (Auto-generate from covered weeks) ──
    with tabs[2]:
        _render_olcme36_sinav_olustur(store, _g_level, _g_sinif, _g_sube)

    # ── TAB 3: Ogrenci Sinavlari (Student takes exam — also in veli panel) ──
    with tabs[3]:
        _render_olcme36_ogrenci_sinavlari(store, _g_level, _g_sinif, _g_sube)

    # ── TAB 4: Sinav Sonuclari (Results by sinif/sube) ──
    with tabs[4]:
        _render_olcme36_sonuclar(store, _g_level, _g_sinif, _g_sube)

    # ── TAB 5: Quiz / Yazili / Deneme (multi-week exam creation) ──
    with tabs[5]:
        _render_olcme36_multi_week(store, _g_level, _g_sinif, _g_sube)


# ── TAB 0: Ders Defteri (Ders Isleme Motoru) ────────────────────────────────

_DD_DAY_KEYS = ["mon", "tue", "wed", "thu", "fri"]
_DD_DAY_NAMES = {"mon": "Pazartesi", "tue": "Sali", "wed": "Carsamba", "thu": "Persembe", "fri": "Cuma"}
_DD_STATUS_ICONS = {"completed": "✅", "partial": "⚠️", "skipped": "❌", "not_started": "⬜"}
_DD_STATUS_COLORS = {"completed": "#059669", "partial": "#d97706", "skipped": "#dc2626", "not_started": "#6b7280"}


def _dd_load_weekly_plan(grade_num: int) -> list[dict]:
    """weekly_plans.json'dan belirtilen sinifin 36 haftalik planini yukle."""
    try:
        with open(_WP_PATH, "r", encoding="utf-8") as f:
            all_plans = json.load(f)
        return all_plans.get(str(grade_num), [])
    except (json.JSONDecodeError, OSError, FileNotFoundError):
        return []


def _dd_get_day_plan(weekly_plan: list[dict], week: int, day_key: str) -> dict | None:
    """Belirli haftanin belirli gununun plan verisini dondur."""
    for wp in weekly_plan:
        if wp.get("week") == week:
            return wp.get("days", {}).get(day_key)
    return None


def _dd_get_week_meta(weekly_plan: list[dict], week: int) -> dict:
    """Haftanin meta bilgilerini dondur (unit_theme, grammar_focus, vb.)."""
    for wp in weekly_plan:
        if wp.get("week") == week:
            return wp
    return {}


def _dd_parse_activity_minutes(activity_text: str) -> int:
    """Etkinlik metninden dakika bilgisini cikar. Orn: '(10dk) Kelime Pratigi...' -> 10"""
    import re
    m = re.match(r"\((\d+)\s*dk\)", activity_text.strip())
    return int(m.group(1)) if m else 0


def _dd_build_record_from_plan(day_plan: dict, week_meta: dict,
                                level: str, sinif: int, sube: str,
                                week: int, day_key: str, date_str: str) -> YdLessonRecord:
    """weekly_plans.json verisinden bos bir YdLessonRecord olustur."""
    hours_data = []
    for h in day_plan.get("hours", []):
        acts = []
        for idx, act_text in enumerate(h.get("activity", [])):
            mins = _dd_parse_activity_minutes(act_text)
            acts.append(YdActivityRecord(
                activity_index=idx,
                activity_text=act_text,
                planned_minutes=mins,
                actual_minutes=0,
                status="not_started",
            ).to_dict())
        hours_data.append(YdHourRecord(
            hour=h.get("hour", 1),
            slot=h.get("slot", ""),
            focus=h.get("focus", ""),
            planned_duration=h.get("duration", "40 dk"),
            status="not_started",
            activities=acts,
        ).to_dict())

    hw_notes = day_plan.get("homework", [])
    return YdLessonRecord(
        level=level, sinif=sinif, sube=sube,
        week=week, day_key=day_key,
        day_name=_DD_DAY_NAMES.get(day_key, day_key),
        date=date_str,
        unit_theme=week_meta.get("unit_theme", week_meta.get("theme", "")),
        hours=hours_data,
        homework_note="\n".join(hw_notes) if hw_notes else "",
    )


def _render_ders_defteri(store: YdAssessmentStore, level: str, sinif: int, sube: str):
    """Ders Defteri — Gunluk/saatlik ders isleme motoru."""

    # ── Baslik ──
    st.markdown(
        '<div style="background:linear-gradient(135deg,#1e3a5f,#2563eb);color:#fff;'
        'padding:16px 20px;border-radius:12px;margin-bottom:14px;">'
        '<div style="font-size:1.15rem;font-weight:800;">📖 Ders Defteri</div>'
        '<div style="font-size:.82rem;opacity:.85;margin-top:2px;">'
        'Gunluk ders planini gorun, etkinlikleri isaretle, ilerlemeyi takip edin</div>'
        '</div>',
        unsafe_allow_html=True,
    )

    # ── Sinif numarasini bul ──
    grade_num = sinif if sinif else 5
    weekly_plan = _dd_load_weekly_plan(grade_num)
    if not weekly_plan:
        st.warning(f"{grade_num}. sinif icin haftalik plan verisi bulunamadi (weekly_plans.json).")
        return

    # ── Hafta secimi ──
    from datetime import date
    today = date.today()
    today_day_key = {0: "mon", 1: "tue", 2: "wed", 3: "thu", 4: "fri"}.get(today.weekday())

    # Otomatik hafta tespiti (akademik takvim: Eylul 2. hafta baslangic)
    curriculum = _CURRICULUM.get(level, [])
    cur_week_auto = None
    if curriculum:
        # Basit hesaplama: Eylul 2. Pazartesi = Hafta 1
        import calendar
        year = today.year if today.month >= 9 else today.year - 1
        sept_1 = date(year, 9, 1)
        # Eylul'un 2. Pazartesini bul
        days_to_mon = (7 - sept_1.weekday()) % 7
        first_mon = sept_1 + timedelta(days=days_to_mon)
        second_mon = first_mon + timedelta(days=7) if first_mon == sept_1 else first_mon
        if today >= second_mon:
            diff_days = (today - second_mon).days
            cur_week_auto = min(36, max(1, (diff_days // 7) + 1))

    _sel_col1, _sel_col2 = st.columns([1, 1])
    with _sel_col1:
        week_options = list(range(1, 37))
        default_idx = (cur_week_auto - 1) if cur_week_auto else 0
        sel_week = st.selectbox(
            "📅 Hafta:",
            week_options,
            index=default_idx,
            format_func=lambda w: f"Hafta {w}",
            key="dd_week_sel",
        )
    with _sel_col2:
        week_meta = _dd_get_week_meta(weekly_plan, sel_week)
        theme = week_meta.get("unit_theme", week_meta.get("theme", "—"))
        grammar = week_meta.get("grammar_focus", "—")
        st.markdown(
            f'<div style="background:#f0fdf4;border-left:4px solid #059669;padding:10px 14px;'
            f'border-radius:8px;margin-top:24px;">'
            f'<b>Unite:</b> {theme} &nbsp;|&nbsp; <b>Gramer:</b> {grammar}</div>',
            unsafe_allow_html=True,
        )

    # ── Alt sekmeler: Gun bazli + Haftalik Ozet ──
    day_tabs_labels = []
    for dk in _DD_DAY_KEYS:
        dp = _dd_get_day_plan(weekly_plan, sel_week, dk)
        dn = _DD_DAY_NAMES[dk]
        rec = store.get_lesson_record(level, sinif, sube, sel_week, dk)
        if rec:
            icon = _DD_STATUS_ICONS.get(rec.overall_status, "⬜")
            pct = f" ({rec.completion_pct:.0f}%)" if rec.completion_pct > 0 else ""
        else:
            icon = "⬜" if dp else "—"
            pct = ""
        has_plan = "📋" if dp and dp.get("hours") else ""
        today_mark = " 🔵" if dk == today_day_key else ""
        day_tabs_labels.append(f"{icon} {dn}{pct}{today_mark}")
    day_tabs_labels.append("📊 Haftalik Ozet")

    day_tabs = st.tabs(day_tabs_labels)

    # ── Her gun icin ders isleme formu ──
    for di, dk in enumerate(_DD_DAY_KEYS):
        with day_tabs[di]:
            day_plan = _dd_get_day_plan(weekly_plan, sel_week, dk)
            if not day_plan or not day_plan.get("hours"):
                st.info(f"{_DD_DAY_NAMES[dk]} icin bu haftada ders plani bulunmuyor.")
                continue

            # Mevcut kaydi yukle veya plandan olustur
            existing_rec = store.get_lesson_record(level, sinif, sube, sel_week, dk)
            if existing_rec:
                rec = existing_rec
            else:
                # Tarih hesapla
                if cur_week_auto and sel_week == cur_week_auto and dk == today_day_key:
                    date_str = today.isoformat()
                else:
                    date_str = ""
                rec = _dd_build_record_from_plan(
                    day_plan, week_meta, level, sinif, sube, sel_week, dk, date_str
                )

            # ── Tarih girisi ──
            _date_col1, _date_col2 = st.columns([0.4, 0.6])
            with _date_col1:
                date_val = st.date_input(
                    "Tarih:",
                    value=date.fromisoformat(rec.date) if rec.date else today,
                    key=f"dd_date_{dk}_{sel_week}",
                )

            # ── Saatleri goster ──
            hours_to_save = []
            for hi, hr_data in enumerate(rec.hours):
                hr = hr_data if isinstance(hr_data, dict) else {}
                slot = hr.get("slot", "")
                focus = hr.get("focus", "")
                hour_num = hr.get("hour", hi + 1)
                slot_color = "#059669" if "MAIN" in slot.upper() else "#7c3aed" if "SKILL" in slot.upper() else "#2563eb"

                st.markdown(
                    f'<div style="background:linear-gradient(135deg,{slot_color}ee,{slot_color}bb);'
                    f'color:#fff;padding:10px 16px;border-radius:10px 10px 0 0;margin-top:12px;">'
                    f'<span style="font-weight:800;font-size:1rem;">{hour_num}. Saat — {slot}</span>'
                    f'<br><span style="font-size:.82rem;opacity:.9;">{focus}</span></div>',
                    unsafe_allow_html=True,
                )

                # Saat durumu
                _hr_col1, _hr_col2, _hr_col3 = st.columns([0.35, 0.35, 0.3])
                with _hr_col1:
                    hr_status_opts = list(LESSON_STATUS.keys())
                    hr_cur_status = hr.get("status", "not_started")
                    hr_status_idx = hr_status_opts.index(hr_cur_status) if hr_cur_status in hr_status_opts else 3
                    new_hr_status = st.selectbox(
                        "Durum:",
                        hr_status_opts,
                        index=hr_status_idx,
                        format_func=lambda s: f"{_DD_STATUS_ICONS.get(s, '')} {LESSON_STATUS.get(s, s)}",
                        key=f"dd_hr_st_{dk}_{sel_week}_{hi}",
                    )
                with _hr_col2:
                    if new_hr_status in ("skipped", "partial"):
                        skip_opts = list(SKIP_REASONS.keys())
                        cur_skip = hr.get("skip_reason", "")
                        skip_idx = skip_opts.index(cur_skip) if cur_skip in skip_opts else 0
                        new_skip = st.selectbox(
                            "Neden:",
                            skip_opts,
                            index=skip_idx,
                            format_func=lambda s: SKIP_REASONS.get(s, s),
                            key=f"dd_hr_skip_{dk}_{sel_week}_{hi}",
                        )
                    else:
                        new_skip = ""
                with _hr_col3:
                    hr_note = st.text_input(
                        "Not:",
                        value=hr.get("teacher_note", ""),
                        key=f"dd_hr_note_{dk}_{sel_week}_{hi}",
                        placeholder="Ogretmen notu...",
                    )

                # ── Etkinlikler ──
                acts = hr.get("activities", [])
                new_acts = []
                if acts:
                    for ai, act in enumerate(acts):
                        act_text = act.get("activity_text", "")
                        planned_min = act.get("planned_minutes", 0)
                        act_status = act.get("status", "not_started")
                        act_actual = act.get("actual_minutes", 0)
                        act_note = act.get("note", "")

                        _ac1, _ac2, _ac3, _ac4 = st.columns([0.45, 0.2, 0.15, 0.2])
                        with _ac1:
                            # Etkinlik metni (kisaltilmis)
                            short_text = act_text[:80] + "..." if len(act_text) > 80 else act_text
                            icon = _DD_STATUS_ICONS.get(act_status, "⬜")
                            st.markdown(
                                f'<div style="font-size:.82rem;color:#334155;padding:4px 0;">'
                                f'{icon} {_sanitize_html(short_text)}</div>',
                                unsafe_allow_html=True,
                            )
                        with _ac2:
                            act_st_opts = ["completed", "partial", "skipped", "not_started"]
                            act_st_idx = act_st_opts.index(act_status) if act_status in act_st_opts else 3
                            new_act_st = st.selectbox(
                                "Durum",
                                act_st_opts,
                                index=act_st_idx,
                                format_func=lambda s: LESSON_STATUS.get(s, s),
                                key=f"dd_act_st_{dk}_{sel_week}_{hi}_{ai}",
                                label_visibility="collapsed",
                            )
                        with _ac3:
                            new_act_min = st.number_input(
                                f"dk (/{planned_min})",
                                min_value=0, max_value=60,
                                value=act_actual if act_actual > 0 else planned_min if new_act_st == "completed" else 0,
                                key=f"dd_act_min_{dk}_{sel_week}_{hi}_{ai}",
                            )
                        with _ac4:
                            new_act_note = st.text_input(
                                "Not",
                                value=act_note,
                                key=f"dd_act_note_{dk}_{sel_week}_{hi}_{ai}",
                                label_visibility="collapsed",
                                placeholder="Not...",
                            )

                        new_acts.append({
                            "activity_index": ai,
                            "activity_text": act_text,
                            "planned_minutes": planned_min,
                            "actual_minutes": new_act_min,
                            "status": new_act_st,
                            "note": new_act_note,
                        })

                # Saat ozeti: planlanan vs gerceklesen
                total_planned = sum(a.get("planned_minutes", 0) for a in acts)
                total_actual = sum(a.get("actual_minutes", 0) for a in new_acts) if new_acts else 0
                completed_acts = sum(1 for a in new_acts if a.get("status") == "completed") if new_acts else 0
                total_acts = len(new_acts) if new_acts else 0

                # Saat durumunu etkinliklerden otomatik belirle
                if new_hr_status == "not_started" and total_acts > 0 and completed_acts > 0:
                    if completed_acts == total_acts:
                        new_hr_status = "completed"
                    else:
                        new_hr_status = "partial"

                actual_total = total_actual if total_actual > 0 else 0
                st.markdown(
                    f'<div style="background:#f8fafc;border:1px solid #e2e8f0;padding:6px 12px;'
                    f'border-radius:0 0 10px 10px;font-size:.78rem;color:#64748b;">'
                    f'Etkinlik: <b>{completed_acts}/{total_acts}</b> tamamlandi &nbsp;|&nbsp; '
                    f'Sure: <b>{actual_total}</b> / {total_planned} dk</div>',
                    unsafe_allow_html=True,
                )

                hours_to_save.append({
                    "hour": hour_num,
                    "slot": slot,
                    "focus": focus,
                    "planned_duration": hr.get("planned_duration", "40 dk"),
                    "status": new_hr_status,
                    "skip_reason": new_skip,
                    "activities": new_acts,
                    "teacher_note": hr_note,
                    "actual_total_minutes": actual_total,
                })

            # ── Odev notu ──
            hw_existing = rec.homework_note if isinstance(rec.homework_note, str) else ""
            hw_note = st.text_area(
                "📝 Odev / Ek Not:",
                value=hw_existing,
                key=f"dd_hw_{dk}_{sel_week}",
                height=60,
                placeholder="Bu gune ait odev veya ek notlar...",
            )

            # ── Kaydet butonu ──
            _sv_col1, _sv_col2, _sv_col3 = st.columns([0.3, 0.4, 0.3])
            with _sv_col1:
                if st.button("💾 Kaydet", key=f"dd_save_{dk}_{sel_week}", type="primary"):
                    rec.hours = hours_to_save
                    rec.homework_note = hw_note
                    rec.date = date_val.isoformat() if date_val else ""
                    rec.calculate_completion()
                    store.save_lesson_record(rec)
                    st.success(f"✅ {_DD_DAY_NAMES[dk]} — Hafta {sel_week} kaydedildi! (%{rec.completion_pct:.0f})")
                    st.rerun()
            with _sv_col2:
                # Tum etkinlikleri tamamla butonu
                if st.button("✅ Tumunu Tamamla", key=f"dd_all_done_{dk}_{sel_week}"):
                    for h in hours_to_save:
                        h["status"] = "completed"
                        for a in h.get("activities", []):
                            a["status"] = "completed"
                            if a["actual_minutes"] == 0:
                                a["actual_minutes"] = a.get("planned_minutes", 0)
                    rec.hours = hours_to_save
                    rec.homework_note = hw_note
                    rec.date = date_val.isoformat() if date_val else ""
                    rec.calculate_completion()
                    store.save_lesson_record(rec)
                    st.success(f"✅ {_DD_DAY_NAMES[dk]} tum etkinlikler tamamlandi!")
                    st.rerun()
            with _sv_col3:
                if existing_rec and st.button("🗑️ Kaydi Sil", key=f"dd_del_{dk}_{sel_week}"):
                    store.delete_lesson_record(rec.id)
                    st.warning("Kayit silindi.")
                    st.rerun()

    # ── Haftalik Ozet Sekmesi ──
    with day_tabs[-1]:
        _render_dd_weekly_summary(store, level, sinif, sube, sel_week, weekly_plan)


def _render_dd_weekly_summary(store: YdAssessmentStore, level: str, sinif: int,
                               sube: str, week: int, weekly_plan: list[dict]):
    """Haftalik ders isleme ozeti ve ilerleme raporu."""
    progress = store.get_week_progress(level, sinif, sube, week)
    week_meta = _dd_get_week_meta(weekly_plan, week)
    theme = week_meta.get("unit_theme", week_meta.get("theme", "—"))

    # ── Genel ozet kartlari ──
    pct = progress["completion_pct"]
    pct_color = "#059669" if pct >= 80 else "#d97706" if pct >= 50 else "#dc2626" if pct > 0 else "#6b7280"
    st.markdown(
        f'<div style="background:linear-gradient(135deg,#0f172a,#1e293b);color:#fff;'
        f'padding:18px 22px;border-radius:12px;margin-bottom:14px;text-align:center;">'
        f'<div style="font-size:1.1rem;font-weight:700;">Hafta {week} — {theme}</div>'
        f'<div style="font-size:2.2rem;font-weight:900;color:{pct_color};margin:8px 0;">'
        f'%{pct:.0f}</div>'
        f'<div style="font-size:.85rem;opacity:.7;">'
        f'{progress["completed_hours"]}/{progress["total_hours"]} saat tamamlandi</div>'
        f'</div>',
        unsafe_allow_html=True,
    )

    # ── Gun bazli tablo ──
    st.markdown("##### Gunluk Durum")
    _cols = st.columns(5)
    for ci, dk in enumerate(_DD_DAY_KEYS):
        with _cols[ci]:
            day_info = progress["days"].get(dk, {})
            status = day_info.get("status", "not_started")
            d_pct = day_info.get("completion_pct", 0.0)
            icon = _DD_STATUS_ICONS.get(status, "⬜")
            bg = _DD_STATUS_COLORS.get(status, "#6b7280")
            dt = day_info.get("date", "")
            dt_disp = dt[5:10] if dt else "—"
            st.markdown(
                f'<div style="background:{bg}15;border:2px solid {bg};border-radius:10px;'
                f'padding:12px;text-align:center;">'
                f'<div style="font-size:1.3rem;">{icon}</div>'
                f'<div style="font-weight:700;font-size:.9rem;color:{bg};">{_DD_DAY_NAMES[dk]}</div>'
                f'<div style="font-size:1.1rem;font-weight:800;color:{bg};">%{d_pct:.0f}</div>'
                f'<div style="font-size:.72rem;color:#94a3b8;">{dt_disp}</div>'
                f'</div>',
                unsafe_allow_html=True,
            )

    # ── 36 hafta genel ilerleme ──
    st.markdown("---")
    st.markdown("##### 36 Hafta Genel Ilerleme")
    all_weeks_progress = []
    for w in range(1, 37):
        wp = store.get_week_progress(level, sinif, sube, w)
        all_weeks_progress.append(wp)

    # Hafta kartlari (9 ay x 4 hafta)
    month_ranges = {
        "Eylul": (1, 4), "Ekim": (5, 8), "Kasim": (9, 12),
        "Aralik": (13, 16), "Ocak": (17, 20), "Subat": (21, 24),
        "Mart": (25, 28), "Nisan": (29, 32), "Mayis": (33, 36),
    }
    for month_label, (w_start, w_end) in month_ranges.items():
        _mcols = st.columns(4)
        for mi, wn in enumerate(range(w_start, w_end + 1)):
            with _mcols[mi]:
                wp = all_weeks_progress[wn - 1]
                p = wp["completion_pct"]
                bg_c = "#059669" if p >= 80 else "#d97706" if p >= 50 else "#dc2626" if p > 0 else "#1e293b"
                txt_c = "#fff" if p > 0 else "#64748b"
                wm = _dd_get_week_meta(weekly_plan, wn)
                wt = wm.get("unit_theme", wm.get("theme", ""))[:15]
                st.markdown(
                    f'<div style="background:{bg_c};color:{txt_c};padding:8px;'
                    f'border-radius:8px;text-align:center;margin:2px 0;font-size:.75rem;">'
                    f'<div style="font-weight:800;">H{wn}</div>'
                    f'<div style="font-size:1rem;font-weight:900;">%{p:.0f}</div>'
                    f'<div style="opacity:.8;">{wt}</div></div>',
                    unsafe_allow_html=True,
                )
        # Ay etiketi
        avg_pct = sum(all_weeks_progress[wn - 1]["completion_pct"] for wn in range(w_start, w_end + 1)) / 4
        st.markdown(
            f'<div style="text-align:center;font-size:.78rem;color:#94a3b8;margin-bottom:8px;">'
            f'{month_label} — Ort. %{avg_pct:.0f}</div>',
            unsafe_allow_html=True,
        )


# ── TAB 1: Konu Takibi ──────────────────────────────────────────────────────

def _render_olcme36_konu_takibi(store: YdAssessmentStore, level: str, sinif: int, sube: str):
    """Teacher marks which weeks have been covered."""
    st.markdown(
        '<div style="background:#fef2f2;border-left:4px solid #be123c;padding:12px 16px;'
        'border-radius:8px;margin-bottom:12px;">'
        '<b>Islenen Haftalari Isaretleyin</b> — Isaretlenen haftalardan otomatik sinav olusturulabilir.'
        '</div>',
        unsafe_allow_html=True,
    )

    curriculum = _CURRICULUM.get(level, [])
    if not curriculum:
        st.info("Bu seviye icin mufredat bulunamadi.")
        return

    covered = store.get_covered_weeks(level, sinif, sube)

    # Month grouping
    month_ranges = {
        "Eylul (H1-4)": (1, 4), "Ekim (H5-8)": (5, 8), "Kasim (H9-12)": (9, 12),
        "Aralik (H13-16)": (13, 16), "Ocak (H17-20)": (17, 20), "Subat (H21-24)": (21, 24),
        "Mart (H25-28)": (25, 28), "Nisan (H29-32)": (29, 32), "Mayis (H33-36)": (33, 36),
    }

    for month_label, (w_start, w_end) in month_ranges.items():
        with st.expander(month_label, expanded=False):
            for wn in range(w_start, w_end + 1):
                week_data = next((w for w in curriculum if w.get("week") == wn), None)
                if not week_data:
                    continue
                theme = week_data.get("theme", f"Hafta {wn}")
                theme_tr = week_data.get("theme_tr", "")
                is_covered = str(wn) in covered

                col1, col2, col3 = st.columns([0.08, 0.72, 0.2])
                with col1:
                    new_val = st.checkbox(
                        f"H{wn}", value=is_covered,
                        key=f"olcme36_cov_{level}_{sinif}_{sube}_{wn}",
                        label_visibility="collapsed",
                    )
                with col2:
                    status_icon = "✅" if new_val else "⬜"
                    vocab_count = len(week_data.get("vocab", []))
                    st.markdown(
                        f'{status_icon} **Hafta {wn}:** {theme} ({theme_tr}) '
                        f'<span style="color:#6b7280;font-size:12px;">— {vocab_count} kelime</span>',
                        unsafe_allow_html=True,
                    )
                with col3:
                    if new_val and not is_covered:
                        store.mark_week_covered(level, sinif, sube, wn,
                                                week_data.get("vocab", []))
                    elif not new_val and is_covered:
                        store.unmark_week(level, sinif, sube, wn)

    # Summary
    covered = store.get_covered_weeks(level, sinif, sube)
    total_covered = len(covered)
    st.markdown(
        f'<div style="background:linear-gradient(135deg,#065f46,#059669);color:#fff;'
        f'padding:14px 18px;border-radius:10px;margin-top:12px;text-align:center;">'
        f'<span style="font-size:1.5rem;font-weight:800;">{total_covered}</span>'
        f'<span style="font-size:.9rem;opacity:.85;"> / 36 hafta islendi</span></div>',
        unsafe_allow_html=True,
    )


# ── TAB 2: Sinav Olustur ────────────────────────────────────────────────────

def _render_olcme36_sinav_olustur(store: YdAssessmentStore, level: str, sinif: int, sube: str):
    """Teacher creates a weekly exam from covered topics."""
    covered = store.get_covered_weeks(level, sinif, sube)
    covered_weeks_sorted = sorted([int(w) for w in covered.keys()])

    if not covered_weeks_sorted:
        st.info("Henuz islenmis hafta yok. Once 'Haftalik Konu Takibi' sekmesinde haftalari isaretleyin.")
        return

    st.markdown(
        '<div style="background:#eff6ff;border-left:4px solid #2563eb;padding:12px 16px;'
        'border-radius:8px;margin-bottom:12px;">'
        '<b>Haftalik Degerlendirme Sinavi Olustur</b> — Islenen haftalardan otomatik soru uretilir.'
        '</div>',
        unsafe_allow_html=True,
    )

    col1, col2 = st.columns(2)
    with col1:
        selected_week = st.selectbox(
            "Sinav Haftasi:",
            covered_weeks_sorted,
            format_func=lambda w: f"Hafta {w} — {_get_week_theme(level, w)}",
            key="olcme36_sinav_week",
        )
    with col2:
        q_count = st.slider("Soru Sayisi:", 5, 20, 10, key="olcme36_q_count")

    # Check if exam already exists for this week
    existing = store.get_exams(level=level, sinif=sinif, sube=sube, category="haftalik")
    week_exams = [e for e in existing if selected_week in e.weeks]

    if week_exams:
        latest = week_exams[-1]
        st.warning(f"Hafta {selected_week} icin zaten bir sinav var: **{latest.name}** ({latest.status})")

        if latest.status == "draft":
            c1, c2 = st.columns(2)
            with c1:
                if st.button("Mevcut Sinavi Gonder", key="olcme36_send_existing", type="primary"):
                    latest.status = "sent"
                    latest.sent_at = datetime.now().isoformat()
                    latest.deadline = (datetime.now() + timedelta(days=3)).isoformat()
                    store.save_exam(latest)
                    st.success("Sinav ogrencilere gonderildi!")
                    st.rerun()
            with c2:
                if st.button("Yeni Sinav Olustur (Yeniden)", key="olcme36_regen"):
                    st.session_state["olcme36_force_regen"] = True
                    st.rerun()

        if latest.status == "sent":
            st.info("Bu sinav zaten gonderildi. Ogrenci cevaplarini bekliyor.")
            return

    # Generate
    force = st.session_state.pop("olcme36_force_regen", False)
    show_create = not week_exams or force

    if show_create:
        if st.button("Sinav Olustur", key="olcme36_create_btn", type="primary", use_container_width=True):
            generator = YdQuestionGenerator(_CURRICULUM)
            questions = generator.generate(level, [selected_week], "haftalik", q_count)
            if not questions:
                st.error("Soru uretilemedi. Mufredat verisi eksik olabilir.")
                return

            theme = _get_week_theme(level, selected_week)
            exam = YdExam(
                name=f"Hafta {selected_week} — {theme} (Haftalik Degerlendirme)",
                category="haftalik",
                grade=sinif,
                sinif=sinif,
                sube=sube,
                level=level,
                weeks=[selected_week],
                questions=[q.to_dict() for q in questions],
                total_points=sum(q.points for q in questions),
                duration_minutes=max(10, q_count * 2),
                status="draft",
            )
            exam = store.save_exam(exam)
            st.success(f"Sinav olusturuldu: **{exam.name}** ({len(questions)} soru)")
            st.rerun()

    # Show existing exams for this class
    all_exams = store.get_exams(level=level, sinif=sinif, sube=sube)
    if all_exams:
        st.markdown("---")
        st.markdown("**Olusturulan Sinavlar:**")
        for ex in sorted(all_exams, key=lambda e: e.created_at, reverse=True)[:10]:
            cat_label = EXAM_CATEGORIES.get(ex.category, ex.category)
            status_map = {
                "draft": "Taslak", "sent": "Gonderildi",
                "completed": "Tamamlandi", "archived": "Arsivlendi"
            }
            status_label = status_map.get(ex.status, ex.status)
            weeks_str = ", ".join(str(w) for w in ex.weeks)

            col1, col2, col3 = st.columns([0.5, 0.3, 0.2])
            with col1:
                st.markdown(f"**{ex.name}**  \n{cat_label} | Hafta: {weeks_str} | {len(ex.questions)} soru")
            with col2:
                color = {"draft": "#f59e0b", "sent": "#2563eb", "completed": "#059669"}.get(ex.status, "#6b7280")
                st.markdown(f'<span style="color:{color};font-weight:700;">{status_label}</span>',
                            unsafe_allow_html=True)
            with col3:
                if ex.status == "draft":
                    if st.button("Gonder", key=f"olcme36_send_{ex.id}"):
                        ex.status = "sent"
                        ex.sent_at = datetime.now().isoformat()
                        ex.deadline = (datetime.now() + timedelta(days=3)).isoformat()
                        store.save_exam(ex)
                        st.success("Gonderildi!")
                        st.rerun()


def _get_week_theme(level: str, week_num: int) -> str:
    """Get theme name for a given week."""
    curriculum = _CURRICULUM.get(level, [])
    for w in curriculum:
        if w.get("week") == week_num:
            return w.get("theme", f"Hafta {week_num}")
    return f"Hafta {week_num}"


# ── TAB 3: Ogrenci Sinavlari (Student takes exam) ───────────────────────────

def _render_olcme36_ogrenci_sinavlari(store: YdAssessmentStore, level: str, sinif: int, sube: str):
    """Student-facing exam interface — also called from veli panel."""
    st.markdown(
        '<div style="background:#f0fdf4;border-left:4px solid #059669;padding:12px 16px;'
        'border-radius:8px;margin-bottom:12px;">'
        '<b>Ogrenci Sinav Ekrani</b> — Gonderilen sinavlari cozun ve geri gonderin.'
        '</div>',
        unsafe_allow_html=True,
    )

    # Student selection
    try:
        from utils.shared_data import get_student_display_options
        students = get_student_display_options(sinif_filter=sinif, sube_filter=sube, include_empty=False)
    except Exception:
        students = {}

    if not students:
        st.info("Bu sinif/sube icin kayitli ogrenci bulunamadi.")
        return

    student_name = st.selectbox("Ogrenci:", list(students.keys()), key="olcme36_student_sel")
    if not student_name:
        return
    student_data = students[student_name]
    student_id = student_data.get("id", student_name)

    # Get sent exams
    sent_exams = store.get_exams(level=level, sinif=sinif, sube=sube, status="sent")
    if not sent_exams:
        st.info("Henuz gonderilmis sinav bulunmamaktadir.")
        return

    # Check which exams student already submitted
    student_answers = store.get_student_answers(student_id=student_id)
    submitted_exam_ids = {a.exam_id for a in student_answers if a.status == "submitted"}

    # Filter to pending exams
    pending_exams = [e for e in sent_exams if e.id not in submitted_exam_ids]
    completed_exams = [e for e in sent_exams if e.id in submitted_exam_ids]

    if pending_exams:
        st.markdown(f"**Bekleyen Sinavlar ({len(pending_exams)}):**")
        exam_options = {f"{e.name} ({len(e.questions)} soru)": e for e in pending_exams}
        selected_exam_label = st.selectbox("Sinav Sec:", list(exam_options.keys()), key="olcme36_exam_sel")
        exam = exam_options[selected_exam_label]

        _render_olcme36_take_exam(store, exam, student_id, student_name, sinif, sube)
    else:
        st.success("Tum sinavlar tamamlandi!")

    if completed_exams:
        st.markdown("---")
        st.markdown(f"**Tamamlanan Sinavlar ({len(completed_exams)}):**")
        for ce in completed_exams:
            st.markdown(f"- {ce.name}")


def _render_olcme36_take_exam(store: YdAssessmentStore, exam: YdExam,
                               student_id: str, student_name: str, sinif: int, sube: str):
    """Render exam questions for student to answer."""
    questions = [YdQuestion.from_dict(q) for q in exam.questions]
    ss_key = f"olcme36_ans_{exam.id}_{student_id}"

    st.markdown(
        f'<div style="background:linear-gradient(135deg,#1e40af,#3b82f6);color:#fff;'
        f'padding:14px 18px;border-radius:10px;margin:12px 0;">'
        f'<div style="font-size:1.1rem;font-weight:700;">{exam.name}</div>'
        f'<div style="font-size:.85rem;opacity:.85;">'
        f'{len(questions)} soru | Sure: {exam.duration_minutes} dk | '
        f'Toplam: {exam.total_points} puan</div></div>',
        unsafe_allow_html=True,
    )

    answers = {}
    for i, q in enumerate(questions):
        st.markdown(f"---\n**Soru {i + 1}** {'(' + q.skill + ')' if q.skill else ''}")
        st.markdown(q.stem)

        if q.q_type in ("mcq", "fill_blank", "true_false"):
            if q.choices:
                choice_labels = [f"{k}) {v}" for k, v in sorted(q.choices.items())]
                selected = st.radio(
                    f"Cevabin:", choice_labels,
                    key=f"{ss_key}_q{i}",
                    index=None,
                    label_visibility="collapsed",
                )
                if selected:
                    answers[q.id] = selected.split(")")[0].strip()
        elif q.q_type == "matching":
            if q.choices:
                choice_labels = [f"{k}) {v}" for k, v in sorted(q.choices.items())]
                selected = st.radio(
                    f"Cevabin:", choice_labels,
                    key=f"{ss_key}_q{i}",
                    index=None,
                    label_visibility="collapsed",
                )
                if selected:
                    answers[q.id] = selected.split(")")[0].strip()

    st.markdown("---")
    answered_count = len(answers)
    total_count = len(questions)
    st.markdown(f"**Cevaplanan:** {answered_count} / {total_count}")

    if st.button("Geri Gonder", key=f"olcme36_submit_{exam.id}", type="primary", use_container_width=True):
        if answered_count == 0:
            st.error("Lutfen en az bir soruyu cevaplayin.")
            return

        # Save student answer
        student_ans = YdStudentAnswer(
            exam_id=exam.id,
            student_id=student_id,
            student_name=student_name,
            sinif=sinif,
            sube=sube,
            answers=answers,
            status="submitted",
            submitted_at=datetime.now().isoformat(),
        )
        student_ans = store.save_answer(student_ans)

        # Auto-grade
        result = YdAutoGrader.grade(exam, student_ans)
        result = store.save_result(result)

        # Auto-generate remediation homework for wrong/empty answers
        remediation = YdAutoGrader.generate_remediation(exam, result, _CURRICULUM)
        if remediation:
            store.save_remediation(remediation)

        # Check if all students submitted
        try:
            from utils.shared_data import get_student_display_options
            all_students = get_student_display_options(sinif_filter=sinif, sube_filter=sube, include_empty=False)
            all_answers = store.get_student_answers(exam_id=exam.id)
            submitted_ids = {a.student_id for a in all_answers if a.status == "submitted"}
            if len(submitted_ids) >= len(all_students):
                exam.status = "completed"
                store.save_exam(exam)
        except Exception:
            pass

        st.success(
            f"Sinav gonderildi ve degerlendirildi!\n\n"
            f"**Sonuc:** {result.correct_count}/{result.total_questions} dogru | "
            f"**Puan:** {result.score:.1f}/100"
        )
        if remediation:
            st.info(
                f"Yanlis/bos sorulara ait **{remediation.total_questions} soruluk otomatik odev** "
                f"olusturuldu ve gonderildi."
            )
        st.balloons()
        st.rerun()


# ── TAB 4: Sinav Sonuclari — Grafikli Analiz ─────────────────────────────────

def _render_olcme36_sonuclar(store: YdAssessmentStore, level: str, sinif: int, sube: str):
    """Display exam results — full graphical analysis, skill/theme/week breakdown, AI recommendations."""
    import pandas as pd

    st.markdown(
        '<div style="background:linear-gradient(135deg,#7c2d12,#ea580c);color:#fff;'
        'padding:16px 20px;border-radius:12px;margin-bottom:14px;text-align:center;">'
        '<h3 style="margin:0;font-size:19px;">Sinav Sonuclari & Analiz</h3>'
        '<p style="margin:4px 0 0;font-size:12px;opacity:.85;">'
        'Grafik | Beceri Analizi | Kazanim Bazli | Hafta Bazli | AI Tavsiye | Otomatik Odev</p>'
        '</div>',
        unsafe_allow_html=True,
    )

    # ── Filters ──
    fc1, fc2 = st.columns(2)
    with fc1:
        cat_filter = st.selectbox(
            "Kategori:", ["Tumu"] + list(EXAM_CATEGORIES.values()),
            key="olcme36_cat_filter",
        )
    with fc2:
        view_mode = st.radio("Gorunum:", ["Sinif Ozeti", "Ogrenci Detay"], horizontal=True,
                             key="olcme36_view_mode")

    cat_key = None
    if cat_filter != "Tumu":
        cat_key = next((k for k, v in EXAM_CATEGORIES.items() if v == cat_filter), None)

    results = store.get_results(sinif=sinif, sube=sube, category=cat_key)
    if not results:
        st.info("Henuz sinav sonucu bulunmamaktadir.")
        return

    # ══════════════════════════════════════════════════════════════════
    # SINIF OZETI
    # ══════════════════════════════════════════════════════════════════
    if view_mode == "Sinif Ozeti":
        _render_sonuc_sinif_ozeti(results, store, level, sinif, sube)
    else:
        _render_sonuc_ogrenci_detay(results, store, level, sinif, sube)


def _render_sonuc_sinif_ozeti(results: list, store, level, sinif, sube):
    """Class-level summary with charts."""
    import pandas as pd

    # Group by exam
    exam_groups: dict[str, list[YdExamResult]] = {}
    for r in results:
        exam_groups.setdefault(r.exam_id, []).append(r)

    # ── Genel Istatistikler ──
    all_scores = [r.score for r in results]
    avg_all = sum(all_scores) / len(all_scores) if all_scores else 0
    c1, c2, c3, c4 = st.columns(4)
    with c1:
        st.metric("Genel Ortalama", f"{avg_all:.1f}")
    with c2:
        st.metric("Toplam Sinav", len(exam_groups))
    with c3:
        st.metric("Toplam Sonuc", len(results))
    with c4:
        above_70 = sum(1 for s in all_scores if s >= 70)
        st.metric("Basarili (%70+)", f"{above_70}/{len(all_scores)}")

    # ── Puan Dagilimi Grafigi ──
    st.markdown("---")
    st.markdown("**Puan Dagilimi**")
    bins = {"0-29": 0, "30-49": 0, "50-69": 0, "70-84": 0, "85-100": 0}
    for s in all_scores:
        if s < 30: bins["0-29"] += 1
        elif s < 50: bins["30-49"] += 1
        elif s < 70: bins["50-69"] += 1
        elif s < 85: bins["70-84"] += 1
        else: bins["85-100"] += 1
    df_dist = pd.DataFrame({"Puan Araligi": list(bins.keys()), "Ogrenci Sayisi": list(bins.values())})
    st.bar_chart(df_dist.set_index("Puan Araligi"), use_container_width=True)

    # ── Sinav Bazli Ortalama Trend ──
    if len(exam_groups) > 1:
        st.markdown("**Sinav Bazli Ortalama Trend**")
        trend_data = []
        for eid, group in exam_groups.items():
            first = group[0]
            avg = sum(r.score for r in group) / len(group)
            trend_data.append({
                "Sinav": first.exam_name[:30],
                "Ortalama": round(avg, 1),
            })
        df_trend = pd.DataFrame(trend_data)
        st.line_chart(df_trend.set_index("Sinav"), use_container_width=True)

    # ── Beceri Bazli Analiz (Aggregate) ──
    st.markdown("---")
    st.markdown("**Beceri (Skill) Bazli Basari Orani**")
    agg_skills: dict[str, dict] = {}
    for r in results:
        for sk, data in r.skill_breakdown.items():
            if sk not in agg_skills:
                agg_skills[sk] = {"correct": 0, "total": 0}
            agg_skills[sk]["correct"] += data.get("correct", 0)
            agg_skills[sk]["total"] += data.get("total", 0)

    if agg_skills:
        skill_labels = {"vocabulary": "Kelime", "grammar": "Dilbilgisi", "other": "Diger"}
        skill_rows = []
        for sk, data in agg_skills.items():
            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
            skill_rows.append({
                "Beceri": skill_labels.get(sk, sk.title()),
                "Dogru": data["correct"],
                "Toplam": data["total"],
                "Basari %": round(pct, 1),
            })
        df_sk = pd.DataFrame(skill_rows)
        col_chart, col_table = st.columns([0.6, 0.4])
        with col_chart:
            st.bar_chart(df_sk.set_index("Beceri")["Basari %"], use_container_width=True)
        with col_table:
            st.dataframe(df_sk, use_container_width=True, hide_index=True)

    # ── Tema/Kazanim Bazli Analiz ──
    st.markdown("---")
    st.markdown("**Tema (Kazanim) Bazli Basari Orani**")
    agg_themes: dict[str, dict] = {}
    for r in results:
        for th, data in r.theme_breakdown.items():
            if th not in agg_themes:
                agg_themes[th] = {"correct": 0, "total": 0}
            agg_themes[th]["correct"] += data.get("correct", 0)
            agg_themes[th]["total"] += data.get("total", 0)

    if agg_themes:
        theme_rows = []
        for th, data in sorted(agg_themes.items()):
            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
            theme_rows.append({
                "Tema/Kazanim": th,
                "Dogru": data["correct"],
                "Toplam": data["total"],
                "Basari %": round(pct, 1),
            })
        df_th = pd.DataFrame(theme_rows)
        st.bar_chart(df_th.set_index("Tema/Kazanim")["Basari %"], use_container_width=True)
        st.dataframe(df_th, use_container_width=True, hide_index=True)

        # AI Tavsiye — zayif temalar
        weak_themes = [t for t in theme_rows if t["Basari %"] < 60]
        if weak_themes:
            st.markdown("---")
            st.markdown(
                '<div style="background:linear-gradient(135deg,#7c3aed,#a855f7);color:#fff;'
                'padding:14px 18px;border-radius:10px;">'
                '<h4 style="margin:0;font-size:16px;">AI Analiz & Tavsiye</h4></div>',
                unsafe_allow_html=True,
            )
            for wt in weak_themes:
                color = "#dc2626" if wt["Basari %"] < 40 else "#f59e0b"
                st.markdown(
                    f'<div style="background:{color}10;border-left:3px solid {color};'
                    f'padding:10px 14px;border-radius:6px;margin:6px 0;">'
                    f'<b>{wt["Tema/Kazanim"]}</b> — '
                    f'<span style="color:{color};font-weight:700;">{wt["Basari %"]:.0f}%</span><br>'
                    f'<span style="font-size:13px;color:#94A3B8;">'
                    f'Bu temada basari orani dusuk. Ek pekistirme etkinlikleri ve tekrar calismasi onerilir. '
                    f'Kelime kartlari, eslestirme oyunlari ve kisa quiz\'ler ile desteklenmelidir.</span>'
                    f'</div>',
                    unsafe_allow_html=True,
                )

    # ── Hafta Bazli Analiz ──
    st.markdown("---")
    st.markdown("**Hafta Bazli Basari Orani**")
    agg_weeks: dict[str, dict] = {}
    for r in results:
        for wk, data in r.week_breakdown.items():
            if wk not in agg_weeks:
                agg_weeks[wk] = {"correct": 0, "total": 0}
            agg_weeks[wk]["correct"] += data.get("correct", 0)
            agg_weeks[wk]["total"] += data.get("total", 0)

    if agg_weeks:
        week_rows = []
        for wk in sorted(agg_weeks.keys(), key=lambda x: int(x) if x.isdigit() else 0):
            data = agg_weeks[wk]
            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
            theme = _get_week_theme(level, int(wk)) if wk.isdigit() else wk
            week_rows.append({
                "Hafta": f"H{wk} — {theme}",
                "Dogru": data["correct"],
                "Toplam": data["total"],
                "Basari %": round(pct, 1),
            })
        df_wk = pd.DataFrame(week_rows)
        st.bar_chart(df_wk.set_index("Hafta")["Basari %"], use_container_width=True)
        st.dataframe(df_wk, use_container_width=True, hide_index=True)

    # ── Sinav Bazli Detay ──
    st.markdown("---")
    st.markdown("**Sinav Bazli Ogrenci Siralamalari**")
    for exam_id, group in exam_groups.items():
        first = group[0]
        cat_label = EXAM_CATEGORIES.get(first.exam_category, first.exam_category)
        weeks_str = ", ".join(str(w) for w in first.weeks)
        scores = [r.score for r in group]
        avg = sum(scores) / len(scores) if scores else 0

        with st.expander(f"{first.exam_name} | {cat_label} | Ort: {avg:.1f} ({len(group)} ogrenci)"):
            rows = []
            for i, r in enumerate(sorted(group, key=lambda x: x.score, reverse=True)):
                rows.append({
                    "Sira": i + 1,
                    "Ogrenci": r.student_name,
                    "Dogru": r.correct_count,
                    "Yanlis": r.wrong_count,
                    "Bos": r.empty_count,
                    "Puan": f"{r.score:.1f}",
                })
            df = pd.DataFrame(rows)
            st.dataframe(df, use_container_width=True, hide_index=True)

    # ── Otomatik Odev Durumu ──
    st.markdown("---")
    st.markdown("**Otomatik Odev (Telafi) Durumu**")
    all_rem = store.get_remediation(sinif=sinif, sube=sube)
    if all_rem:
        rem_rows = []
        for rem in all_rem:
            rem_rows.append({
                "Ogrenci": rem.student_name,
                "Sinav": rem.exam_id[:12],
                "Eksik Konu": len(rem.wrong_topics),
                "Odev Soru": rem.total_questions,
                "Durum": "Tamamlandi" if rem.status == "completed" else "Bekliyor",
                "Puan": f"{rem.score:.0f}" if rem.status == "completed" else "-",
            })
        df_rem = pd.DataFrame(rem_rows)
        st.dataframe(df_rem, use_container_width=True, hide_index=True)
    else:
        st.info("Henuz otomatik odev olusturulmamis.")


def _render_sonuc_ogrenci_detay(results: list, store, level, sinif, sube):
    """Individual student detailed result view — sonuc belgesi style."""
    import pandas as pd

    # Student selection
    student_names = sorted(set(r.student_name for r in results))
    selected_student = st.selectbox("Ogrenci Sec:", student_names, key="olcme36_sonuc_student")
    student_results = [r for r in results if r.student_name == selected_student]

    if not student_results:
        return

    # ── Sonuc Belgesi Header ──
    latest = student_results[-1]
    all_scores = [r.score for r in student_results]
    avg_score = sum(all_scores) / len(all_scores) if all_scores else 0
    color = "#059669" if avg_score >= 70 else "#f59e0b" if avg_score >= 50 else "#dc2626"

    st.markdown(
        f'<div style="background:linear-gradient(135deg,#1e1b4b,#312e81);color:#fff;'
        f'padding:20px 24px;border-radius:14px;margin:10px 0;">'
        f'<div style="display:flex;justify-content:space-between;align-items:center;">'
        f'<div>'
        f'<div style="font-size:1.3rem;font-weight:800;">{selected_student}</div>'
        f'<div style="font-size:.85rem;opacity:.8;margin-top:2px;">'
        f'{sinif}. Sinif {sube} | {level.replace("grade","").title()} | '
        f'{len(student_results)} sinav</div></div>'
        f'<div style="text-align:right;">'
        f'<div style="font-size:2.2rem;font-weight:900;color:{color};">{avg_score:.1f}</div>'
        f'<div style="font-size:.8rem;opacity:.7;">Genel Ortalama</div></div>'
        f'</div></div>',
        unsafe_allow_html=True,
    )

    # ── Sinav Gecmisi Trend ──
    if len(student_results) > 1:
        st.markdown("**Sinav Gecmisi Trend**")
        trend = []
        for r in student_results:
            trend.append({
                "Sinav": r.exam_name[:25],
                "Puan": r.score,
            })
        df_trend = pd.DataFrame(trend)
        st.line_chart(df_trend.set_index("Sinav"), use_container_width=True)

    # ── Puan Kartlari ──
    c1, c2, c3, c4, c5 = st.columns(5)
    with c1:
        st.metric("Ortalama", f"{avg_score:.1f}")
    with c2:
        st.metric("En Yuksek", f"{max(all_scores):.1f}")
    with c3:
        st.metric("En Dusuk", f"{min(all_scores):.1f}")
    with c4:
        total_correct = sum(r.correct_count for r in student_results)
        total_q = sum(r.total_questions for r in student_results)
        st.metric("Toplam D/Y", f"{total_correct}/{total_q}")
    with c5:
        pass_count = sum(1 for s in all_scores if s >= 70)
        st.metric("Gecen Sinav", f"{pass_count}/{len(all_scores)}")

    # ── Beceri Bazli Analiz ──
    st.markdown("---")
    st.markdown("**Beceri Bazli Performans**")
    stu_skills: dict[str, dict] = {}
    for r in student_results:
        for sk, data in r.skill_breakdown.items():
            if sk not in stu_skills:
                stu_skills[sk] = {"correct": 0, "total": 0}
            stu_skills[sk]["correct"] += data.get("correct", 0)
            stu_skills[sk]["total"] += data.get("total", 0)

    if stu_skills:
        skill_labels = {"vocabulary": "Kelime", "grammar": "Dilbilgisi", "other": "Diger"}
        sk_rows = []
        for sk, data in stu_skills.items():
            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
            sk_rows.append({
                "Beceri": skill_labels.get(sk, sk.title()),
                "Dogru": data["correct"],
                "Toplam": data["total"],
                "Basari %": round(pct, 1),
            })
        df_sk = pd.DataFrame(sk_rows)
        col1, col2 = st.columns([0.6, 0.4])
        with col1:
            st.bar_chart(df_sk.set_index("Beceri")["Basari %"], use_container_width=True)
        with col2:
            st.dataframe(df_sk, use_container_width=True, hide_index=True)

    # ── Tema/Kazanim Bazli Analiz ──
    st.markdown("---")
    st.markdown("**Tema (Kazanim) Bazli Performans**")
    stu_themes: dict[str, dict] = {}
    for r in student_results:
        for th, data in r.theme_breakdown.items():
            if th not in stu_themes:
                stu_themes[th] = {"correct": 0, "total": 0}
            stu_themes[th]["correct"] += data.get("correct", 0)
            stu_themes[th]["total"] += data.get("total", 0)

    if stu_themes:
        th_rows = []
        for th, data in sorted(stu_themes.items()):
            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
            th_rows.append({
                "Tema/Kazanim": th,
                "Dogru": data["correct"],
                "Toplam": data["total"],
                "Basari %": round(pct, 1),
            })
        df_th = pd.DataFrame(th_rows)
        st.bar_chart(df_th.set_index("Tema/Kazanim")["Basari %"], use_container_width=True)
        st.dataframe(df_th, use_container_width=True, hide_index=True)

        # Weak themes
        weak = [t for t in th_rows if t["Basari %"] < 60]
        strong = [t for t in th_rows if t["Basari %"] >= 85]
    else:
        weak = []
        strong = []

    # ── Soru Detay (son sinav) ──
    st.markdown("---")
    st.markdown("**Son Sinav — Soru Bazli Detay**")
    latest_r = student_results[-1]
    for i, d in enumerate(latest_r.details):
        is_ok = d.get("is_correct", False)
        icon = "correct" if is_ok else ("empty" if not d.get("selected") else "wrong")
        colors = {"correct": "#059669", "wrong": "#dc2626", "empty": "#6b7280"}
        icons = {"correct": "O", "wrong": "X", "empty": "-"}
        st.markdown(
            f'<div style="background:{colors[icon]}08;border-left:3px solid {colors[icon]};'
            f'padding:8px 12px;border-radius:6px;margin:4px 0;">'
            f'<b style="color:{colors[icon]};">[{icons[icon]}] Soru {i+1}</b> '
            f'({d.get("skill","")}) — {d.get("theme","")}<br>'
            f'<span style="font-size:13px;">{d.get("stem","")}</span><br>'
            f'<span style="font-size:12px;color:#6b7280;">'
            f'Dogru: <b>{d.get("correct_text", d.get("correct",""))}</b>'
            f'{" | Secilen: " + d.get("selected_text", d.get("selected","")) if d.get("selected") else " | Bos birakildi"}'
            f'</span>'
            f'</div>',
            unsafe_allow_html=True,
        )

    # ── AI Analiz & Tavsiye Belgesi ──
    st.markdown("---")
    st.markdown(
        '<div style="background:linear-gradient(135deg,#7c3aed,#a855f7);color:#fff;'
        'padding:16px 20px;border-radius:12px;margin:10px 0;">'
        '<h4 style="margin:0;font-size:17px;">AI Analiz & Tavsiye Raporu</h4>'
        '<p style="margin:4px 0 0;font-size:12px;opacity:.85;">'
        'Ogrenci performansina dayali otomatik degerlendirme</p></div>',
        unsafe_allow_html=True,
    )

    # ── Sonuc Belgesi (OD stili) ──
    _render_yd_sonuc_belgesi(selected_student, sinif, sube, level, avg_score,
                              student_results, stu_skills, weak, strong, store)


def _render_yd_sonuc_belgesi(student_name, sinif, sube, level, avg_score,
                              student_results, stu_skills, weak_themes, strong_themes, store):
    """Render AI-powered sonuc belgesi matching OD module style."""

    # Performance band
    if avg_score >= 85:
        band, band_color = "USTUN BASARI", "#059669"
    elif avg_score >= 70:
        band, band_color = "BASARILI", "#2563eb"
    elif avg_score >= 50:
        band, band_color = "GELISIM GEREKLI", "#f59e0b"
    else:
        band, band_color = "DESTEK GEREKLI", "#dc2626"

    # ── Genel Degerlendirme ──
    latest = student_results[-1]
    total_correct = sum(r.correct_count for r in student_results)
    total_q = sum(r.total_questions for r in student_results)

    st.markdown(
        f'<div style="background:{band_color}10;border:2px solid {band_color};'
        f'padding:16px 20px;border-radius:12px;margin:8px 0;">'
        f'<div style="font-size:1.2rem;font-weight:800;color:{band_color};">{band}</div>'
        f'<div style="font-size:.9rem;color:#94A3B8;margin-top:6px;">'
        f'{student_name}, {sinif}. Sinif {sube} subi Ingilizce dersinde '
        f'{len(student_results)} sinav sonucuna gore <b>{avg_score:.1f}</b> genel ortalama ile '
        f'<b style="color:{band_color};">{band}</b> kategorisindedir. '
        f'Toplam {total_q} sorudan {total_correct} tanesini dogru cevaplamistir.</div></div>',
        unsafe_allow_html=True,
    )

    # ── Guclu Yonler ──
    col_a, col_b = st.columns(2)
    with col_a:
        st.markdown("**Guclu Yonler:**")
        if strong_themes:
            for s in strong_themes:
                st.markdown(
                    f'<div style="background:#f0fdf4;border-left:3px solid #059669;'
                    f'padding:6px 10px;border-radius:4px;margin:3px 0;">'
                    f'<b>{s["Tema/Kazanim"]}</b> — {s["Basari %"]:.0f}%</div>',
                    unsafe_allow_html=True,
                )
        else:
            st.markdown("_Henuz belirgin guclu alan tanimlanmamistir._")

        # Skill strengths
        skill_labels = {"vocabulary": "Kelime", "grammar": "Dilbilgisi", "other": "Diger"}
        for sk, data in stu_skills.items():
            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
            if pct >= 75:
                st.markdown(f"- {skill_labels.get(sk, sk.title())} becerisinde **{pct:.0f}%** basari")

    # ── Gelistirilmesi Gereken Alanlar ──
    with col_b:
        st.markdown("**Gelistirilmesi Gereken Alanlar:**")
        if weak_themes:
            for w in weak_themes:
                st.markdown(
                    f'<div style="background:#fef2f2;border-left:3px solid #dc2626;'
                    f'padding:6px 10px;border-radius:4px;margin:3px 0;">'
                    f'<b>{w["Tema/Kazanim"]}</b> — {w["Basari %"]:.0f}%</div>',
                    unsafe_allow_html=True,
                )
        else:
            st.markdown("_Tum alanlarda yeterli performans gostermektedir._")

        for sk, data in stu_skills.items():
            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
            if pct < 60:
                st.markdown(f"- {skill_labels.get(sk, sk.title())} becerisinde **{pct:.0f}%** — gelisim gerekli")

    # ── Tavsiyeler ──
    st.markdown("---")
    st.markdown("**Tavsiyeler:**")
    tavsiye_no = 1
    if weak_themes:
        for w in weak_themes:
            rec = _get_theme_recommendation(w["Tema/Kazanim"])
            st.markdown(f"{tavsiye_no}. **{w['Tema/Kazanim']}:** {rec}")
            tavsiye_no += 1

    if avg_score < 50:
        st.markdown(f"{tavsiye_no}. Birebir etut programi ile desteklenmelidir.")
        tavsiye_no += 1
        st.markdown(f"{tavsiye_no}. Gunluk 15 dakika kelime tekrari yapmalidir.")
        tavsiye_no += 1
    elif avg_score < 70:
        st.markdown(f"{tavsiye_no}. Haftalik ekstra quiz ile pekistirme yapilmalidir.")
        tavsiye_no += 1
    else:
        st.markdown(f"{tavsiye_no}. Ileri seviye okuma ve yazma etkinlikleri ile desteklenmelidir.")
        tavsiye_no += 1

    # ── 4 Haftalik Calisma Programi ──
    st.markdown("---")
    st.markdown("**4 Haftalik Calisma Programi:**")
    if weak_themes:
        weak_names = [w["Tema/Kazanim"] for w in weak_themes[:3]]
        st.markdown(f"- **Hafta 1:** {weak_names[0] if len(weak_names) > 0 else 'Genel tekrar'} — Kelime kartlari ve eslestirme oyunlari")
        st.markdown(f"- **Hafta 2:** {weak_names[1] if len(weak_names) > 1 else weak_names[0] if weak_names else 'Genel tekrar'} — Cumle yapilari ve fill-in-blank alistirmalari")
        st.markdown(f"- **Hafta 3:** Tum zayif temalar — Karisik quiz ve diyalog pratikleri")
        st.markdown(f"- **Hafta 4:** Degerlendirme sinavi — Gelisim olcumu ve kiyaslama")
    else:
        st.markdown("- **Hafta 1-2:** Mevcut seviyeyi pekistirme — Okuma ve dinleme aktiviteleri")
        st.markdown("- **Hafta 3-4:** Ileri seviye — Yazma portfolyo ve sunum calismasi")

    # ── Geri Bildirim ──
    if avg_score >= 85:
        geri = f"{student_name} dil ogreniminde cok basarili bir performans sergilemektedir. Motivasyonunu korumak icin zorlayici gorevler verilmelidir."
    elif avg_score >= 70:
        geri = f"{student_name} genel olarak basarili ancak bazi konularda pekistirmeye ihtiyac duymaktadir. Duzenli tekrar ile basarisi artacaktir."
    elif avg_score >= 50:
        geri = f"{student_name} temel becerilerde gelisim gostermektedir ancak sistematik calisma ile desteklenmelidir. Veli isbirligi onemlidir."
    else:
        geri = f"{student_name} acil destek programina alinmalidir. Bireysel ogretim plani olusturulmali ve gunluk pratik yapilmalidir."

    st.info(f"**Geri Bildirim:** {geri}")

    # ── Otomatik Odevler (Telafi) Durumu ──
    latest_r = student_results[-1]
    rem_list = store.get_remediation(student_id=latest_r.student_id)
    if rem_list:
        st.markdown("---")
        st.markdown("**Otomatik Telafi Odevleri:**")
        for rem in rem_list:
            status_label = "Tamamlandi" if rem.status == "completed" else "Bekliyor"
            status_color = "#059669" if rem.status == "completed" else "#f59e0b"
            topics_str = ", ".join(set(wt.get("theme", "") for wt in rem.wrong_topics[:3]))
            st.markdown(
                f'<div style="background:{status_color}08;border-left:3px solid {status_color};'
                f'padding:10px 14px;border-radius:6px;margin:4px 0;">'
                f'<b>Telafi:</b> {topics_str} | '
                f'{rem.total_questions} soru | '
                f'<b style="color:{status_color};">{status_label}</b>'
                f'{f" | Puan: {rem.score:.0f}/100" if rem.status == "completed" else ""}'
                f'</div>',
                unsafe_allow_html=True,
            )


def _get_theme_recommendation(theme: str) -> str:
    """Return a specific recommendation based on weak theme."""
    recs = {
        "Back to School": "Okul kelimelerini flashcard ve eslestirme oyunlariyla pekistirin.",
        "My Daily Routine": "Gunluk rutin cumle kaliplarini tekrarlayarak pratikyapin.",
        "My Family": "Aile agaci etkinligi ve rol play ile destekleyin.",
        "Animals & Nature": "Hayvan kartlari ve siniflandirma oyunlari ile destekleyin.",
        "Food & Shopping": "Alisveris diyaloglari ve menu okuma etkinlikleri onerilir.",
        "Hobbies & Free Time": "Hobi anketi ve esli konusma pratikleri yapin.",
        "Seasons & Weather": "Hava durumu gunlugu tutma etkinligi onerilir.",
        "Jobs & Careers": "Meslek tanitim posterleri ve roportaj etkinligi yapin.",
    }
    return recs.get(theme,
        f"'{theme}' konusundaki kelime ve yapi calismalarina agirlik verin. "
        f"Gunluk 10 dk kelime tekrari + haftalik kisa quiz ile pekistirin."
    )


# ── TAB 5: Quiz / Yazili / Deneme (multi-week) ──────────────────────────────

def _render_olcme36_multi_week(store: YdAssessmentStore, level: str, sinif: int, sube: str):
    """Create Quiz, Yazili, or Deneme from multiple weeks."""
    st.markdown(
        '<div style="background:#f5f3ff;border-left:4px solid #7c3aed;padding:12px 16px;'
        'border-radius:8px;margin-bottom:12px;">'
        '<b>Quiz / Okul Yazilisi / Deneme Sinavi Hazirla</b> — '
        'Birden fazla hafta secip kapsamli sinav olusturun.'
        '</div>',
        unsafe_allow_html=True,
    )

    covered = store.get_covered_weeks(level, sinif, sube)
    covered_weeks_sorted = sorted([int(w) for w in covered.keys()])

    if not covered_weeks_sorted:
        st.info("Islenmis hafta yok. Once konu takibinden haftalari isaretleyin.")
        return

    col1, col2 = st.columns(2)
    with col1:
        exam_type = st.selectbox(
            "Sinav Turu:",
            ["quiz", "yazili", "deneme"],
            format_func=lambda x: EXAM_CATEGORIES.get(x, x),
            key="olcme36_multi_type",
        )
    with col2:
        default_count = CATEGORY_QUESTION_COUNTS.get(exam_type, 15)
        q_count = st.slider("Soru Sayisi:", 5, 50, default_count, key="olcme36_multi_q_count")

    # Week selection
    selected_weeks = st.multiselect(
        "Haftalar:",
        covered_weeks_sorted,
        format_func=lambda w: f"H{w} — {_get_week_theme(level, w)}",
        key="olcme36_multi_weeks",
    )

    if not selected_weeks:
        st.info("Sinav icin en az bir hafta seciniz.")
        return

    # Duration based on type
    duration_map = {"quiz": 20, "yazili": 40, "deneme": 60}
    duration = duration_map.get(exam_type, 20)

    st.markdown(
        f'<div style="background:#e0e7ff;padding:10px 14px;border-radius:8px;margin:8px 0;">'
        f'<b>{EXAM_CATEGORIES[exam_type]}</b> | '
        f'{len(selected_weeks)} hafta | {q_count} soru | {duration} dk</div>',
        unsafe_allow_html=True,
    )

    if st.button("Sinav Olustur", key="olcme36_multi_create", type="primary", use_container_width=True):
        generator = YdQuestionGenerator(_CURRICULUM)
        questions = generator.generate(level, selected_weeks, exam_type, q_count)
        if not questions:
            st.error("Soru uretilemedi.")
            return

        weeks_label = f"H{min(selected_weeks)}-H{max(selected_weeks)}"
        cat_label = EXAM_CATEGORIES[exam_type]
        exam = YdExam(
            name=f"{cat_label} — {weeks_label} ({sinif}. Sinif {sube})",
            category=exam_type,
            grade=sinif,
            sinif=sinif,
            sube=sube,
            level=level,
            weeks=selected_weeks,
            questions=[q.to_dict() for q in questions],
            total_points=sum(q.points for q in questions),
            duration_minutes=duration,
            status="draft",
        )
        exam = store.save_exam(exam)
        st.success(f"**{exam.name}** olusturuldu! ({len(questions)} soru)")

        c1, c2 = st.columns(2)
        with c1:
            if st.button("Hemen Gonder", key="olcme36_multi_send", type="primary"):
                exam.status = "sent"
                exam.sent_at = datetime.now().isoformat()
                exam.deadline = (datetime.now() + timedelta(days=7)).isoformat()
                store.save_exam(exam)
                st.success("Sinav ogrencilere gonderildi!")
                st.rerun()

    # Existing multi-week exams
    all_exams = store.get_exams(level=level, sinif=sinif, sube=sube)
    multi_exams = [e for e in all_exams if e.category != "haftalik"]
    if multi_exams:
        st.markdown("---")
        st.markdown("**Olusturulan Quiz / Yazili / Deneme Sinavlari:**")
        for ex in sorted(multi_exams, key=lambda e: e.created_at, reverse=True)[:10]:
            cat_label = EXAM_CATEGORIES.get(ex.category, ex.category)
            status_map = {
                "draft": "Taslak", "sent": "Gonderildi",
                "completed": "Tamamlandi", "archived": "Arsivlendi",
            }
            weeks_str = ", ".join(str(w) for w in ex.weeks)
            st.markdown(
                f"- **{ex.name}** | {cat_label} | Hafta: {weeks_str} | "
                f'{status_map.get(ex.status, ex.status)} | {len(ex.questions)} soru'
            )
            if ex.status == "draft":
                if st.button("Gonder", key=f"olcme36_multi_send_{ex.id}"):
                    ex.status = "sent"
                    ex.sent_at = datetime.now().isoformat()
                    ex.deadline = (datetime.now() + timedelta(days=7)).isoformat()
                    store.save_exam(ex)
                    st.success("Gonderildi!")
                    st.rerun()


# ── VELI PANELI ENTEGRASYONU ─────────────────────────────────────────────────

def _render_veli_yd_sinavlar(sinif, sube=None):
    """Render student exams section in parent panel.
    Called from render_veli_english_tab()."""
    if not sinif or not sube:
        return

    level = _yd_sinif_to_level(sinif)
    if not level:
        return

    store = _get_yd_assessment_store()
    sent_exams = store.get_exams(level=level, sinif=int(sinif), sube=sube, status="sent")
    if not sent_exams:
        return

    st.markdown(
        '<div style="background:linear-gradient(135deg,#be123c,#e11d48);color:#fff;'
        'padding:14px 18px;border-radius:12px;margin:12px 0;text-align:center;">'
        '<h4 style="margin:0;font-size:16px;">Ingilizce Sinavlari</h4>'
        '<p style="margin:3px 0 0;font-size:12px;opacity:0.85;">'
        'Ogretmenin gonderdigi sinavlar</p></div>',
        unsafe_allow_html=True,
    )

    # Student selection (parent picks their child)
    try:
        from utils.shared_data import get_student_display_options
        students = get_student_display_options(sinif_filter=int(sinif), sube_filter=sube, include_empty=False)
    except Exception:
        students = {}

    if not students:
        st.info("Kayitli ogrenci bulunamadi.")
        return

    student_name = st.selectbox("Ogrenci:", list(students.keys()), key="veli_yd_sinav_student")
    if not student_name:
        return
    student_data = students[student_name]
    student_id = student_data.get("id", student_name)

    # Check submitted
    student_answers = store.get_student_answers(student_id=student_id)
    submitted_ids = {a.exam_id for a in student_answers if a.status == "submitted"}

    pending = [e for e in sent_exams if e.id not in submitted_ids]
    done = [e for e in sent_exams if e.id in submitted_ids]

    if pending:
        for exam in pending:
            with st.expander(f"Bekleyen: {exam.name} ({len(exam.questions)} soru)", expanded=True):
                _render_olcme36_take_exam(store, exam, student_id, student_name, int(sinif), sube)

    if done:
        st.markdown("**Tamamlanan Sinavlar:**")
        for exam in done:
            exam_results = store.get_results(exam_id=exam.id, student_id=student_id)
            if exam_results:
                r = exam_results[0]
                color = "#059669" if r.score >= 70 else "#f59e0b" if r.score >= 50 else "#dc2626"
                st.markdown(
                    f'<div style="background:{color}10;border-left:3px solid {color};'
                    f'padding:8px 12px;border-radius:6px;margin:4px 0;">'
                    f'<b>{exam.name}</b> — '
                    f'<span style="color:{color};font-weight:700;">{r.score:.1f} puan</span> | '
                    f'{r.correct_count}/{r.total_questions} dogru</div>',
                    unsafe_allow_html=True,
                )

                # Soru detay + analiz
                with st.expander(f"Detay: {exam.name}", expanded=False):
                    # Skill breakdown
                    if r.skill_breakdown:
                        skill_labels = {"vocabulary": "Kelime", "grammar": "Dilbilgisi", "other": "Diger"}
                        for sk, data in r.skill_breakdown.items():
                            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
                            sk_color = "#059669" if pct >= 70 else "#f59e0b" if pct >= 50 else "#dc2626"
                            st.markdown(
                                f'{skill_labels.get(sk, sk.title())}: '
                                f'<b style="color:{sk_color};">{pct:.0f}%</b> '
                                f'({data["correct"]}/{data["total"]})',
                                unsafe_allow_html=True,
                            )

                    # Wrong/empty answers
                    wrong_items = [d for d in r.details if not d.get("is_correct")]
                    if wrong_items:
                        st.markdown("**Yanlis/Bos Sorular:**")
                        for d in wrong_items:
                            st.markdown(
                                f'<div style="background:#fef2f210;border-left:2px solid #dc2626;'
                                f'padding:6px 10px;border-radius:4px;margin:3px 0;font-size:13px;">'
                                f'{d.get("stem","")[:80]}<br>'
                                f'Dogru: <b>{d.get("correct_text", d.get("correct",""))}</b>'
                                f'</div>',
                                unsafe_allow_html=True,
                            )

                    # AI tavsiye
                    if r.score < 70:
                        weak_themes = [th for th, data in r.theme_breakdown.items()
                                       if data["total"] > 0 and (data["correct"] / data["total"] * 100) < 60]
                        if weak_themes:
                            st.markdown("**Tavsiye:**")
                            for wt in weak_themes:
                                rec = _get_theme_recommendation(wt)
                                st.markdown(f"- **{wt}:** {rec}")

    # ── Otomatik Odevler (Telafi) ──
    rem_list = store.get_remediation(student_id=student_id)
    pending_rem = [r for r in rem_list if r.status == "sent"]
    if pending_rem:
        st.markdown(
            '<div style="background:linear-gradient(135deg,#92400e,#d97706);color:#fff;'
            'padding:12px 16px;border-radius:10px;margin:12px 0;text-align:center;">'
            '<h4 style="margin:0;font-size:15px;">Telafi Odevleri</h4>'
            '<p style="margin:2px 0 0;font-size:11px;opacity:.85;">'
            'Sinav sonrasi otomatik olusturulan pekistirme odevleri</p></div>',
            unsafe_allow_html=True,
        )
        for rem in pending_rem:
            with st.expander(f"Telafi Odevi ({rem.total_questions} soru) — {len(rem.wrong_topics)} eksik konu", expanded=True):
                # Show wrong topics
                st.markdown("**Eksik Konular:**")
                for wt in rem.wrong_topics[:5]:
                    st.markdown(f"- H{wt.get('week','?')} {wt.get('theme','')}: {wt.get('stem','')[:60]}")

                # Render homework questions
                hw_questions = [YdQuestion.from_dict(q) for q in rem.homework_questions]
                hw_answers = {}
                for i, q in enumerate(hw_questions):
                    st.markdown(f"---\n**Soru {i+1}** ({q.skill})")
                    st.markdown(q.stem)
                    if q.choices:
                        choice_labels = [f"{k}) {v}" for k, v in sorted(q.choices.items())]
                        sel = st.radio(
                            f"Cevap:", choice_labels,
                            key=f"veli_rem_{rem.id}_q{i}",
                            index=None, label_visibility="collapsed",
                        )
                        if sel:
                            hw_answers[q.id] = sel.split(")")[0].strip()

                st.markdown(f"---\n**Cevaplanan:** {len(hw_answers)} / {len(hw_questions)}")
                if st.button("Odevi Gonder", key=f"veli_rem_submit_{rem.id}", type="primary"):
                    if not hw_answers:
                        st.error("En az bir soruyu cevaplayin.")
                    else:
                        # Grade remediation
                        correct = 0
                        for q in hw_questions:
                            if hw_answers.get(q.id, "").upper() == q.correct.upper():
                                correct += 1
                        rem.answers = hw_answers
                        rem.score = round((correct / len(hw_questions)) * 100, 1) if hw_questions else 0
                        rem.status = "completed"
                        rem.completed_at = datetime.now().isoformat()
                        store.save_remediation(rem)
                        st.success(f"Odev tamamlandi! Puan: {rem.score:.0f}/100 ({correct}/{len(hw_questions)} dogru)")
                        st.rerun()


