# ── Unite -> Hafta haritalama ──────────────────────────────────────────────────

_UNIT_BREAKS = [4, 7, 11, 14, 18, 22, 25, 29, 32, 37]


def _unit_to_weeks(unit_num: int) -> list[int]:
    """Unite numarasindan (1-10) hafta listesini dondurur."""
    if unit_num < 1 or unit_num > 10:
        return []
    start = _UNIT_BREAKS[unit_num - 2] if unit_num > 1 else 1
    end = _UNIT_BREAKS[unit_num - 1] - 1
    return list(range(start, end + 1))


def _get_unit_theme(level: str, unit_num: int) -> str:
    """Unite temasi — ilk haftanin temasini dondurur."""
    weeks = _unit_to_weeks(unit_num)
    if not weeks:
        return f"Unite {unit_num}"
    curriculum = _CURRICULUM.get(level, [])
    for w in curriculum:
        if w.get("week") == weeks[0]:
            return w.get("theme", w.get("unit_theme", f"Unite {unit_num}"))
    return f"Unite {unit_num}"


def _get_unit_theme_tr(level: str, unit_num: int) -> str:
    """Unite temasi (Turkce)."""
    weeks = _unit_to_weeks(unit_num)
    if not weeks:
        return f"Unite {unit_num}"
    curriculum = _CURRICULUM.get(level, [])
    for w in curriculum:
        if w.get("week") == weeks[0]:
            return w.get("theme_tr", w.get("unit_theme_tr", ""))
    return ""


# ── Ana giris noktasi ──────────────────────────────────────────────────────────

def _render_yd_quiz_tab():
    """Unite Quiz Sistemi — unite bazli quiz olustur, online sinav, sonuc karnesi.

    Ogrenci paneli yonlendirmesi: Eger st.session_state['yd_quiz_target_tab']
    set edilmisse direkt o sekmeyi acar (ogrenci kendi quizini cozmek icin
    'ogrenci' atayabilir). Auto-fill icin yd_quiz_student_id de kullanilabilir.
    """
    # Eger ogrenci panelinden direkt yonlendirme geldiyse, ogrenci modunu zorla
    target_tab = st.session_state.get("yd_quiz_target_tab", None)

    _olcme36_styled_header(
        "Unite Quiz Sistemi",
        "Unite bazli quiz olustur | Ogretmen baslatir | Ogrenci cozer | Otomatik sonuc karnesi",
    )

    # Ogrenci modu: kendi rolundeyse global filtre yerine kendi sinifini kullan
    _g_yil = _g_sinif = _g_sube = _g_level = None
    auto_student = None
    if target_tab == "ogrenci":
        # Auth user'dan ogrenci kimlik bilgisini cek
        try:
            from utils.auth import AuthManager
            auth_user = AuthManager.get_current_user() or {}
            if auth_user.get("role") == "student":
                from models.akademik_takip import AkademikDataStore
                _ak = AkademikDataStore()
                # Username veya numara ile ogrenciyi bul
                _uname = auth_user.get("username", "")
                _stu_no = auth_user.get("student_number", "") or _uname
                _all_stu = _ak.get_students()
                for s in _all_stu:
                    if s.numara == _stu_no or s.id == _uname:
                        auto_student = s
                        break
                if auto_student:
                    _g_sinif = int(auto_student.sinif) if auto_student.sinif else 0
                    _g_sube = auto_student.sube
                    _g_level = f"grade{_g_sinif}" if 1 <= _g_sinif <= 12 else None
                    # Ogrenci icin auto-fill
                    st.session_state["yd_quiz_student_sel"] = f"{auto_student.ad} {auto_student.soyad} ({auto_student.numara})"
                    st.session_state["_yd_auto_student"] = auto_student
        except Exception:
            pass

    if _g_sinif is None or _g_sube is None or _g_level is None:
        _g_yil, _g_sinif, _g_sube, _g_level = _yd_get_global_filters()
    if not _g_sinif or not _g_sube or not _g_level:
        st.warning("Lutfen ustdeki filtrelerden **Sinif** ve **Sube** seciniz.")
        return

    store = _get_yd_assessment_store()

    # Ogrenci modunda sadece "Ogrenci Quiz Ekrani" goster — daha sade UX
    if target_tab == "ogrenci" and auto_student:
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#1e1b4b,#4338ca);color:#fff;'
            f'padding:14px 18px;border-radius:12px;margin-bottom:14px;">'
            f'<div style="font-size:1.1rem;font-weight:800;">'
            f'\U0001F393 Hosgeldin, {auto_student.ad} {auto_student.soyad}!</div>'
            f'<div style="font-size:.85rem;opacity:.9;margin-top:3px;">'
            f'Asagidaki bekleyen Ingilizce quizlerini cozebilirsin. Suren basladiginda saat isleyecek.</div>'
            f'</div>',
            unsafe_allow_html=True,
        )
        # Ogrenci icin direkt ogrenci ekrani
        _render_quiz_ogrenci_ekrani(store, _g_level, _g_sinif, _g_sube,
                                    forced_student=auto_student)
        # Cikis butonu — ogretmen modu icin
        if st.button("← Quiz Sistemine Donus", key="yd_quiz_back_teacher"):
            st.session_state.pop("yd_quiz_target_tab", None)
            st.session_state.pop("_yd_auto_student", None)
            st.rerun()
        return

    # Ogretmen / yonetici modu: 4 sekme
    tab_names = [
        "\U0001F4DD Quiz Olustur",
        "\U0001F3AE Quiz Yonetimi",
        "\U0001F393 Ogrenci Quiz Ekrani",
        "\U0001F4CA Quiz Sonuclari & Karne",
    ]
    tabs = st.tabs(tab_names)

    with tabs[0]:
        _render_quiz_olustur(store, _g_level, _g_sinif, _g_sube)
    with tabs[1]:
        _render_quiz_yonetimi(store, _g_level, _g_sinif, _g_sube)
    with tabs[2]:
        _render_quiz_ogrenci_ekrani(store, _g_level, _g_sinif, _g_sube)
    with tabs[3]:
        _render_quiz_sonuclari(store, _g_level, _g_sinif, _g_sube)


# ── TAB 1: Quiz Olustur ───────────────────────────────────────────────────────

def _render_quiz_olustur(store: YdAssessmentStore, level: str, sinif: int, sube: str):
    """Ogretmen unite bazli quiz olusturur."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#1e1b4b,#4338ca);color:#fff;'
        'padding:14px 18px;border-radius:12px;margin-bottom:14px;">'
        '<h4 style="margin:0;font-size:17px;">\U0001F4DD Unite Bazli Quiz Olustur</h4>'
        '<p style="margin:3px 0 0;font-size:12px;opacity:.85;">'
        'Unite secin, soru sayisi belirleyin, otomatik quiz olusturun</p></div>',
        unsafe_allow_html=True,
    )

    # Unite secimi
    unit_options = list(range(1, 11))
    col1, col2, col3 = st.columns(3)
    with col1:
        selected_unit = st.selectbox(
            "Unite:",
            unit_options,
            format_func=lambda u: f"Unite {u}: {_get_unit_theme(level, u)}",
            key="yd_quiz_unit_sel",
        )
    with col2:
        q_count = st.slider("Soru Sayisi:", 5, 25, 15, key="yd_quiz_q_count")
    with col3:
        duration = st.slider("Sure (dk):", 5, 45, 20, key="yd_quiz_duration")

    unit_theme = _get_unit_theme(level, selected_unit)
    unit_theme_tr = _get_unit_theme_tr(level, selected_unit)
    unit_weeks = _unit_to_weeks(selected_unit)

    # Unite bilgi kutusu
    st.markdown(
        f'<div style="background:#eff6ff;border-left:4px solid #3b82f6;padding:10px 14px;'
        f'border-radius:8px;margin:8px 0;">'
        f'<b>Unite {selected_unit}:</b> {unit_theme}'
        f'{" (" + unit_theme_tr + ")" if unit_theme_tr else ""} | '
        f'Haftalar: {", ".join(str(w) for w in unit_weeks)}</div>',
        unsafe_allow_html=True,
    )

    # Mevcut quiz kontrol
    existing_quizzes = store.get_exams(level=level, sinif=sinif, sube=sube, category="quiz")
    unit_quizzes = [e for e in existing_quizzes if getattr(e, "unit", 0) == selected_unit]

    if unit_quizzes:
        latest = unit_quizzes[-1]
        st.info(f"Unite {selected_unit} icin mevcut quiz: **{latest.name}** (Durum: {latest.status})")

    # Quiz olustur butonu
    if st.button("\U0001F680 Quiz Olustur", key="yd_quiz_create_btn", type="primary", use_container_width=True):
        generator = YdQuestionGenerator(_CURRICULUM)
        questions = generator.generate(level, unit_weeks, "quiz", q_count)
        if not questions:
            st.error("Soru uretilemedi. Bu unite icin mufredat verisi eksik olabilir.")
            return

        quiz_name = f"Unite {selected_unit}: {unit_theme} — Quiz"
        exam = YdExam(
            name=quiz_name,
            category="quiz",
            grade=sinif,
            sinif=sinif,
            sube=sube,
            level=level,
            weeks=unit_weeks,
            unit=selected_unit,
            unit_theme=unit_theme,
            questions=[q.to_dict() for q in questions],
            total_points=sum(q.points for q in questions),
            duration_minutes=duration,
            status="draft",
        )
        exam = store.save_exam(exam)
        st.success(f"Quiz olusturuldu: **{quiz_name}** ({len(questions)} soru, {duration} dk)")
        st.rerun()

    # Olusturulan quizler listesi
    if unit_quizzes:
        st.markdown("---")
        st.markdown(
            '<div style="background:linear-gradient(135deg,#1e1b4b,#4338ca);'
            'color:#fff;padding:10px 16px;border-radius:10px;margin:10px 0 8px;">'
            '<div style="font-size:1rem;font-weight:800;color:#fff;">'
            '\U0001F4DD Bu Unite icin Olusturulan Quizler</div>'
            f'<div style="font-size:.78rem;color:#c7d2fe;margin-top:2px;">'
            f'{len(unit_quizzes)} quiz mevcut</div></div>',
            unsafe_allow_html=True,
        )
        for ex in sorted(unit_quizzes, key=lambda e: e.created_at, reverse=True):
            _status_map = {"draft": ("Taslak", "#f59e0b", "#fffbeb"),
                           "sent": ("Gonderildi", "#2563eb", "#eff6ff"),
                           "started": ("Basladi", "#059669", "#ecfdf5"),
                           "completed": ("Tamamlandi", "#6b7280", "#f3f4f6"),
                           "archived": ("Arsivlendi", "#9ca3af", "#f3f4f6")}
            s_label, s_color, s_bg = _status_map.get(ex.status, (ex.status, "#6b7280", "#f3f4f6"))
            st.markdown(
                f'<div style="background:{s_bg};border-left:4px solid {s_color};'
                f'border:1px solid {s_color}44;border-left-width:4px;'
                f'padding:10px 14px;border-radius:8px;margin:6px 0;'
                f'box-shadow:0 1px 4px rgba(0,0,0,0.05);">'
                f'<div style="font-size:1rem;font-weight:800;color:#0f172a;">{ex.name}</div>'
                f'<div style="font-size:.82rem;color:#334155;margin-top:4px;">'
                f'<b style="color:#1e3a8a;">{len(ex.questions)} soru</b> · '
                f'<b style="color:#1e3a8a;">{ex.duration_minutes} dk</b> · '
                f'<span style="background:{s_color};color:#fff;padding:2px 10px;'
                f'border-radius:10px;font-size:.72rem;font-weight:700;">{s_label}</span>'
                f'</div></div>',
                unsafe_allow_html=True,
            )


# ── TAB 2: Quiz Yonetimi (Gonder, Baslat, Bitir) ──────────────────────────────

def _render_quiz_yonetimi(store: YdAssessmentStore, level: str, sinif: int, sube: str):
    """Ogretmen quiz gonderir, baslatir, bitirir."""
    st.markdown(
        '<div style="background:linear-gradient(135deg,#134e4a,#0d9488);color:#fff;'
        'padding:14px 18px;border-radius:12px;margin-bottom:14px;">'
        '<h4 style="margin:0;font-size:17px;">\U0001F3AE Quiz Yonetimi</h4>'
        '<p style="margin:3px 0 0;font-size:12px;opacity:.85;">'
        'Taslak quizleri gonderin | Baslatin | Bitirin | Arsivleyin</p></div>',
        unsafe_allow_html=True,
    )

    all_quizzes = store.get_exams(level=level, sinif=sinif, sube=sube, category="quiz")
    if not all_quizzes:
        st.info("Henuz quiz olusturulmamis. 'Quiz Olustur' sekmesinden quiz olusturun.")
        return

    # Durum gruplari
    drafts = [e for e in all_quizzes if e.status == "draft"]
    sent = [e for e in all_quizzes if e.status == "sent"]
    started = [e for e in all_quizzes if e.status == "started"]
    completed = [e for e in all_quizzes if e.status == "completed"]

    # ── Istatistik kartlari ──
    c1, c2, c3, c4 = st.columns(4)
    with c1:
        st.metric("Taslak", len(drafts))
    with c2:
        st.metric("Gonderildi", len(sent))
    with c3:
        st.metric("Aktif", len(started))
    with c4:
        st.metric("Tamamlandi", len(completed))

    # ── TASLAK quizler — Gonder butonu ──
    if drafts:
        st.markdown(
            '<div style="background:linear-gradient(135deg,#92400e,#f59e0b);'
            'color:#fff;padding:10px 16px;border-radius:10px;margin:14px 0 6px;">'
            '<div style="font-size:1rem;font-weight:800;color:#fff;">'
            '\U0001F4DD Taslak Quizler</div>'
            f'<div style="font-size:.78rem;color:#fef3c7;margin-top:2px;">'
            f'{len(drafts)} quiz gonderilmeyi bekliyor</div></div>',
            unsafe_allow_html=True,
        )
        for ex in drafts:
            col1, col2, col3 = st.columns([0.5, 0.25, 0.25])
            with col1:
                st.markdown(
                    f'<div style="background:#fffbeb;border:1px solid #f59e0b66;'
                    f'border-left:4px solid #f59e0b;border-radius:8px;'
                    f'padding:10px 14px;margin:4px 0;'
                    f'box-shadow:0 1px 4px rgba(0,0,0,0.05);">'
                    f'<div style="font-size:.95rem;font-weight:800;color:#0f172a;">{ex.name}</div>'
                    f'<div style="font-size:.78rem;color:#334155;margin-top:4px;">'
                    f'<b style="color:#92400e;">{len(ex.questions)} soru</b> · '
                    f'<b style="color:#92400e;">{ex.duration_minutes} dk</b> · '
                    f'<span style="background:#f59e0b;color:#fff;padding:2px 10px;'
                    f'border-radius:10px;font-size:.7rem;font-weight:700;">TASLAK</span>'
                    f'</div></div>',
                    unsafe_allow_html=True,
                )
            with col2:
                if st.button("\U0001F4E8 Gonder", key=f"qy_send_{ex.id}", type="primary",
                             use_container_width=True):
                    ex.status = "sent"
                    ex.sent_at = datetime.now().isoformat()
                    store.save_exam(ex)
                    st.success(f"Quiz gonderildi: {ex.name}")
                    st.rerun()
            with col3:
                if st.button("\U0001F5D1 Sil", key=f"qy_del_{ex.id}",
                             use_container_width=True):
                    records = store._load("exams")
                    records = [r for r in records if r.get("id") != ex.id]
                    store._save("exams", records)
                    st.success("Quiz silindi.")
                    st.rerun()

    # ── GONDERILMIS quizler — Baslat butonu ──
    if sent:
        st.markdown(
            '<div style="background:linear-gradient(135deg,#1e3a8a,#2563eb);'
            'color:#fff;padding:10px 16px;border-radius:10px;margin:14px 0 6px;">'
            '<div style="font-size:1rem;font-weight:800;color:#fff;">'
            '\U0001F4E4 Gonderilmis Quizler (Baslatmaya Hazir)</div>'
            f'<div style="font-size:.78rem;color:#dbeafe;margin-top:2px;">'
            f'{len(sent)} quiz baslatilmaya hazir</div></div>',
            unsafe_allow_html=True,
        )
        for ex in sent:
            col1, col2 = st.columns([0.6, 0.4])
            with col1:
                st.markdown(
                    f'<div style="background:#eff6ff;padding:10px 14px;border-radius:8px;'
                    f'border:1px solid #2563eb44;border-left:4px solid #2563eb;'
                    f'margin:4px 0;box-shadow:0 1px 4px rgba(0,0,0,0.05);">'
                    f'<div style="font-size:.95rem;font-weight:800;color:#0f172a;">{ex.name}</div>'
                    f'<div style="font-size:.78rem;color:#1e3a8a;margin-top:4px;">'
                    f'<b>{len(ex.questions)} soru</b> · <b>{ex.duration_minutes} dk</b> · '
                    f'Gonderim: {ex.sent_at[:16] if ex.sent_at else "-"}</div></div>',
                    unsafe_allow_html=True,
                )
            with col2:
                if st.button("\u25B6 BASLAT", key=f"qy_start_{ex.id}", type="primary", use_container_width=True):
                    ex.status = "started"
                    ex.started_at = datetime.now().isoformat()
                    ex.deadline = (datetime.now() + timedelta(minutes=ex.duration_minutes)).isoformat()
                    store.save_exam(ex)
                    st.success(f"Quiz basladi! Sure: {ex.duration_minutes} dk — Bitis: {ex.deadline[:16]}")
                    st.rerun()

    # ── AKTIF quizler — Bitir butonu + Canli durum ──
    if started:
        st.markdown(
            '<div style="background:linear-gradient(135deg,#065f46,#059669);'
            'color:#fff;padding:10px 16px;border-radius:10px;margin:14px 0 6px;">'
            '<div style="font-size:1rem;font-weight:800;color:#fff;">'
            '\u25B6\uFE0F Aktif Quizler (Devam Ediyor)</div>'
            f'<div style="font-size:.78rem;color:#d1fae5;margin-top:2px;">'
            f'{len(started)} quiz su an cozuluyor</div></div>',
            unsafe_allow_html=True,
        )
        for ex in started:
            # Sure kontrolu
            deadline_dt = datetime.fromisoformat(ex.deadline) if ex.deadline else None
            now = datetime.now()
            remaining = (deadline_dt - now).total_seconds() if deadline_dt else 0
            time_up = remaining <= 0

            # Cevap durumu
            all_answers = store.get_student_answers(exam_id=ex.id)
            submitted_count = sum(1 for a in all_answers if a.status == "submitted")
            try:
                from utils.shared_data import get_student_display_options
                total_students = len(get_student_display_options(
                    sinif_filter=sinif, sube_filter=sube, include_empty=False))
            except Exception:
                total_students = 0

            remaining_min = max(0, int(remaining // 60))
            remaining_sec = max(0, int(remaining % 60))

            if time_up:
                time_text = '<span style="color:#dc2626;font-weight:700;">SURE DOLDU</span>'
            else:
                time_text = f'<span style="color:#059669;font-weight:700;">{remaining_min}:{remaining_sec:02d} kaldi</span>'

            st.markdown(
                f'<div style="background:linear-gradient(135deg,#f0fdf4,#dcfce7);'
                f'padding:14px 18px;border-radius:10px;border:2px solid #059669;margin:6px 0;">'
                f'<div style="font-size:1.05rem;font-weight:700;color:#065f46;">{ex.name}</div>'
                f'<div style="font-size:.9rem;color:#047857;margin-top:4px;">'
                f'Gonderim: {submitted_count}/{total_students} ogrenci | {time_text}</div></div>',
                unsafe_allow_html=True,
            )

            bc1, bc2 = st.columns(2)
            with bc1:
                _bitir_clicked = st.button("\u23F9 BITIR & DEGERLENDIR",
                                           key=f"qy_stop_{ex.id}", type="primary",
                                           use_container_width=True)
                if time_up or _bitir_clicked:
                    # 1) Tum gonderilen cevaplari otomatik puanla
                    _all_ans = store.get_student_answers(exam_id=ex.id)
                    _existing_results = {r.student_id for r in store.get_results(exam_id=ex.id)}
                    _graded_count = 0
                    for _ans in _all_ans:
                        if _ans.status != "submitted":
                            continue
                        if _ans.student_id in _existing_results:
                            continue  # Zaten puanlanmis
                        try:
                            _result = YdAutoGrader.grade(ex, _ans)
                            store.save_result(_result)
                            # Telafi
                            _rem = YdAutoGrader.generate_remediation(ex, _result, _CURRICULUM)
                            if _rem:
                                store.save_remediation(_rem)
                            _graded_count += 1
                        except Exception:
                            pass
                    # 2) Quiz'i tamamlandi olarak isaretle
                    ex.status = "completed"
                    store.save_exam(ex)
                    if _graded_count > 0:
                        st.success(
                            f"Quiz tamamlandi: **{ex.name}**\n\n"
                            f"{_graded_count} yeni cevap otomatik puanlandi. "
                            f"Sonuclar 'Quiz Sonuclari & Karne' sekmesinde gorulebilir."
                        )
                    else:
                        st.success(f"Quiz tamamlandi: **{ex.name}**")
                    st.rerun()
            with bc2:
                if not time_up:
                    extra = st.number_input("Ek sure (dk):", 1, 30, 5, key=f"qy_ext_{ex.id}")
                    if st.button("\u23F0 Sure Uzat", key=f"qy_extend_{ex.id}"):
                        new_deadline = deadline_dt + timedelta(minutes=extra)
                        ex.deadline = new_deadline.isoformat()
                        ex.duration_minutes += extra
                        store.save_exam(ex)
                        st.success(f"Sure {extra} dk uzatildi. Yeni bitis: {new_deadline.strftime('%H:%M')}")
                        st.rerun()

    # ── TAMAMLANAN quizler ──
    if completed:
        st.markdown(
            '<div style="background:linear-gradient(135deg,#374151,#6b7280);'
            'color:#fff;padding:10px 16px;border-radius:10px;margin:14px 0 6px;">'
            '<div style="font-size:1rem;font-weight:800;color:#fff;">'
            '\U0001F3C1 Tamamlanan Quizler</div>'
            f'<div style="font-size:.78rem;color:#e5e7eb;margin-top:2px;">'
            f'{len(completed)} quiz sonuclandi</div></div>',
            unsafe_allow_html=True,
        )
        for ex in completed:
            results = store.get_results(exam_id=ex.id)
            avg_score = sum(r.score for r in results) / len(results) if results else 0
            color = "#059669" if avg_score >= 70 else "#f59e0b" if avg_score >= 50 else "#dc2626"
            bg_color = "#ecfdf5" if avg_score >= 70 else "#fffbeb" if avg_score >= 50 else "#fef2f2"
            st.markdown(
                f'<div style="background:{bg_color};border:1px solid {color}44;'
                f'border-left:4px solid {color};padding:10px 14px;border-radius:8px;'
                f'margin:4px 0;box-shadow:0 1px 4px rgba(0,0,0,0.05);">'
                f'<div style="font-size:.95rem;font-weight:800;color:#0f172a;">{ex.name}</div>'
                f'<div style="font-size:.82rem;color:#334155;margin-top:4px;">'
                f'<b style="color:{color};">{len(results)} ogrenci</b> · '
                f'<span style="background:{color};color:#fff;padding:2px 10px;'
                f'border-radius:10px;font-size:.72rem;font-weight:700;">Ort: {avg_score:.1f}</span>'
                f'</div></div>',
                unsafe_allow_html=True,
            )


# ── TAB 3: Ogrenci Quiz Ekrani ────────────────────────────────────────────────

def _render_quiz_ogrenci_ekrani(store: YdAssessmentStore, level: str, sinif: int, sube: str,
                                forced_student=None):
    """Ogrenci quiz cozer — timer ile.

    forced_student: Eger verilirse (ogrenci kendi panelinden geldiyse),
    ogrenci secim dropdown'u atlanir ve direkt o ogrenci icin bekleyen quizler
    listelenir. Ogretmen modu icin None birakin.
    """
    st.markdown(
        '<div style="background:linear-gradient(135deg,#1e3a5f,#2563eb);color:#fff;'
        'padding:14px 18px;border-radius:12px;margin-bottom:14px;">'
        '<h4 style="margin:0;font-size:17px;">\U0001F393 Ogrenci Quiz Ekrani</h4>'
        '<p style="margin:3px 0 0;font-size:12px;opacity:.85;">'
        'Aktif quizleri cozun ve gonderin</p></div>',
        unsafe_allow_html=True,
    )

    # Ogrenci modu: forced_student varsa direkt onu kullan
    if forced_student is not None:
        student_id = getattr(forced_student, "id", "") or f"{forced_student.numara}_{forced_student.sube}"
        student_name = f"{forced_student.ad} {forced_student.soyad}"
    else:
        # Ogretmen modu: ogrenci secim dropdown'u
        try:
            from utils.shared_data import get_student_display_options
            students = get_student_display_options(sinif_filter=sinif, sube_filter=sube, include_empty=False)
        except Exception:
            students = {}

        if not students:
            st.info("Kayitli ogrenci bulunamadi.")
            return

        student_name = st.selectbox("Ogrenci Secin:", list(students.keys()), key="yd_quiz_student_sel")
        if not student_name:
            return
        student_data = students[student_name]
        student_id = student_data.get("id", student_name)

    # Aktif (started) quizler
    started_quizzes = store.get_exams(level=level, sinif=sinif, sube=sube, category="quiz", status="started")
    # Gonderilmis (sent) quizler de goster
    sent_quizzes = store.get_exams(level=level, sinif=sinif, sube=sube, category="quiz", status="sent")
    active_quizzes = started_quizzes + sent_quizzes

    if not active_quizzes:
        st.info("Su anda aktif quiz bulunmamaktadir. Ogretmenin quiz baslatmasini bekleyin.")
        return

    # Ogrencinin cevapladigi quizleri filtrele
    student_answers = store.get_student_answers(student_id=student_id)
    submitted_ids = {a.exam_id for a in student_answers if a.status == "submitted"}

    pending_quizzes = [e for e in active_quizzes if e.id not in submitted_ids]
    done_quizzes = [e for e in active_quizzes if e.id in submitted_ids]

    if not pending_quizzes and not done_quizzes:
        st.info("Cozulecek quiz yok.")
        return

    # ── Bekleyen Quizler ──
    if pending_quizzes:
        for exam in pending_quizzes:
            # Sure kontrolu (sadece started olanlar icin)
            if exam.status == "started" and exam.deadline:
                deadline_dt = datetime.fromisoformat(exam.deadline)
                remaining = (deadline_dt - datetime.now()).total_seconds()
                if remaining <= 0:
                    st.warning(f"**{exam.name}** — Sure doldu! Bu quiz artik cevaplanamaz.")
                    continue
                remaining_min = int(remaining // 60)
                remaining_sec = int(remaining % 60)
                time_badge = (
                    f'<span style="background:#059669;color:#fff;padding:3px 10px;'
                    f'border-radius:20px;font-size:13px;font-weight:700;">'
                    f'\u23F1 {remaining_min}:{remaining_sec:02d}</span>'
                )
            else:
                time_badge = ""

            with st.expander(f"\U0001F4DD {exam.name} ({len(exam.questions)} soru)", expanded=True):
                st.markdown(
                    f'<div style="background:linear-gradient(135deg,#1e40af,#3b82f6);color:#fff;'
                    f'padding:12px 16px;border-radius:10px;margin-bottom:10px;">'
                    f'<div style="font-size:1.05rem;font-weight:700;">{exam.name}</div>'
                    f'<div style="font-size:.85rem;opacity:.85;">'
                    f'{len(exam.questions)} soru | Sure: {exam.duration_minutes} dk | '
                    f'Toplam: {exam.total_points:.0f} puan {time_badge}</div></div>',
                    unsafe_allow_html=True,
                )

                # Sorulari render et
                _render_quiz_questions(store, exam, student_id, student_name, sinif, sube)

    # ── Tamamlanan Quizler — Ozet ──
    if done_quizzes:
        st.markdown("---")
        st.markdown("**Tamamlanan Quizler:**")
        for exam in done_quizzes:
            exam_results = store.get_results(exam_id=exam.id, student_id=student_id)
            if exam_results:
                r = exam_results[0]
                color = "#059669" if r.score >= 70 else "#f59e0b" if r.score >= 50 else "#dc2626"
                st.markdown(
                    f'<div style="background:{color}10;border-left:3px solid {color};'
                    f'padding:8px 12px;border-radius:6px;margin:4px 0;">'
                    f'<b>{exam.name}</b> — '
                    f'<span style="color:{color};font-weight:700;">{r.score:.1f} puan</span> | '
                    f'{r.correct_count}/{r.total_questions} dogru</div>',
                    unsafe_allow_html=True,
                )


def _render_quiz_questions(store: YdAssessmentStore, exam: YdExam,
                           student_id: str, student_name: str, sinif: int, sube: str):
    """Render quiz questions for student to answer — timer-aware."""
    questions = [YdQuestion.from_dict(q) for q in exam.questions]
    ss_key = f"ydquiz_ans_{exam.id}_{student_id}"

    answers = {}
    for i, q in enumerate(questions):
        st.markdown(f"---\n**Soru {i + 1}** {'(' + q.skill + ')' if q.skill else ''}")
        st.markdown(q.stem)
        if q.stem_tr:
            st.caption(q.stem_tr)

        if q.choices:
            choice_labels = [f"{k}) {v}" for k, v in sorted(q.choices.items())]
            selected = st.radio(
                f"Cevabin:", choice_labels,
                key=f"{ss_key}_q{i}",
                index=None,
                label_visibility="collapsed",
            )
            if selected:
                answers[q.id] = selected.split(")")[0].strip()

    st.markdown("---")
    answered_count = len(answers)
    total_count = len(questions)

    # Progress bar
    progress = answered_count / total_count if total_count > 0 else 0
    st.progress(progress, text=f"Cevaplanan: {answered_count}/{total_count}")

    if st.button("\U0001F4E8 Quiz'i Gonder", key=f"ydquiz_submit_{exam.id}_{student_id}",
                 type="primary", use_container_width=True):
        if answered_count == 0:
            st.error("Lutfen en az bir soruyu cevaplayin.")
            return

        # Sure dolmus mu kontrol
        if exam.status == "started" and exam.deadline:
            deadline_dt = datetime.fromisoformat(exam.deadline)
            if datetime.now() > deadline_dt:
                st.error("Sure doldu! Quiz gonderilemez.")
                return

        # Kaydet
        student_ans = YdStudentAnswer(
            exam_id=exam.id,
            student_id=student_id,
            student_name=student_name,
            sinif=sinif,
            sube=sube,
            answers=answers,
            status="submitted",
            submitted_at=datetime.now().isoformat(),
        )
        student_ans = store.save_answer(student_ans)

        # Otomatik puanlama
        result = YdAutoGrader.grade(exam, student_ans)
        result = store.save_result(result)

        # Telafi odevi
        remediation = YdAutoGrader.generate_remediation(exam, result, _CURRICULUM)
        if remediation:
            store.save_remediation(remediation)

        # Tum ogrenciler cevapladiysa quiz tamamlandi
        try:
            from utils.shared_data import get_student_display_options
            all_students = get_student_display_options(sinif_filter=sinif, sube_filter=sube, include_empty=False)
            all_answers = store.get_student_answers(exam_id=exam.id)
            submitted_ids = {a.student_id for a in all_answers if a.status == "submitted"}
            if len(submitted_ids) >= len(all_students):
                exam.status = "completed"
                store.save_exam(exam)
        except Exception:
            pass

        st.success(
            f"Quiz tamamlandi!\n\n"
            f"**Sonuc:** {result.correct_count}/{result.total_questions} dogru | "
            f"**Puan:** {result.score:.1f}/100"
        )
        if remediation:
            st.info(f"Yanlis sorulara ait **{remediation.total_questions} soruluk telafi odevi** olusturuldu.")
        st.balloons()
        st.rerun()


# ── TAB 4: Quiz Sonuclari & Karne ─────────────────────────────────────────────

def _render_quiz_sonuclari(store: YdAssessmentStore, level: str, sinif: int, sube: str):
    """Quiz sonuclari — sinif ozeti, ogrenci karnesi, unite bazli analiz."""
    import pandas as pd

    st.markdown(
        '<div style="background:linear-gradient(135deg,#581c87,#7c3aed);color:#fff;'
        'padding:16px 20px;border-radius:12px;margin-bottom:14px;text-align:center;">'
        '<h3 style="margin:0;font-size:19px;">Quiz Sonuclari & Karne</h3>'
        '<p style="margin:4px 0 0;font-size:12px;opacity:.85;">'
        'Sinif Ozeti | Ogrenci Karnesi | Unite Bazli Analiz | Beceri Analizi</p></div>',
        unsafe_allow_html=True,
    )

    results = store.get_results(sinif=sinif, sube=sube, category="quiz")
    if not results:
        st.info("Henuz quiz sonucu bulunmamaktadir.")
        return

    view_mode = st.radio("Gorunum:", ["Sinif Ozeti", "Ogrenci Karnesi", "Unite Analizi"],
                         horizontal=True, key="yd_quiz_view_mode")

    if view_mode == "Sinif Ozeti":
        _render_quiz_sinif_ozeti(results, store, level, sinif, sube)
    elif view_mode == "Ogrenci Karnesi":
        _render_quiz_ogrenci_karnesi(results, store, level, sinif, sube)
    else:
        _render_quiz_unite_analizi(results, store, level, sinif, sube)


def _render_quiz_sinif_ozeti(results: list, store, level, sinif, sube):
    """Sinif geneli quiz ozeti."""
    import pandas as pd

    all_scores = [r.score for r in results]
    avg_all = sum(all_scores) / len(all_scores) if all_scores else 0
    max_score = max(all_scores) if all_scores else 0
    min_score = min(all_scores) if all_scores else 0

    # Istatistik kartlari
    c1, c2, c3, c4 = st.columns(4)
    with c1:
        st.metric("Sinif Ortalamasi", f"{avg_all:.1f}")
    with c2:
        st.metric("En Yuksek", f"{max_score:.1f}")
    with c3:
        st.metric("En Dusuk", f"{min_score:.1f}")
    with c4:
        above_70 = sum(1 for s in all_scores if s >= 70)
        st.metric("Basarili (%70+)", f"{above_70}/{len(all_scores)}")

    # Puan dagilimi
    st.markdown("---")
    st.markdown("**Puan Dagilimi**")
    bins = {"0-29": 0, "30-49": 0, "50-69": 0, "70-84": 0, "85-100": 0}
    for s in all_scores:
        if s < 30: bins["0-29"] += 1
        elif s < 50: bins["30-49"] += 1
        elif s < 70: bins["50-69"] += 1
        elif s < 85: bins["70-84"] += 1
        else: bins["85-100"] += 1
    df_dist = pd.DataFrame({"Puan Araligi": list(bins.keys()), "Ogrenci Sayisi": list(bins.values())})
    st.bar_chart(df_dist.set_index("Puan Araligi"), use_container_width=True)

    # Ogrenci siralama tablosu
    st.markdown("---")
    st.markdown("**Ogrenci Siralama**")
    student_scores: dict[str, list] = {}
    for r in results:
        student_scores.setdefault(r.student_name, []).append(r.score)

    rows = []
    for name, scores in sorted(student_scores.items(), key=lambda x: sum(x[1]) / len(x[1]), reverse=True):
        avg = sum(scores) / len(scores)
        rows.append({
            "Ogrenci": name,
            "Quiz Sayisi": len(scores),
            "Ortalama": round(avg, 1),
            "En Yuksek": round(max(scores), 1),
            "En Dusuk": round(min(scores), 1),
        })
    if rows:
        df = pd.DataFrame(rows)
        st.dataframe(df, use_container_width=True, hide_index=True)

    # Beceri bazli analiz
    st.markdown("---")
    st.markdown("**Beceri (Skill) Bazli Basari**")
    agg_skills: dict[str, dict] = {}
    for r in results:
        for sk, data in r.skill_breakdown.items():
            if sk not in agg_skills:
                agg_skills[sk] = {"correct": 0, "total": 0}
            agg_skills[sk]["correct"] += data.get("correct", 0)
            agg_skills[sk]["total"] += data.get("total", 0)
    if agg_skills:
        skill_labels = {"vocabulary": "Kelime", "grammar": "Dilbilgisi", "other": "Diger"}
        sk_rows = []
        for sk, data in agg_skills.items():
            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
            sk_rows.append({"Beceri": skill_labels.get(sk, sk.title()), "Basari %": round(pct, 1)})
        df_sk = pd.DataFrame(sk_rows)
        st.bar_chart(df_sk.set_index("Beceri"), use_container_width=True)


def _render_quiz_ogrenci_karnesi(results: list, store, level, sinif, sube):
    """Ogrenci bazli quiz karnesi."""
    import pandas as pd

    # Ogrenci secimi
    student_names = sorted(set(r.student_name for r in results))
    if not student_names:
        st.info("Sonuc bulunamadi.")
        return

    sel_student = st.selectbox("Ogrenci:", student_names, key="yd_quiz_karne_student")
    student_results = [r for r in results if r.student_name == sel_student]

    if not student_results:
        st.info("Bu ogrenci icin sonuc yok.")
        return

    # Karne basligi
    avg_score = sum(r.score for r in student_results) / len(student_results)
    total_quizzes = len(student_results)
    karne_color = "#059669" if avg_score >= 70 else "#f59e0b" if avg_score >= 50 else "#dc2626"

    st.markdown(
        f'<div style="background:linear-gradient(135deg,#0f172a,#1e293b);color:#fff;'
        f'padding:20px 24px;border-radius:14px;margin:10px 0;'
        f'border:2px solid {karne_color}40;">'
        f'<div style="font-size:1.2rem;font-weight:700;">\U0001F4CB Quiz Karnesi: {sel_student}</div>'
        f'<div style="display:flex;gap:30px;margin-top:10px;">'
        f'<div><span style="font-size:2rem;font-weight:800;color:{karne_color};">{avg_score:.1f}</span>'
        f'<br><span style="font-size:12px;color:#94a3b8;">Genel Ortalama</span></div>'
        f'<div><span style="font-size:2rem;font-weight:800;color:#818cf8;">{total_quizzes}</span>'
        f'<br><span style="font-size:12px;color:#94a3b8;">Quiz Sayisi</span></div>'
        f'<div><span style="font-size:2rem;font-weight:800;color:#38bdf8;">'
        f'{sum(r.correct_count for r in student_results)}/{sum(r.total_questions for r in student_results)}</span>'
        f'<br><span style="font-size:12px;color:#94a3b8;">Toplam Dogru</span></div>'
        f'</div></div>',
        unsafe_allow_html=True,
    )

    # Quiz bazli detay tablosu
    st.markdown("---")
    st.markdown("**Quiz Bazli Sonuclar:**")
    rows = []
    for r in sorted(student_results, key=lambda x: x.graded_at, reverse=True):
        unit_label = f"U{r.unit}" if getattr(r, "unit", 0) else "-"
        rows.append({
            "Quiz": r.exam_name,
            "Unite": unit_label,
            "Puan": round(r.score, 1),
            "Dogru": r.correct_count,
            "Yanlis": r.wrong_count,
            "Bos": r.empty_count,
            "Tarih": r.graded_at[:10] if r.graded_at else "-",
        })
    if rows:
        df = pd.DataFrame(rows)
        st.dataframe(df, use_container_width=True, hide_index=True)

    # Beceri kirilim
    st.markdown("---")
    st.markdown("**Beceri Analizi:**")
    agg_skills: dict[str, dict] = {}
    for r in student_results:
        for sk, data in r.skill_breakdown.items():
            if sk not in agg_skills:
                agg_skills[sk] = {"correct": 0, "total": 0}
            agg_skills[sk]["correct"] += data.get("correct", 0)
            agg_skills[sk]["total"] += data.get("total", 0)

    if agg_skills:
        skill_labels = {"vocabulary": "Kelime", "grammar": "Dilbilgisi", "other": "Diger"}
        for sk, data in agg_skills.items():
            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
            color = "#059669" if pct >= 70 else "#f59e0b" if pct >= 50 else "#dc2626"
            st.markdown(
                f'<div style="background:{color}10;border-left:3px solid {color};'
                f'padding:6px 12px;border-radius:4px;margin:3px 0;">'
                f'{skill_labels.get(sk, sk.title())}: '
                f'<b style="color:{color};">{pct:.0f}%</b> ({data["correct"]}/{data["total"]})</div>',
                unsafe_allow_html=True,
            )

    # Zayif temalar
    weak_themes = []
    for r in student_results:
        for th, data in r.theme_breakdown.items():
            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
            if pct < 60:
                weak_themes.append(th)
    if weak_themes:
        st.markdown("---")
        st.markdown(
            '<div style="background:#fef3c7;border-left:3px solid #f59e0b;'
            'padding:10px 14px;border-radius:6px;">'
            '<b>\u26A0 Gelisim Gerektiren Temalar:</b><br>'
            + ", ".join(set(weak_themes))
            + '</div>',
            unsafe_allow_html=True,
        )


def _render_quiz_unite_analizi(results: list, store, level, sinif, sube):
    """Unite bazli quiz analizi."""
    import pandas as pd

    # Unite bazli gruplama
    unit_data: dict[int, list] = {}
    for r in results:
        u = getattr(r, "unit", 0) or 0
        if u > 0:
            unit_data.setdefault(u, []).append(r)

    if not unit_data:
        # Eski sonuclarda unit alani yok — haftalardan hesapla
        for r in results:
            if r.weeks:
                u = _week_to_unit(r.weeks[0])
                unit_data.setdefault(u, []).append(r)

    if not unit_data:
        st.info("Unite bazli veri bulunamadi.")
        return

    st.markdown("**Unite Bazli Basari Haritasi:**")
    rows = []
    for u in sorted(unit_data.keys()):
        u_results = unit_data[u]
        avg = sum(r.score for r in u_results) / len(u_results)
        theme = _get_unit_theme(level, u)
        rows.append({
            "Unite": f"U{u}: {theme}",
            "Ortalama": round(avg, 1),
            "Quiz Sayisi": len(set(r.exam_id for r in u_results)),
            "Ogrenci Sonucu": len(u_results),
        })

    if rows:
        df = pd.DataFrame(rows)
        st.bar_chart(df.set_index("Unite")["Ortalama"], use_container_width=True)
        st.dataframe(df, use_container_width=True, hide_index=True)

    # En zayif ve en guclu uniteler
    if len(rows) >= 2:
        sorted_rows = sorted(rows, key=lambda x: x["Ortalama"])
        weakest = sorted_rows[0]
        strongest = sorted_rows[-1]
        st.markdown(
            f'<div style="display:flex;gap:12px;margin-top:12px;">'
            f'<div style="flex:1;background:#fef2f2;border:1px solid #fca5a5;border-radius:8px;'
            f'padding:10px 14px;text-align:center;">'
            f'<div style="font-size:12px;color:#dc2626;">En Zayif Unite</div>'
            f'<div style="font-weight:700;color:#991b1b;">{weakest["Unite"]}</div>'
            f'<div style="font-size:1.3rem;font-weight:800;color:#dc2626;">{weakest["Ortalama"]}</div></div>'
            f'<div style="flex:1;background:#f0fdf4;border:1px solid #86efac;border-radius:8px;'
            f'padding:10px 14px;text-align:center;">'
            f'<div style="font-size:12px;color:#059669;">En Guclu Unite</div>'
            f'<div style="font-weight:700;color:#065f46;">{strongest["Unite"]}</div>'
            f'<div style="font-size:1.3rem;font-weight:800;color:#059669;">{strongest["Ortalama"]}</div></div>'
            f'</div>',
            unsafe_allow_html=True,
        )


# ── Veli Paneli — Quiz Entegrasyonu ────────────────────────────────────────────

def _render_veli_yd_quizler(sinif, sube=None):
    """Veli panelinde ogrencinin quiz sonuclarini goster.
    Called from render_veli_english_tab()."""
    if not sinif or not sube:
        return

    level = _yd_sinif_to_level(sinif)
    if not level:
        return

    store = _get_yd_assessment_store()

    # Aktif quizler (ogrenci cozmesi gerekenler)
    active_quizzes = store.get_exams(level=level, sinif=int(sinif), sube=sube, category="quiz", status="started")
    sent_quizzes = store.get_exams(level=level, sinif=int(sinif), sube=sube, category="quiz", status="sent")
    completed_quizzes = store.get_exams(level=level, sinif=int(sinif), sube=sube, category="quiz", status="completed")
    all_quizzes = active_quizzes + sent_quizzes + completed_quizzes

    if not all_quizzes:
        return

    st.markdown(
        '<div style="background:linear-gradient(135deg,#4338ca,#7c3aed);color:#fff;'
        'padding:14px 18px;border-radius:12px;margin:12px 0;text-align:center;">'
        '<h4 style="margin:0;font-size:16px;">\U0001F3AF Unite Quizleri</h4>'
        '<p style="margin:3px 0 0;font-size:12px;opacity:0.85;">'
        'Unite bazli quiz sonuclari ve aktif quizler</p></div>',
        unsafe_allow_html=True,
    )

    # Ogrenci secimi
    try:
        from utils.shared_data import get_student_display_options
        students = get_student_display_options(sinif_filter=int(sinif), sube_filter=sube, include_empty=False)
    except Exception:
        students = {}

    if not students:
        st.info("Kayitli ogrenci bulunamadi.")
        return

    student_name = st.selectbox("Ogrenci:", list(students.keys()), key="veli_yd_quiz_student")
    if not student_name:
        return
    student_data = students[student_name]
    student_id = student_data.get("id", student_name)

    # Cevaplanan quizler
    student_answers = store.get_student_answers(student_id=student_id)
    submitted_ids = {a.exam_id for a in student_answers if a.status == "submitted"}

    # Aktif — cevaplanmamis quizler
    pending = [e for e in (active_quizzes + sent_quizzes) if e.id not in submitted_ids]
    if pending:
        for exam in pending:
            # Sure kontrolu
            if exam.status == "started" and exam.deadline:
                deadline_dt = datetime.fromisoformat(exam.deadline)
                if datetime.now() > deadline_dt:
                    st.warning(f"**{exam.name}** — Sure doldu!")
                    continue

            with st.expander(f"\U0001F4DD Bekleyen Quiz: {exam.name} ({len(exam.questions)} soru)", expanded=True):
                _render_quiz_questions(store, exam, student_id, student_name, int(sinif), sube)

    # Tamamlanan quizler — sonuc karnesi
    done_ids = submitted_ids.intersection({e.id for e in all_quizzes})
    if done_ids:
        st.markdown("**Tamamlanan Quizler:**")
        for exam in all_quizzes:
            if exam.id not in done_ids:
                continue
            exam_results = store.get_results(exam_id=exam.id, student_id=student_id)
            if exam_results:
                r = exam_results[0]
                color = "#059669" if r.score >= 70 else "#f59e0b" if r.score >= 50 else "#dc2626"
                unit_label = f"Unite {r.unit}: " if getattr(r, "unit", 0) else ""
                st.markdown(
                    f'<div style="background:{color}10;border-left:3px solid {color};'
                    f'padding:8px 12px;border-radius:6px;margin:4px 0;">'
                    f'<b>{unit_label}{exam.name}</b> — '
                    f'<span style="color:{color};font-weight:700;">{r.score:.1f} puan</span> | '
                    f'{r.correct_count}/{r.total_questions} dogru</div>',
                    unsafe_allow_html=True,
                )

                with st.expander(f"Detay: {exam.name}", expanded=False):
                    if r.skill_breakdown:
                        skill_labels = {"vocabulary": "Kelime", "grammar": "Dilbilgisi", "other": "Diger"}
                        for sk, data in r.skill_breakdown.items():
                            pct = (data["correct"] / data["total"] * 100) if data["total"] else 0
                            sk_color = "#059669" if pct >= 70 else "#f59e0b" if pct >= 50 else "#dc2626"
                            st.markdown(
                                f'{skill_labels.get(sk, sk.title())}: '
                                f'<b style="color:{sk_color};">{pct:.0f}%</b> ({data["correct"]}/{data["total"]})',
                                unsafe_allow_html=True,
                            )
                    wrong_items = [d for d in r.details if not d.get("is_correct")]
                    if wrong_items:
                        st.markdown("**Yanlis/Bos Sorular:**")
                        for d in wrong_items[:10]:
                            st.markdown(
                                f'<div style="background:#fef2f210;border-left:2px solid #dc2626;'
                                f'padding:6px 10px;border-radius:4px;margin:3px 0;font-size:13px;">'
                                f'{d.get("stem","")[:80]}<br>'
                                f'Dogru: <b>{d.get("correct_text", d.get("correct",""))}</b></div>',
                                unsafe_allow_html=True,
                            )


